: 3, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "location": "Cheonjeyeon Waterfall", "alt": "Cheonjeyeon Waterfall — gallery image 1", "caption": "Cheonjeyeon Waterfall — photo 1"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "O''sulloc Tea Museum", "alt": "O''sulloc Tea Museum — gallery image 1", "caption": "O''sulloc Tea Museum — photo 1"}, {"id": 5, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "location": "Aewol Cafe Street (Handam Coastal Trail)", "alt": "Aewol Cafe Street (Handam Coastal Trail) — gallery image 1", "caption": "Aewol Cafe Street (Handam Coastal Trail) — photo 1"}, {"id": 6, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "Hallasan 1100 Highland", "alt": "Hallasan 1100 Highland — gallery image 2", "caption": "Hallasan 1100 Highland — photo 2"}, {"id": 7, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "Hallasan 1100 Highland", "alt": "Hallasan 1100 Highland — gallery image 3", "caption": "Hallasan 1100 Highland — photo 3"}, {"id": 8, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "location": "Daepo Jusangjeolli Cliff", "alt": "Daepo Jusangjeolli Cliff — gallery image 2", "caption": "Daepo Jusangjeolli Cliff — photo 2"}, {"id": 9, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "location": "Daepo Jusangjeolli Cliff", "alt": "Daepo Jusangjeolli Cliff — gallery image 3", "caption": "Daepo Jusangjeolli Cliff — photo 3"}, {"id": 10, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "location": "Daepo Jusangjeolli Cliff", "alt": "Daepo Jusangjeolli Cliff — gallery image 4", "caption": "Daepo Jusangjeolli Cliff — photo 4"}, {"id": 11, "type": "photo", "src": "/images/tours/jusangjeolli/photo-005.webp", "location": "Daepo Jusangjeolli Cliff", "alt": "Daepo Jusangjeolli Cliff — gallery image 5", "caption": "Daepo Jusangjeolli Cliff — photo 5"}, {"id": 12, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "location": "Cheonjeyeon Waterfall", "alt": "Cheonjeyeon Waterfall — gallery image 2", "caption": "Cheonjeyeon Waterfall — photo 2"}, {"id": 13, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "location": "Cheonjeyeon Waterfall", "alt": "Cheonjeyeon Waterfall — gallery image 3", "caption": "Cheonjeyeon Waterfall — photo 3"}, {"id": 14, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/photo-004.webp", "location": "Cheonjeyeon Waterfall", "alt": "Cheonjeyeon Waterfall — gallery image 4", "caption": "Cheonjeyeon Waterfall — photo 4"}, {"id": 15, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "O''sulloc Tea Museum", "alt": "O''sulloc Tea Museum — gallery image 2", "caption": "O''sulloc Tea Museum — photo 2"}, {"id": 16, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "O''sulloc Tea Museum", "alt": "O''sulloc Tea Museum — gallery image 3", "caption": "O''sulloc Tea Museum — photo 3"}, {"id": 17, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "O''sulloc Tea Museum", "alt": "O''sulloc Tea Museum — gallery image 4", "caption": "O''sulloc Tea Museum — photo 4"}, {"id": 18, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "location": "Aewol Cafe Street (Handam Coastal Trail)", "alt": "Aewol Cafe Street (Handam Coastal Trail) — gallery image 2", "caption": "Aewol Cafe Street (Handam Coastal Trail) — photo 2"}, {"id": 19, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "location": "Aewol Cafe Street (Handam Coastal Trail)", "alt": "Aewol Cafe Street (Handam Coastal Trail) — gallery image 3", "caption": "Aewol Cafe Street (Handam Coastal Trail) — photo 3"}, {"id": 20, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "location": "Aewol Cafe Street (Handam Coastal Trail)", "alt": "Aewol Cafe Street (Handam Coastal Trail) — gallery image 4", "caption": "Aewol Cafe Street (Handam Coastal Trail) — photo 4"}, {"id": 21, "type": "photo", "src": "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp", "location": "Aewol Cafe Street (Handam Coastal Trail)", "alt": "Aewol Cafe Street (Handam Coastal Trail) — gallery image 5", "caption": "Aewol Cafe Street (Handam Coastal Trail) — photo 5"}, {"id": 22, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "location": "Iho Tewoo Beach", "caption": "Iho Tewoo Beach — photo 1", "alt": "Iho Tewoo Beach — gallery image 1"}, {"id": 23, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp", "location": "Iho Tewoo Beach", "caption": "Iho Tewoo Beach — photo 2", "alt": "Iho Tewoo Beach — gallery image 2"}], "itineraryStops": [{"number": 1, "time": "09:30", "duration": "45 min", "name": "Hallasan 1100 Highland", "category": "Alpine Ramsar Wetland Boardwalk — A Taste of UNESCO Hallasan", "description": "**The Hallasan 1100 Highland Wetland (한라산 1100고지 습지)** is an alpine wetland on the western flank of Hallasan at **1,100 m above sea level**, registered on **12 October 2009 as a Ramsar Convention Wetland of International Importance (Site No. 1893)**. Covering about **13 ha**, it sits within the boundary of Hallasan''s **UNESCO World Natural Heritage and Biosphere Reserve** — meaning you can lightly experience Hallasan''s UNESCO value without climbing all the way to the Baengnokdam summit. \n\nThe wetland is made up of **more than 16 freshwater marshes and ponds** scattered across the plateau, and you can loop around it on a **flat wooden boardwalk of about 1 km (around 20 minutes)**. The boardwalk is almost level, so it is relatively easy even for strollers or those with limited mobility. It is home to three endangered bird species and one nationally designated threatened plant species, along with Jeju''s native mammals, reptiles, and insects, and interpretive panels along the boardwalk explain the wetland ecology. \n\n**Road 1100 (opened 1973, 36.6 km long)**, which leads to the wetland, is **the highest national road in Korea**, linking Jeju City and Seogwipo''s Jungmun district from north to south. Across the road, the **1100 Highland Rest Area** has a convenience store (GS25), a café serving warm drinks and ramen, an observation deck, and a park honoring the **White Deer (Baekrok, 白鹿) statue** (a Jeju legend in which an immortal rode a white deer up Hallasan) and **Go Sang-don, the first Korean to summit Everest** — a good spot for a 10–15 minute break. \n\nAt 1,100 m, the temperature is **7–10°C lower** than at the coast, so even in midsummer a light layer is needed. In winter, the snow-covered boardwalk and frozen wetland become one of Jeju''s most prized snowscape photo spots, but **Road 1100 is also the first road to be closed during heavy snow, heavy rain, or icing** — in which case the itinerary is replaced with an indoor Jeju City attraction (e.g., the Jeju National Museum). \n\nBoth admission and parking are **free**, and no reservation is required.", "image": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "highlights": ["**Ramsar Wetland of International Importance No. 1893** (registered 2009) — within the boundary of Hallasan''s UNESCO World Heritage + Biosphere Reserve", "**Alpine wetland at 1,100 m** — more than 16 freshwater marshes and ponds across the plateau", "**About 1 km of flat wooden boardwalk** (around 20 min) — relatively easy even for strollers and those with limited mobility", "**Road 1100** — opened 1973, 36.6 km, the highest national road in Korea", "Home to **Jeju''s native ecology**, including three endangered bird species + one threatened plant species", "**1100 Highland Rest Area** across the road — White Deer statue, Go Sang-don park, convenience store, café, observation deck", "**7–10°C cooler than the coast** — a layer recommended even in midsummer", "Winter **snowscape spot** (but during heavy snow Road 1100 is closed → indoor alternative)", "**Free admission + free parking**, no reservation needed"], "timeUsed": ["Parking + restroom at the 1100 Highland Rest Area — ~5 min", "One loop of the boardwalk wetland trail — ~20 min", "Observation deck + White Deer statue photos — ~10 min", "Rest / drinks at the rest area — ~10 min"], "whyOnRoute": "**The starting point of the southwest loop.** From Jeju City you climb Road 1100 up to the highlands, lightly experiencing Hallasan''s scale and alpine ecology, before descending to the southern Jungmun coast that leads on to Jusangjeolli and Cheonjeyeon. Unlike a summit climb or steep uphill trails, this is a **flat boardwalk stroll** with almost no physical demand, and it lets you sample a **Ramsar wetland + UNESCO Hallasan** at once, for free and without reservation. The flow from mountain down to coast keeps the route natural, and the early hour means Road 1100 is relatively quiet — in winter, when the road is closed, an indoor attraction is used instead.", "_poi_meta": {"poi_key": "hallasan_1100_wetland", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Ramsar Sites Information Service — Site #1893 (Hallasan 1100 Altitude Wetland)", "Hallasan National Park official site (hallasan.go.kr)", "UNESCO WHC inscription 1264 (Jeju Volcanic Island and Lava Tubes, 2007)", "VisitKorea — 1100 Altitude Wetland (1100-goji)", "Jeju Special Self-Governing Province — Wetland Protected Area records"]}, "smartNotes": {"photo": "The signature composition is the wooden boardwalk crossing the freshwater ponds with Hallasan in the distance, and the winter snowscape is one of the most photographed scenes on Jeju. The White Deer statue at the rest area is also a popular photo spot.", "facilities": "The 1100 Highland Rest Area across the road brings together a convenience store, café, observation deck, and restrooms.", "tip": "Even in midsummer the 1,100 m highland is 7–10°C cooler than the coast, so pack a light layer. In winter Road 1100 is the first to be closed, so check road conditions; if closed, an indoor attraction is used instead."}, "convenience": {"restroom": "Restrooms at the 1100 Highland Rest Area across the road", "parking": "Free parking at the rest area (can be busy on snowy weekends)"}, "visitBasics": {"hours": "Wetland boardwalk open 24 hours (free); 1100 Highland Rest Area café and store about 09:00–17:00", "closed": "Open year-round, but Road 1100 may be closed during heavy snow or rain — check road conditions before a winter visit", "admission": "Free (Ramsar wetland, no admission or parking fee)", "walking": "Very easy — one loop of about 1 km on flat wooden boardwalk, 15–20 min; manageable for most mobility levels, including strollers"}, "images": ["/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp"], "imageCredits": [{"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "Hallasan 1100 Highland", "caption": "Hallasan 1100 Highland — photo 1", "alt": "Hallasan 1100 Highland — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "Hallasan 1100 Highland", "caption": "Hallasan 1100 Highland — photo 2", "alt": "Hallasan 1100 Highland — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "Hallasan 1100 Highland", "caption": "Hallasan 1100 Highland — photo 3", "alt": "Hallasan 1100 Highland — gallery image 3"}]}, {"number": 2, "time": "11:00", "duration": "45 min", "name": "Daepo Jusangjeolli Cliff", "category": "Volcanic Coastline — Hexagonal Columnar-Jointed Lava", "description": "**Daepo Jusangjeolli Cliff** is a dramatic stretch of columnar basalt on the Jungmun coast. The stone pillars were formed as lava cooled and contracted, creating the polygonal columns seen along the sea. \n\nThe columns are commonly described as 30-40 m high and continue for about 1 km along the coast. Visitors use a clifftop boardwalk and viewing decks to see the columns, ocean, and wave action. \n\nOn windy or high-tide days, waves may create strong spray, so the guide may adjust photo time for safety and comfort.", "image": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "highlights": ["**Natural Monument No. 443** — designated **2005-01-06**, the most recent Jeju coastal NM", "Columns rise **30–40 m**, packed in **5- to 7-sided polygons** (mostly hexagons) along **1 km** of coastline", "Formation: **Hallasan flank lava cooled in the sea ~250,000–140,000 years ago**, contracting perpendicular to cooling face", "**East Asia''s premier columnar-jointing site** — peer to Giant''s Causeway, Devils Postpile, Fingal''s Cave", "**Strong wave spray on some high-tide days** — dramatic coastal photos when conditions are safe", "**0.8 km boardwalk loop**, ~15 min walk — barrier-free deck, wheelchair/stroller accessible", "Part of **Jeju Global Geopark (UNESCO 2010-10)** — 13 island-wide geosites", "Admission **₩2,000 adult / ₩1,000 youth / FREE under 7 + over 65**", "Hallasan summit visible to the north on clear days, **directly downstream** geologically"], "timeUsed": ["Parking + ticket purchase + entrance — ~5 min", "Walk to first viewing platform — ~5 min", "Cliff-edge column viewing + photos — ~15 min", "Continue boardwalk loop — ~10 min", "Return to coach — ~10 min"], "whyOnRoute": "Jusangjeolli connects Hallasan''s volcanic origin with the south coast, showing how Jeju''s lava shaped the island from mountain to sea. It is close to Jungmun and pairs efficiently with Cheonjeyeon Falls, keeping the middle of the day smooth without long backtracking.", "_poi_meta": {"poi_key": "daepo_jusangjeolli_cliff", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Cultural Heritage Administration — Natural Monument No. 443 designation (2005-01-06)", "Jeju Global Geopark official site (geopark.jeju.go.kr)", "UNESCO Global Geoparks Network — Jeju (2010 designation)", "VisitJeju — Daepo Jusangjeolli", "Korea Geological Survey — Jeju basalt formation studies"]}, "smartNotes": {"photo": "A slight side angle usually captures the texture of the basalt and wave energy better than a straight-on shot.", "facilities": "Facilities are simple, but the entrance area is practical and sufficient.", "tip": "Because wind and sea mist can change the feel of the stop quickly, it works best with a steady pace."}, "convenience": {"restroom": "Entrance area", "parking": "Paid parking lot"}, "visitBasics": {"hours": "09:00–18:00 (last entry 17:40)", "closed": "Open year-round", "admission": "KRW 2,000 adults / KRW 1,000 children and teens", "walking": "Easy"}, "images": ["/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "/images/tours/jusangjeolli/photo-005.webp"], "imageCredits": [{"url": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/photo-005.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "location": "Daepo Jusangjeolli Cliff", "caption": "Daepo Jusangjeolli Cliff — photo 1", "alt": "Daepo Jusangjeolli Cliff — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "location": "Daepo Jusangjeolli Cliff", "caption": "Daepo Jusangjeolli Cliff — photo 2", "alt": "Daepo Jusangjeolli Cliff — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "location": "Daepo Jusangjeolli Cliff", "caption": "Daepo Jusangjeolli Cliff — photo 3", "alt": "Daepo Jusangjeolli Cliff — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "location": "Daepo Jusangjeolli Cliff", "caption": "Daepo Jusangjeolli Cliff — photo 4", "alt": "Daepo Jusangjeolli Cliff — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/jusangjeolli/photo-005.webp", "location": "Daepo Jusangjeolli Cliff", "caption": "Daepo Jusangjeolli Cliff — photo 5", "alt": "Daepo Jusangjeolli Cliff — gallery image 5"}]}, {"number": 3, "time": "12:00", "duration": "70 min", "name": "Cheonjeyeon Waterfall", "category": "Three-Tier Waterfall + Forest — ''Pond of the Emperor of Heaven''", "description": "**Cheonjeyeon Falls (천제연, ''연 = pond + 천제 = Emperor of Heaven'')** is a **three-tier waterfall** in Jungmun''s volcanic gorge, designated **Natural Monument No. 378 (1993)** for its rare ecological combination. \n\nThe name comes from a **Joseon-era Daoist legend that seven nymphs (선녀, *seonnyeo*) descended from heaven nightly to bathe in the upper pond** — a myth reinforced by the dramatic site''s microclimate of perpetual mist. \n\nThe **1st tier (22 m fall, 21 m deep pond)** drops into a circular basalt cauldron and only flows after heavy rain — most days the upper pond sits glassy and reflective. \n\nThe **2nd tier (30 m fall) flows year-round** — the dominant photographic subject. The 3rd tier completes the descent to the sea. The **120 m / 78 m-high Seonimgyo Bridge (선임교, ''Bridge of the Seven Nymphs'')** crosses the gorge midway through the loop — its cast-bronze relief panels along both sides depict **all seven nymphs in flight**, a literal architectural realization of the founding legend. \n\nSurrounding forest is a **rare-plant habitat** including **Korean toadlily (***Tricyrtis macropoda***)** and the endangered **Mankyua chejuense fern** (Jeju endemic, IUCN Critically Endangered). Loop length: **0.8 km, ~30 min walk** with several steep stair sections. \n\nAdmission: **Adult ₩2,500 / Youth ₩1,350 / FREE under 7 + over 65**. Cheonjeyeon is also a member of the **''Yeongjusipgyeong (영주십경, 10 Scenic Wonders of Jeju)''** Joseon-era literati canon — alongside Hallasan summit, Seongsan Sunrise, and Jeongbang Falls — meaning today''s southwest loop covers **2 of the 10 (Hallasan + Cheonjeyeon)** in a single day. \n\nThe biennial **Jeju Chilseonyeo (Seven Nymphs) Festival** held at the bridge in May (every odd year) reenacts the descent legend with traditional dance and musical performance — reservations required when the festival coincides with a tour date. Hours **09:00–18:00** year-round (last entry 17:30).", "image": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "highlights": ["**Natural Monument No. 378 (designated 1993)** — three-tier waterfall + rare-plant habitat", "Name **''Cheonjeyeon'' = ''Pond of the Emperor of Heaven''** — Joseon Daoist legend", "**Seven Nymphs (선녀) legend** carved into the **120 m × 78 m Seonimgyo Bridge** relief panels", "**1st tier (22 m / 21 m pond)** — only flows after heavy rain; **2nd tier (30 m) flows year-round**", "Habitat for **Mankyua chejuense fern** — Jeju endemic, IUCN Critically Endangered", "**0.8 km loop / ~30 min** — moderate stairs, footwear matters", "Admission **₩2,500 adult / ₩1,350 youth / FREE under 7 + over 65**", "**Jeju Chilseonyeo (Seven Nymphs) Festival** held biennially at the site — bridge ceremony", "**Misty microclimate** — natural cooling, popular summer afternoon retreat"], "timeUsed": ["Entrance + ticket — ~5 min", "Descent to 1st tier viewing platform — ~10 min", "1st tier + 2nd tier photography — ~20 min", "Seonimgyo Bridge + nymph relief panels — ~15 min", "Forest loop + ascent back to coach — ~25 min"], "whyOnRoute": "**Mid-afternoon contrast stop.** After Hallasan''s wide mountain scenery and Jusangjeolli''s open coast, Cheonjeyeon''s forested gorge brings shade, water, and a quieter atmosphere. The Seven Nymphs legend and Seonimgyo Bridge add a cultural story, while the Jungmun location keeps transfer time short before continuing to O''sulloc.", "_poi_meta": {"poi_key": "cheonjeyeon_falls", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Cultural Heritage Administration — Natural Monument No. 378 (1993 designation)", "VisitJeju — Cheonjeyeon Pokpo official listing", "Korea National Arboretum — Mankyua chejuense conservation records", "Jeju Cultural Foundation — Seven Nymphs Festival history", "Seogwipo City tourism — Cheonjeyeon admission and access"]}, "smartNotes": {"photo": "Instead of forcing everything into one frame, layered compositions with the bridge and waterfall usually look better.", "facilities": "Basic facilities are concentrated near the entrance.", "tip": "Because of stairs and potentially slippery sections, a steady pace usually makes this stop more enjoyable."}, "convenience": {"restroom": "Entrance area", "parking": "Parking available"}, "visitBasics": {"hours": "09:00–17:50 (last entry 17:10)", "closed": "Open year-round", "admission": "KRW 2,500 adults / KRW 1,350 teens and children", "walking": "Moderate, with stairs and sometimes wet sections"}, "images": ["/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "/images/tours/cheonjeyeon-falls/photo-004.webp"], "imageCredits": [{"url": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "source": "atoc-korea"}, {"url": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "source": "atoc-korea"}, {"url": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "source": "atoc-korea"}, {"url": "/images/tours/cheonjeyeon-falls/photo-004.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "location": "Cheonjeyeon Waterfall", "caption": "Cheonjeyeon Waterfall — photo 1", "alt": "Cheonjeyeon Waterfall — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "location": "Cheonjeyeon Waterfall", "caption": "Cheonjeyeon Waterfall — photo 2", "alt": "Cheonjeyeon Waterfall — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "location": "Cheonjeyeon Waterfall", "caption": "Cheonjeyeon Waterfall — photo 3", "alt": "Cheonjeyeon Waterfall — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/photo-004.webp", "location": "Cheonjeyeon Waterfall", "caption": "Cheonjeyeon Waterfall — photo 4", "alt": "Cheonjeyeon Waterfall — gallery image 4"}]}, {"number": 4, "time": "13:15", "duration": "60 min", "name": "Lunch — Seogwipo / Jungmun", "category": "Midday Reset — Seogwipo / Jungmun Local Cuisine", "description": "**A 60-minute reset between Cheonjeyeon Waterfall and O''Sulloc** — the Jungmun resort district is close to both, with a dense restaurant strip catering to both tourists and locals. Default rotation by season and group: **galchi-jorim (braised hairtail)** at a Seogwipo-side specialist when the boats are landing (Sep–Feb), **abalone bibimbap** year-round, or **heuk-doeji (Jeju black pork BBQ)** for guests who prefer grilled meat. \n\nJeju black pork (***Sus scrofa* domesticus, Jeju variety**) is a protected breed designated **Cultural Heritage Material No. 5 (2015)**, traceable to records from around the 12th century. Vegetarian alternative on request: **bibim-guksu** with seasonal Jeju vegetables. A **halal-friendly option** (ingredients disclosed) is available at one venue in the rotation — request it at pickup. After lunch it is about a 25-minute coach ride to O''Sulloc.", "image": null, "highlights": ["**Jungmun** restaurant strip — 3 km from both Jusangjeolli and Cheonjeyeon", "**Galchi-jorim** in season (Sep–Feb), **jeonbok-bibimbap** year-round", "**Heuk-doeji (Jeju black pig)** option — Cultural Heritage Material No. 5 (2015)", "**Halal-friendly + vegetarian** options (request at pickup)", "Lunch venue **5-min coach to Cheonjeyeon** — minimal post-meal transit", "Group dietary requirements collected at pickup; menu pre-confirmed"], "timeUsed": ["Coach to lunch venue — ~5 min", "Order + meal — ~45 min", "Coach to Cheonjeyeon entrance — ~5 min", "Buffer — ~5 min"], "whyOnRoute": "Lunch in Jungmun keeps the route efficient because Jusangjeolli and Cheonjeyeon are both nearby. It also gives guests a comfortable chance to try Jeju favorites such as grilled cutlassfish, black pork, or abalone before the lighter tea-field and café stops later in the afternoon.", "smartNotes": {"photo": "If you want some lifestyle-style gallery shots, food photos work especially well here.", "facilities": "Dining facilities are more than sufficient.", "tip": "A calmer lunch usually improves the second half of the day more than saving a few extra minutes."}, "convenience": {"restroom": "Inside the restaurant", "parking": "Parking available"}, "visitBasics": {"hours": "Depends on the restaurant", "closed": "Varies by venue", "admission": "May be included depending on the product condition, or paid on site", "walking": "Minimal"}}, {"number": 5, "time": "14:35", "duration": "70 min", "name": "O''Sulloc Tea Museum", "category": "Tea Culture & Seogwang Plantation — AmorePacific Heritage", "description": "**O''Sulloc Tea Museum (오설록 티 뮤지엄, ''오설록'' meaning ''meeting snow + green'')** is the tea-culture flagship of **Amorepacific Corporation** — Korea''s largest beauty company. Founder **Suh Sung-whan personally pioneered the project in 1979**, reclaiming volcanic ash farmland on Jeju''s Seogwang plateau when conventional wisdom held tea couldn''t be grown commercially in Korea. \n\nToday the **Seogwang Dawon plantation (서광다원)** is **Korea''s largest green-tea field**, producing **~700 tonnes annually** across Amorepacific''s three Jeju estates. \n\nThe museum building **opened 2001** in the plantation''s heart and was named to **designboom''s Top 10 art museums** for its minimalist green-roofed pavilion-amid-tea-rows design. \n\n**FREE admission**, daily **09:00–18:00**, ~**2 million annual visitors**. The visit splits naturally into three segments: **(1) Museum interior** — tea production process, antique tea-ware collection from Tang dynasty (618–907 CE) onward, and rooftop observation deck with panoramic plantation view; **(2) Tea House cafe** — signature **green tea rolling cake (오설록 롤케이크)** and **green tea ice cream** served from the tea-leaf harvest year directly; **(3) Plantation walking paths** — gravel rows between tea bushes, popular for sunset photography at the western edge. \n\n**Innisfree Jeju House** (Amorepacific''s natural cosmetics brand) is a **5-minute walk** for guests interested in the broader brand ecosystem — also free admission with optional tangerine soap DIY workshop (₩15,000). \n\nThe museum building itself, designed by Korean architect **Mass Studies (Cho Min-suk)**, takes a deliberately low-profile horizontal form that mirrors the tea-row geometry rather than competing with the agricultural landscape — the architectural deference earning it both the designboom Top 10 listing and ongoing use as a case study in Korean contemporary museum design. \n\nOptional add-on: the **Osulloc Tea Class (₩30,000 per person, 60 min, advance booking required)** — guided tea-flight tasting with brewing technique demonstration on Korean ceramics, available daily **10:00–16:00**, English-speaking instruction on Wed/Sat sessions.", "image": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "highlights": ["**Amorepacific** flagship — Korea''s largest beauty company; founder Suh Sung-whan pioneered Jeju tea **1979**", "**Seogwang Dawon = Korea''s largest green-tea field**; ~700 tonnes annual production", "Museum **opened 2001** — designboom Top 10 art museums (architecture)", "**FREE admission**, daily **09:00–18:00**, ~2 million annual visitors", "Antique tea-ware collection spanning **Tang dynasty (618–907 CE)** to modern Korean Joseon ceramics", "**Green tea rolling cake** + **green tea ice cream** = signature cafe items", "**Innisfree Jeju House** 5-min walk — free, optional tangerine soap DIY ₩15,000", "Plantation walking paths **best at golden hour (16:00–17:00)** for photography", "Rooftop deck + ground-level rows give two distinct elevations for tea-row composition"], "timeUsed": ["Parking + entrance — ~5 min", "Museum interior + tea-ware collection — ~20 min", "Tea House cafe (rolling cake + ice cream) — ~20 min", "Plantation walking path — ~20 min", "Optional Innisfree Jeju House visit — ~10 min"], "whyOnRoute": "O''sulloc shifts the day from nature scenery to Jeju lifestyle. The tea fields, museum space, café, and desserts make it an easy indoor-outdoor stop, especially if the weather changes. Its location on the Seogwang plateau also sits naturally between Jungmun''s south-coast sites and the final Aewol coastal stop.", "_poi_meta": {"poi_key": "osulloc_tea_museum", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Amorepacific corporate history (amorepacific.com)", "O''sulloc Tea Museum official site (osulloc.com)", "designboom Top 10 art museums archival listing", "Korea Tea Industry Association — production statistics", "VisitJeju — Osulloc Tea Museum"], "image": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "images": ["/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp"], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "O''sulloc Tea Museum", "alt": "O''sulloc Tea Museum — gallery image 1", "caption": "O''sulloc Tea Museum — photo 1"}, {"id": 2, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "O''sulloc Tea Museum", "alt": "O''sulloc Tea Museum — gallery image 2", "caption": "O''sulloc Tea Museum — photo 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "O''sulloc Tea Museum", "alt": "O''sulloc Tea Museum — gallery image 3", "caption": "O''sulloc Tea Museum — photo 3"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "O''sulloc Tea Museum", "alt": "O''sulloc Tea Museum — gallery image 4", "caption": "O''sulloc Tea Museum — photo 4"}], "imageCredits": [{"url": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "source": "atoc-korea"}]}, "smartNotes": {"photo": "Wide tea-field views and side angles near the cafe usually photograph better than product-style close-ups alone.", "facilities": "With restrooms, drinks, and places to sit, this is one of the most comfortable stops in the second half of the day.", "tip": "It usually feels more satisfying to enjoy both the scenery and the cafe atmosphere rather than rushing through the museum only."}, "convenience": {"restroom": "Museum and cafe area", "parking": "Parking available"}, "visitBasics": {"hours": "Usually 09:00–18:00, with possible seasonal variation", "closed": "Open year-round", "admission": "Free", "walking": "Easy"}, "images": ["/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp"], "imageCredits": [{"url": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "O''sulloc Tea Museum", "alt": "O''sulloc Tea Museum — gallery image 1", "caption": "O''sulloc Tea Museum — photo 1"}, {"id": 2, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "O''sulloc Tea Museum", "alt": "O''sulloc Tea Museum — gallery image 2", "caption": "O''sulloc Tea Museum — photo 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "O''sulloc Tea Museum", "alt": "O''sulloc Tea Museum — gallery image 3", "caption": "O''sulloc Tea Museum — photo 3"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "O''sulloc Tea Museum", "alt": "O''sulloc Tea Museum — gallery image 4", "caption": "O''sulloc Tea Museum — photo 4"}]}, {"number": 6, "time": "16:15", "duration": "55 min", "name": "Aewol Cafe Street (Handam Coastal Trail)", "category": "Coastal Cafe Strip — Afternoon Café + Olle Trail 15A Segment", "description": "**Aewol Cafe Street (애월 카페거리)** is the **5 km coastal stretch of Aewol-eup along the Handam Coastal Trail (한담해안산책로)** on Jeju''s northwest coast — Korea''s most concentrated **''sea-view cafe'' destination**, with 30+ design-forward cafes packed into the cliff-edge strip between Handam Beach and Gwakji Beach. \n\nThe promenade itself is officially named **Jang Han Chul Promenade (장한철산책로)** after **Jang Han Chul (장한철, 1744–?)** — a Jeju-born Joseon-era scholar whose **''Pyohaerok (표해록)''** is one of the earliest Korean accounts of survival at sea, written after his Pacific drift in 1771. \n\nThe walking path is a **30-minute one-way coastal segment of Jeju Olle Trail 15A (Hallim → Gonae)** — black basalt clifftops, tide pools, hexagonal jointing on a smaller scale than Daepo, and unobstructed west-facing horizon = Jeju''s premier sunset viewing strip. \n\n**Signature cafes in rotation by season**: **Bomnal Cafe (봄날 카페)** — appeared in the **2014 K-drama ''You Who Came From the Stars (별에서 온 그대)''** and made Aewol a celebrity-pilgrimage destination overnight; **Randy''s Donuts** (LA brand, Korean franchise — large rooftop deck); **Cafe Knotted** (signature cream donut + sea-view); **Haejigae Cafe** (literally ''sunset cafe'', dedicated to evening light service); **Aewol the Sunset** (rooftop terrace, premium pricing). \n\nFREE admission to the trail and beaches; cafes pricing typical ₩6,000–12,000 per drink + dessert. **Jang Han Chul''s ''Pyohaerok (표해록)''** — the eponymous source of the promenade''s name — is considered one of the foundational texts of **Korean maritime literature**, recording his 29-day Pacific drift after a Jeju-bound ship was blown off course in **December 1770**. \n\nRescued by Ryukyu (modern Okinawa) fishermen and eventually returned home via Nagasaki, his account predates similar Western survival memoirs by decades and informs modern Korean ocean-history scholarship. \n\nThe promenade''s signage along the cliff path quotes passages from the work in Korean + English — a rare in-situ literary heritage marker. Note for **photography enthusiasts**: drone use along the Aewol coast is permitted **outside the 9 km Jeju International Airport approach corridor** — confirm exact perimeter via Korea Drone Map app before flying. \n\nThe **Olle Trail 15A segment** officially runs Hallim Port → Aewol → Gonae Port over 13 km; today''s tour walks the central 1.5 km between Handam and Gwakji.", "image": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "highlights": ["**5 km coastal cafe strip** between Handam and Gwakji beaches — Korea''s densest sea-view cafe row", "**Jang Han Chul Promenade** — named for Jeju-born Joseon scholar (1744–?) author of **''Pyohaerok''** survival memoir", "**Olle Trail 15A** segment (Hallim → Gonae) — 30-min one-way coastal walk", "**Bomnal Cafe (봄날 카페)** = **''You Who Came From the Stars'' (2014, SBS)** filming site", "Rotating signature cafes: **Randy''s Donuts**, **Cafe Knotted**, **Haejigae Cafe**, **Aewol the Sunset**", "**West-facing horizon** = unobstructed sunset viewing — **17:30–18:30 in spring/autumn**", "**Hexagonal jointing visible** at Handam clifftops — same geology as Daepo, smaller scale", "Coastal trail + beaches **FREE**; cafes ~₩6,000–12,000 per drink + dessert", "**40-min coach drive from Jeju International Airport** — last viable stop before evening flights"], "timeUsed": ["Coach arrival + Handam parking — ~5 min", "Coastal trail walk (Handam → mid-section) — ~20 min", "Selected cafe stop (drink + dessert) — ~30 min", "Sunset photography at clifftop — ~15 min", "Walk back to coach — ~5 min"], "whyOnRoute": "**Sunset-focused finale.** Aewol works well as the last stop because it faces west, has a comfortable coastal trail, and offers many sea-view cafés if guests want to rest indoors. It is also a practical final stop before returning toward Jeju City or the airport, so the day can end with a relaxed seaside atmosphere instead of a long detour.", "_poi_meta": {"poi_key": "aewol_cafe_street", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Jeju Olle Foundation — Trail 15A official map (Hallim → Gonae)", "Aewol-eup Cultural Office — Jang Han Chul historical records", "VisitJeju — Aewol Cafe Street", "SBS Drama Archive — ''You Who Came From the Stars'' filming locations", "Joseon Wangjo Sillok / Korean Folklore Society — Pyohaerok textual study"]}, "smartNotes": {"photo": "Later-afternoon backlight and sea-facing terraces usually create the best images here.", "facilities": "Comfort depends on which cafe is chosen, so flexible operation works better than fixing one venue too rigidly.", "tip": "This stop usually scores higher when guests are allowed a freer rhythm rather than being guided too tightly."}, "convenience": {"restroom": "Depends on the cafe you use", "parking": "Parking available in the area"}, "visitBasics": {"hours": "The area itself is open all day; each cafe has its own hours", "closed": "No closure day for the area as a whole", "admission": "Free", "walking": "Easy"}, "images": ["/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp"], "imageCredits": [{"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "location": "Aewol Cafe Street (Handam Coastal Trail)", "caption": "Aewol Cafe Street (Handam Coastal Trail) — photo 1", "alt": "Aewol Cafe Street (Handam Coastal Trail) — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "location": "Aewol Cafe Street (Handam Coastal Trail)", "caption": "Aewol Cafe Street (Handam Coastal Trail) — photo 2", "alt": "Aewol Cafe Street (Handam Coastal Trail) — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "location": "Aewol Cafe Street (Handam Coastal Trail)", "caption": "Aewol Cafe Street (Handam Coastal Trail) — photo 3", "alt": "Aewol Cafe Street (Handam Coastal Trail) — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "location": "Aewol Cafe Street (Handam Coastal Trail)", "caption": "Aewol Cafe Street (Handam Coastal Trail) — photo 4", "alt": "Aewol Cafe Street (Handam Coastal Trail) — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp", "location": "Aewol Cafe Street (Handam Coastal Trail)", "caption": "Aewol Cafe Street (Handam Coastal Trail) — photo 5", "alt": "Aewol Cafe Street (Handam Coastal Trail) — gallery image 5"}]}, {"number": 7, "time": "17:30", "duration": "45 min", "name": "Iho Tewoo Beach (Horse Lighthouses · Sunset)", "category": "Jeju City Beach — Jeju Pony Lighthouses + Sunset Finale", "description": "**Iho Tewoo Beach (이호테우해변, Iho Beach)** is the closest beach to downtown Jeju and Jeju International Airport, and serves as the **sunset finale** that wraps up the day. Its most iconic sight is the pair of **Jeju pony lighthouses (horse lighthouses)** facing each other atop the breakwaters — a **red horse lighthouse and a white horse lighthouse, each about 12 m tall**, shaped like Jeju ponies and standing on the outer and inner breakwaters respectively. The white and red colors are navigational markers that help ships distinguish the sides of the channel, and against the blue sea and sky they have become one of Jeju''s most prized photo spots. \n\nThe sandy beach is made of **fine, silvery sand** mixed with shell fragments, and its gentle slope draws many family visitors. Behind the beach is a **pine forest** that offers shade and walking paths, and at the lowest tide the broad sands reveal a **wondam** — a traditional Jeju fishing method that used the difference between high and low tide to trap fish. At Iho Tewoo, a restored example survives as the **Iho Mosalwon**. \n\nRight alongside the beach runs the **Dodu-dong Rainbow Coastal Road**, where you can enjoy colorful seaside barrier blocks and a coastal drive, and its proximity to the airport makes it **a great last stop before an evening flight**. Admission to the beach and walking paths is **free**.", "image": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "highlights": ["**The closest beach to downtown Jeju and the airport** — sunset finale + easy airport transfer", "Iconic **Jeju pony lighthouses (horse lighthouses)** — a red and a white one, about 12 m tall, a signature photo spot", "**Fine silvery sand** mixed with shell fragments + gentle slope — a family-friendly beach", "**Pine forest** shade and walking paths behind the beach", "**Wondam (Iho Mosalwon)**, a traditional Jeju fishing structure revealed at low tide", "Right alongside, the **Dodu-dong Rainbow Coastal Road** coastal drive", "**Free admission** — golden light at the sunset hour"], "timeUsed": ["Beach parking + walk in — ~5 min", "Pony lighthouse / breakwater walk + photos — ~20 min", "Sunset viewing on the sands / Rainbow Coastal Road — ~15 min", "Regroup — ~5 min"], "whyOnRoute": "**The day''s sunset finale and final stop.** After enjoying cafés and the coast in Aewol, it sits on the way back toward Jeju City, so the flow is natural, and the wide western horizon paired with the pony lighthouses closes the day in golden light. Its closeness to Jeju International Airport makes it ideal as a **last stop before drop-off or an evening flight** — sunset time shifts with the season (later in summer, earlier in winter), so the arrival time is adjusted to that day''s sunset.", "_poi_meta": {"poi_key": "iho_tewoo_beach", "kb_version": "raw-2026", "verified_date": "2026-06-23", "sources": ["VisitKorea — Iho Tewoo Beach (이호테우해변)", "VisitKorea — Iho Tewoo Horse Lighthouses (이호테우 말 등대)", "Jeju Tourism Organization", "Jeju City official tourism data"]}, "smartNotes": {"photo": "Framing the red and white pony lighthouses from the end of the breakwater is the most striking shot, and the backlit silhouettes at sunset along with the Rainbow Coastal Road are popular compositions.", "facilities": "Cafés, restaurants, and amenities are well established around the beach.", "tip": "Sunset time varies by season (around 19:30 in summer, around 18:30 in spring/autumn, around 17:40 in winter), so set arrival to that day''s sunset. With the airport nearby, it makes a great last stop before an evening flight."}, "convenience": {"restroom": "Public restrooms at the beach", "parking": "Free parking lot (busy on peak-season weekends)"}, "visitBasics": {"hours": "Beach and walking paths open 24 hours (free); visit at the sunset hour", "closed": "Open year-round", "admission": "Free (no admission or parking fee)", "walking": "Easy — flat sands and breakwater walk, about 15–20 min"}, "images": ["/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp"], "imageCredits": [{"url": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "source": "atoc-korea"}, {"url": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "location": "Iho Tewoo Beach", "caption": "Iho Tewoo Beach — photo 1", "alt": "Iho Tewoo Beach — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp", "location": "Iho Tewoo Beach", "caption": "Iho Tewoo Beach — photo 2", "alt": "Iho Tewoo Beach — gallery image 2"}]}], "routeFlowStops": [{"name": "1100 Highland", "theme": "Hallasan", "type": "01"}, {"name": "Jusangjeolli", "theme": "Coast", "type": "02"}, {"name": "Cheonjeyeon", "theme": "Waterfall", "type": "03"}, {"name": "Lunch", "theme": "Reset", "type": "04"}, {"name": "O''Sulloc", "theme": "Tea Fields", "type": "05"}, {"name": "Aewol", "theme": "Café", "type": "06"}, {"name": "Iho Tewoo", "theme": "Sunset", "type": "07"}], "routePhases": [{"phase": "오전", "duration": "1-3", "description": ""}, {"phase": "정오~오후 초반", "duration": "4-5", "description": ""}, {"phase": "마무리", "duration": "6-7", "description": ""}], "routeShapeIntro": {"title": "How this route flows", "subtitle": "Starting at the Hallasan 1100 Highland Ramsar wetland, the route runs through volcanic coast, a waterfall, lunch, and tea fields before finishing with Aewol Cafe Street and the Iho Tewoo sunset. Roughly 09:30 to 18:15."}, "whyTourWorks": {"bestFor": ["First-time Jeju travelers and couples", "Adult family trips", "Travelers who want nature, tea fields, and a softer finish", "Active middle-aged and older travelers"], "lessIdealFor": ["Travelers who want to avoid even short stair sections or uphill walks", "Groups relying heavily on strollers", "Itineraries built around very young children"], "routeLogicSections": [{"title": "Pace and structure", "icon": "sun", "iconBg": "bg-amber-50/80", "items": [{"label": "An easy start in the Hallasan highlands", "detail": "The 1100 Highland wetland is a flat boardwalk stroll, so it starts the day without physical strain while letting you feel the atmosphere of the Hallasan highlands, and the route flows naturally down to the southern coast."}, {"label": "Lunch sits in the right position", "detail": "Lunch resets the day between the more open and dramatic morning stops and the calmer waterfall-and-tea-field section that follows."}, {"label": "A gentle finish after O''Sulloc", "detail": "Once the tea fields soften the mood, Aewol opens the afternoon with coffee and sea views, and the final Iho Tewoo sunset closes the day in golden light."}]}, {"title": "How the route is designed", "icon": "mountain", "iconBg": "bg-sky-50/80", "items": [{"label": "Mountain first, sea second", "detail": "This route is designed so you first experience the altitude and alpine wetland of Hallasan 1100 Highland, then have the view open up dramatically to the coast at Jusangjeolli."}, {"label": "Waterfall before tea fields", "detail": "Cheonjeyeon settles the route down before O’Sulloc opens the second half in a lighter and gentler way."}, {"label": "A coastal finish that closes with sunset", "detail": "After enjoying cafés and the coast in Aewol, you meet the sunset at the Iho Tewoo pony lighthouses, closing the day with a lifestyle-oriented finish rather than yet another packed sightseeing stop."}]}, {"title": "When conditions change", "icon": "wind", "iconBg": "bg-slate-50/80", "items": [{"label": "Hallasan road variables", "detail": "At 1100 Highland, Road 1100 may be closed during heavy snow, heavy rain, or icing, in which case the plan is adjusted to an indoor alternative such as the Jeju National Museum."}, {"label": "Wind on the coast", "detail": "Jusangjeolli and Aewol are much more directly exposed to wind than inland stops."}, {"label": "A balanced overall walking load", "detail": "1100 Highland and Iho Tewoo are flat, but Cheonjeyeon has stairs and short uphill sections that call for some care."}]}]}, "practicalAccordionItems": [{"id": "pickup", "title": "Pickup and Return", "preview": "Hotel-lobby pickup in the Jeju City area", "content": ["Pickup takes place at your hotel lobby between 8:20 and 8:50 a.m.", "Return is scheduled between 6:30 and 7:00 p.m., after the Iho Tewoo sunset.", "Airport pickup/drop-off may be possible on request.", "Your exact pickup time is confirmed the night before."]}, {"id": "walking", "title": "Walking and Terrain", "preview": "Moderate overall, and manageable for most guests", "content": ["Total walking across the day is usually around 3.5–4.5 km.", "1100 Highland: about 1 km of flat boardwalk (around 20 min), the easiest section.", "Jusangjeolli: an easy coastal walking path.", "Cheonjeyeon: forest path, stairs, and occasionally slippery sections.", "O''Sulloc, Aewol, Iho Tewoo: comfortable stops where you can take it easy.", "Walking shoes with good grip are recommended."]}, {"id": "weather", "title": "Weather and Closure Adjustments", "preview": "The tour usually runs, with changes if needed", "content": ["Light rain: the tour usually runs as planned.", "If Road 1100 is closed due to heavy snow, heavy rain, or icing: 1100 Highland may be adjusted to an indoor alternative (e.g., the Jeju National Museum).", "In strong wind: time at Jusangjeolli, Aewol, or Iho Tewoo may be shortened.", "If the weather worsens in the afternoon: a larger share of the afternoon may be spent at O''Sulloc.", "If a particular stop is closed: an alternative stop may be used."]}, {"id": "wear", "title": "What to Wear and Bring", "preview": "Good shoes, layers, and a light jacket", "content": ["Shoes with good grip", "Layered clothing for mountain and coastal temperature differences", "A light windbreaker", "Hat and sunscreen", "Water bottle"]}, {"id": "included", "title": "What’s Included / Not Included", "preview": "Guide, vehicle, pickup, and admission included", "variant": "included", "content": ["English-speaking guide", "Small-group vehicle", "Jeju City area hotel pickup and drop-off", "All admission tickets", "Bottled water", "Lunch (pay on site)", "Personal shopping expenses", "Guide gratuities"]}], "practicalWeatherStatic": {"today": {"temp": "—", "label": "Live weather integration"}, "tomorrow": {"temp": "—", "label": "Updated daily"}, "_seasonalSummary": "Southwest Jeju has the most varied terrain on the island — from Hallasan''s 1100 Highland Ramsar wetland to Iho Tewoo''s city beach. The 1100m highland runs 7-10°C cooler than the coast; bring a layer year-round.", "_seasonalTemperatures": [{"season": "Spring (Mar–May)", "range": "6–20°C inland / 10–22°C coast", "notes": "Cherry blossoms; new tea leaves at Osulloc."}, {"season": "Summer (Jun–Aug)", "range": "18–25°C inland / 22–30°C coast", "notes": "1100 Highland stays cool; Iho Tewoo lively at sunset."}, {"season": "Autumn (Sep–Nov)", "range": "8–22°C inland / 12–24°C coast", "notes": "Best season — golden tea fields, clear Hallasan views."}, {"season": "Winter (Dec–Feb)", "range": "-2–7°C inland / 3–10°C coast", "notes": "1100 Highland often snowy — striking, but Road 1100 may close; warm layers required."}]}, "seasonalVariations": [{"season": "Spring", "description": "A season when rapeseed blooms can add yellow color to parts of the coast."}, {"season": "Summer", "description": "Days are long, and the greens across the route feel especially deep and vivid."}, {"season": "Autumn", "description": "Clear skies often make the route’s mountain, coast, and tea-field layers feel especially sharp."}, {"season": "Winter", "description": "The route usually feels quieter, with shorter daylight and a calmer overall mood."}], "bookingTrustItems": [{"icon": "check-circle", "title": "Licensed local operation", "description": "Legally operated guiding in Jeju", "iconBg": "bg-emerald-50/80", "body": "Licensed Korean tour operator — the southwest Jeju year-round circuit covering Hallasan highland, columnar cliffs, waterfall, tea fields, and Aewol cafe coast in a single nine-hour loop."}, {"icon": "route", "title": "Built around Jeju Southwest", "description": "Designed specifically for the southwest route", "iconBg": "bg-sky-50/80", "body": "No mandatory shopping stops: Osulloc Tea Museum has free admission and the Aewol cafe street is free-time exploration — no commission-based retail pressure."}, {"icon": "users", "title": "Operates in a small group", "description": "Up to 8 guests", "iconBg": "bg-amber-50/80", "body": "All-season routing: the 1100 Road wetland shows misty summer atmosphere, brilliant autumn foliage, and occasional winter snow, making the stop genuinely worthwhile in any season."}], "bookingSupportSteps": [{"timing": "Right after booking", "title": "Instant confirmation", "detail": "You receive a booking confirmation with a summary of the day.", "description": "Instant confirmation with Jeju City hotel pickup details (free within city; +₩70,000 outside)."}, {"timing": "12 hours before", "title": "12-hour reminder", "detail": "Weather notes and route adjustments are shared in advance.", "description": "Pre-tour note on 1100 Road current conditions (summer fog, autumn foliage, winter snow probability) and Aewol cafe recommendations."}, {"timing": "The night before", "title": "Final pickup notice", "detail": "Your exact pickup time and driver contact details are shared.", "description": "Final pickup time confirmed the evening before."}, {"timing": "Morning of the tour", "title": "Day-of route note", "detail": "A short morning briefing is given based on live on-site conditions.", "description": "Morning message with weather and any 1100 Road closure note."}, {"timing": "During the tour", "title": "Live stop-by-stop guidance", "detail": "You receive the information you need at each stop.", "description": "Guide narrates Hallasan''s shield-volcano geology, UNESCO Geopark context of Jusangjeolli, the Seven Nymph waterfall legend, and Osulloc''s 1979 Amorepacific founding story."}, {"timing": "After the tour", "title": "Post-tour support", "detail": "Additional guidance and recommendations can be shared afterward.", "description": "Post-tour feedback request sent after drop-off."}], "staticQuestions": [{"id": "first-time", "question": "Is this a good choice for first-time visitors to Jeju?", "answer": "Yes. You get a well-balanced day that takes in the scenery of Hallasan 1100 Highland, volcanic coastline, a waterfall walk, the atmosphere of tea fields, and a finish with Aewol and the Iho Tewoo sunset."}, {"id": "walking", "question": "Is the walking difficult?", "answer": "Not really. Cheonjeyeon, which has stairs, is the most active section, but 1100 Highland is a flat boardwalk stroll and the rest of the itinerary is generally manageable."}, {"id": "rain", "question": "Does the tour run in rainy weather?", "answer": "Yes. The route can run even in the rain, and if Road 1100 is closed due to heavy snow or rain, 1100 Highland may switch to an indoor alternative or exposed coastal sections may be shortened."}, {"id": "parents", "question": "Is it suitable for traveling with parents or older family members?", "answer": "Yes, in many cases. It works well for adult family trips, especially when everyone is comfortable with stairs and short uphill sections."}, {"id": "children", "question": "Can I join with children?", "answer": "Yes. It is especially suitable for children around age 8 and up who can keep up with short walks and the rhythm of a full-day tour."}, {"id": "order", "question": "Can the order of stops change depending on conditions on the day?", "answer": "Yes. Depending on mountain weather, coastal wind, traffic, sunset time, and visitor flow, there may be minor reordering, especially around 1100 Highland and the coastal sections."}, {"id": "lunch", "question": "Is lunch included?", "answer": "That depends on the product condition. Lunch time is built into the route, but whether the meal itself is included follows your booked plan."}, {"id": "why-1100goji", "question": "Why does the route start at 1100 Highland?", "answer": "Because it opens the day by lightly experiencing the Hallasan highlands on a flat boardwalk stroll at the time of highest energy, without turning the day into a heavy hiking itinerary."}, {"id": "why-jusangjeolli", "question": "Why do you go to Jusangjeolli after Hallasan?", "answer": "Because it lets Jeju’s volcanic story unfold naturally from mountain terrain into a dramatic basalt coastline."}, {"id": "why-osulloc", "question": "Why does O''Sulloc come before Aewol?", "answer": "Because it softens the mood after the waterfall section, so that the later stops of Aewol and the Iho Tewoo sunset feel more relaxed and comfortable."}, {"id": "later-structure", "question": "Why is the second half structured this way?", "answer": "Lunch and Cheonjeyeon settle the rhythm after the lively morning section, O''Sulloc adds a light tea-field break, and Aewol and the Iho Tewoo sunset close the day naturally and with a lingering afterglow."}], "guestReviews": [], "reviewsSummary": {"averageRating": 0, "totalReviews": 0, "ratingDistribution": [{"stars": 5, "count": 0, "percentage": 0}, {"stars": 4, "count": 0, "percentage": 0}, {"stars": 3, "count": 0, "percentage": 0}, {"stars": 2, "count": 0, "percentage": 0}, {"stars": 1, "count": 0, "percentage": 0}], "highlights": []}, "sticky_booking_bar": {"note": "Select your d