"indoor_fallback_anchor_count": 2, "early_start_fit": 0.85, "late_finish_fit": 0.95, "full_day_fit": 1, "half_day_fit": 0.05, "value_priced_fit": 0.85, "budget_traveler_fit": 0.7, "free_admission_anchor_count": 4, "total_admission_krw_per_adult": 4500, "off_beaten_path_fit": 0.6, "crowd_avoidance_fit": 0.55, "tourist_circuit_fit": 0.85, "trendy_destination_fit": 1, "minicoach_fit": 1, "max_pax_per_vehicle": 14, "jeju_city_pickup_fit": 1, "airport_drop_compatible_fit": 1, "cruise_shore_excursion_fit": 0.5, "cruise_passenger_fit": 0.6, "korean_food_fit": 0.95, "jeju_local_cuisine_fit": 1, "galchi_fit": 0.95, "black_pig_heritage_fit": 0.85, "seafood_fit": 0.95, "vegetarian_friendly_fit": 0.8, "halal_friendly_fit": 0.6, "tea_tasting_fit": 1, "dessert_anchor_fit": 1, "photo_anchor_count": 5, "instagram_anchor_count": 5, "drone_friendly_fit": 0.55, "filming_location_fit": 0.85, "sunset_photography_fit": 1, "stair_anchor_count": 1, "barrier_free_anchor_fit": 0.55, "is_anchor_for_first_time_jeju_southwest": true, "catalog_position": "first_time_jeju_southwest_loop", "competing_tours_count": 4, "china_mainland_market_fit": 0, "korea_domestic_market_fit": 0, "taiwan_market_fit": 1, "singapore_market_fit": 1, "hong_kong_market_fit": 1, "china_diaspora_overseas_market_fit": 0.95, "se_asia_market_fit": 0.95, "us_market_fit": 0.85, "europe_market_fit": 0.85, "australia_market_fit": 0.85, "japan_market_fit": 0.85, "ramsar_wetland_fit": 1, "high_altitude_wetland_fit": 1, "wetland_ecology_fit": 1, "accessible_boardwalk_fit": 1, "iho_sunset_fit": 1, "horse_lighthouse_fit": 1}, "matching_metadata": {"primary_themes": ["jeju", "southwest", "first_time_jeju", "tea_culture", "cafe_culture", "sunset"], "secondary_themes": ["hallasan_unesco", "ramsar_wetland", "columnar_jointing", "three_tier_waterfall", "seven_nymphs_legend", "amorepacific_heritage", "olle_trail", "horse_lighthouse"], "best_for": ["first_time_jeju", "couples", "honeymoon_travelers", "tea_lovers", "lifestyle_travelers", "k_drama_fans", "photographers", "guests_with_evening_flights"], "not_recommended_for": ["thrill_seekers", "private_tour_seekers", "guests_demanding_seongsan_sunrise", "young_kids_under_5", "guests_avoiding_cafe_culture"], "anchor_pois": ["Hallasan 1100 Highland Wetland", "Daepo Jusangjeolli", "Cheonjeyeon Falls", "O''sulloc Tea Museum", "Aewol Cafe Street", "Iho Tewoo Beach"], "anchor_poi_keys": ["hallasan_1100_wetland", "daepo_jusangjeolli_cliff", "cheonjeyeon_falls", "osulloc_tea_museum", "aewol_cafe_street", "iho_tewoo_beach"], "reviews_attribution": null, "unesco_fit_note": "unesco_fit=3: Hallasan is a UNESCO Biosphere Reserve and the centerpiece of the Jeju Volcanic Island and Lava Tubes World Heritage inscription. The tour visits the 1100 Highland Ramsar wetland (a flat boardwalk inside the Hallasan World Heritage / Biosphere boundary), not the inscribed lava-tube system or the summit hike.", "competing_products": ["jeju-grand-highlights-loop", "jeju-southern-top-unesco-spots-tour", "jeju-west-south-full-day-authentic-tour", "jeju-hydrangea-festival-tour-southwest-route"], "audit_summary": "Southwest Jeju loop covering UNESCO Hallasan via the 1100 Highland Ramsar wetland (Site #1893, flat boardwalk), south-coast volcanic geology (Daepo Jusangjeolli), Joseon Daoist mythology (Cheonjeyeon Seven Nymphs), Korea''s largest tea field (Osulloc / AmorePacific), the west-coast cafe strip (Aewol), and a sunset finale at Iho Tewoo Beach with its iconic horse lighthouses. Easier, more accessible and more sunset-anchored than the highlights-loop sister tour.", "score_rationale": {"high_scores": {"first_time_jeju_fit=0.95": "Strong intro covering UNESCO Hallasan + geology + culture + sunset in one day", "honeymoon_fit=1.0": "Sunset finale at Iho Tewoo + Aewol cafe culture + tea heritage = strongest honeymoon framing", "tea_culture_fit=1.0": "Seogwang plantation = Korea''s largest green-tea field; Amorepacific brand depth", "sunset_photography_fit=1.0": "Iho Tewoo horse lighthouses + west-facing horizon — the single best sunset stop", "mobility_friendly_fit=0.85": "1100 Highland boardwalk + Iho Tewoo beach are flat; only Cheonjeyeon has stairs", "cafe_culture_fit=1.0": "30+ cafes on Aewol''s 5 km strip — Korea''s densest sea-view cafe row"}, "low_scores": {"private_tour_fit=0.05": "Format is small-group fixed itinerary only", "triple_unesco_fit=0.05": "Seongsan deliberately absent — that''s the highlights-loop sister tour", "east_jeju_fit=0.05": "Loop deliberately excludes east coast", "thrill_seekers_fit=0.05": "Pace is contemplative; no adventure activities"}}, "differentiation_vs_highlights_loop_sister": "Southwest-coastal anchor terminating with a sunset finale at Iho Tewoo Beach (sister terminates at east-coast Seongsan Triple UNESCO). This tour = 1100 Highland wetland + tea + cafe + sunset lifestyle emphasis on an easy, accessible profile; sister = UNESCO + geology emphasis. Honeymoon + lifestyle + sunset-photography fit = highest in catalog for southwest framing, with the sunset window timed to seasonal sunset at Iho Tewoo. Pairs complementarily on 2-day Jeju itineraries.", "seasonal_window": {"best_months": ["April", "May", "September", "October", "November"], "good_months": ["March", "June", "August"], "caveat_months": ["July (monsoon)", "December", "January (Hallasan ice)"], "peak_crowd_months": ["April (cherry)", "October (foliage)", "May (tea harvest start)"], "sunset_optimal_months": ["April", "May", "September", "October"]}, "kb_anchor_version": "1.29"}, "pickup_dropoff": {"type": "hotel_lobby", "meeting_points": [{"name": "Jeju City hotel lobbies", "time": "08:30–09:00"}], "dropoff_points": [{"name": "Jeju City hotels (return)", "approx_time": "≈ 18:30–19:00"}], "hotel_pickup_available": true, "notes": "Pickup time 08:30–09:00 a.m., based on hotel lobbies within Jeju City; the final time is confirmed the evening before. Return is after the Iho Tewoo sunset, and depending on circumstances airport pickup/drop-off may also be possible."}, "itinerary_variants": [], "_publication": {"schema_version": "v4_canonical", "last_modified": "2026-06-24", "version_history": ["v1_smallgroup", "v15_unified", "v18_route_2026_06_24"], "fix_passes": {"v15_unified": "Migrated from small-group v1 schema to v15 standard: schema_version 1→7; SEO expanded (primaryKeywords, ogImage, title); price expanded (priceSource, priceNote, discountPercent); routeFlowStops id→type; routePhases stripped of Tailwind classes (bgClass/dotClass/textClass), reshaped to {phase,duration,description}; seasonalVariations stripped of Tailwind, reshaped to {season,description}; whyTourWorks.lessIdeal→lessIdealFor; practicalWeatherStatic gained _seasonalSummary and _seasonalTemperatures; matching_profile expanded to v15 standard (≥40 fields with anchor_poi_keys, vehicle_type_legacy, seasonality, fit-vector full set); matching_metadata reformatted to anchor_pois/anchor_poi_keys/primary_themes/secondary_themes/best_for/not_recommended_for/reviews_attribution/unesco_fit_note shape; pickup_dropoff added (Schema A.1); itinerary_variants=[]; _publication block added. PRESERVED from source (richer than catalog v15): itineraryStops[*].visitBasics, .convenience, .smartNotes (operational data), guestReviews[4 each], reviewsSummary.highlights.", "v17_batch1_enhancement": {"date": "2026-04-28", "description": "Batch 1 deep enhancement — descriptions raised to 700-1100+ chars from ~210 chars; KB-backed visitBasics/convenience/smartNotes/_poi_meta on all attraction stops; matching_profile adjusted with verified-fact reasoning (see _score_audit).", "_score_audit": {"_methodology": "Scores use the current 0-1 float scale. Each delta is anchored to verified facts.", "deltas_applied": {"culture_level": {"old": 3, "new": 4, "reasoning": "UPGRADED 3→4. Verified: O''sulloc has 25-year tea cultivation history (Suh Sungwhan 1979 reclamation, Korea''s first tea museum 2001, designboom Top-10), plus Cheonjeyeon''s Seven Nymphs legend and biennial Chilseonyeo Festival. Two genuine cultural anchors elevates from 3."}, "tea_culture_fit": {"old": "MISSING", "new": 5, "reasoning": "ADDED-PROPOSAL. O''sulloc + Seogwang Plantation = Korea''s flagship tea destination, 2 million visitors/year. 5/5 if added."}, "cafe_culture_fit": {"old": "MISSING", "new": 5, "reasoning": "ADDED-PROPOSAL. Aewol is Korea''s most documented cafe street; O''sulloc cafe is a destination in itself. 5/5 if added."}, "cafe_fit": {"old": "?", "new": 5, "reasoning": "Existing cafe_fit field present. Updated to 5 — Aewol cafe street + O''sulloc cafe + adjacent Innisfree Green Cafe = 3 anchored cafe stops in one day."}, "unesco_fit": {"old": 3, "new": 3, "reasoning": "Confirmed: Hallasan = UNESCO World Heritage 2007 + Biosphere Reserve 2002. 1 of 5 attractions UNESCO-recognised. 3/5 retained."}, "walking_level": {"old": 3, "new": 4, "reasoning": "UPGRADED 3→4. Verified totals: Eoseungsaengak 2.6 km RT + 200 m gain (60 min), Jusangjeolli 0.8 km flat (15 min), Cheonjeyeon many stairs across 3 tiers (~1 km, 60-90 min), O''sulloc flat (15 min walk), Aewol 2 km coastal flat. Total ~6 km + ~250 m elevation. The Cheonjeyeon stair sections push this from 3 to 4."}, "young_kids_fit": {"old": 4, "new": 3, "reasoning": "DOWNGRADED 4→3. Eoseungsaengak''s 200 m wooden-stair gain and Cheonjeyeon''s multi-tier stair complex are both demanding for under-7s. Aewol/O''sulloc are kid-friendly but the day''s first half is not."}, "couple_fit": {"old": 5, "new": 5, "reasoning": "Confirmed: Aewol sunset coast, O''sulloc tea+cafe, Cheonjeyeon''s Seven-Nymphs lore are textbook couple stops. 5/5 verified."}, "weather_sensitivity": {"old": 3, "new": 4, "reasoning": "UPGRADED 3→4. Eoseungsaengak (wooden stairs slippery wet, icy winter), Jusangjeolli (high-tide spray), Aewol (coastal walk weather-exposed) are all weather-dependent. Only O''sulloc fully indoor."}, "iconic_landmark_fit": {"old": "?", "new": 4, "reasoning": "Hallasan + Jusangjeolli + O''sulloc are nationally iconic. Cheonjeyeon and Aewol are regionally iconic. 4/5 (vs Grand Highlights'' 5/5 — that route has Seongsan which carries the Triple-UNESCO crown)."}, "rain_fit": {"old": "?", "new": 3, "reasoning": "Cheonjeyeon ACTUALLY BENEFITS from rain (1st tier only flows after rainfall — verified). O''sulloc indoor. Eoseungsaengak/Jusangjeolli/Aewol exposed. 3/5 — rain neutral overall."}, "value_for_money_fit": {"old": 5, "new": 5, "reasoning": "Verified fees: Hallasan free, Jusangjeolli ₩2,000, Cheonjeyeon ₩2,500, O''sulloc free, Aewol free. ~₩4,500/adult total fee day. 5/5 confirmed."}, "first_time_fit": {"old": "?", "new": 5, "reasoning": "5 distinct categories in one route (mountain, geology, waterfall, tea culture, cafe coast) — perfect first-Jeju overview. Verified itinerary diversity."}}}, "stops_enhanced": 6, "sources": ["VisitKorea", "Wikipedia", "Hallasan National Park", "AllTrails", "Trazy", "Inside Jeju", "World of Waterfalls", "third-party booking site Korea"]}, "v17_schema_unification": {"date": "2026-04-28", "description": "Phase 1: Standardized matching_profile scores to the current 0-1 float scale used by match_tours.matching_profile.", "fields_converted": 43, "fields_skipped": 0, "fields_already_float": 0}, "v18_route_2026_06_24": "Route revision: opener Hallasan Eoseungsaengak → Hallasan 1100 Highland Ramsar wetland (hallasan_1100_wetland); reordered Cheonjeyeon before lunch; added sunset finale stop Iho Tewoo Beach (iho_tewoo_beach, horse lighthouses). Now 7 stops (6 attractions + lunch). Price set to single US$52 (no compare-at). Pickup/drop-off points unchanged; return shifted to 18:30–19:00 for sunset. matching_profile/metadata, catalog_card, SEO, hero, whyTourWorks, practical accordion, FAQ, gallery and page_sections updated across all 6 locales."}}}'::jsonb
