{"id": 9, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "location": "大浦柱状節理帯", "alt": "大浦柱状節理帯 — gallery image 3", "caption": "大浦柱状節理帯 — photo 3"}, {"id": 10, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "location": "大浦柱状節理帯", "alt": "大浦柱状節理帯 — gallery image 4", "caption": "大浦柱状節理帯 — photo 4"}, {"id": 11, "type": "photo", "src": "/images/tours/jusangjeolli/photo-005.webp", "location": "大浦柱状節理帯", "alt": "大浦柱状節理帯 — gallery image 5", "caption": "大浦柱状節理帯 — photo 5"}, {"id": 12, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "location": "天帝淵滝", "alt": "天帝淵滝 — gallery image 2", "caption": "天帝淵滝 — photo 2"}, {"id": 13, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "location": "天帝淵滝", "alt": "天帝淵滝 — gallery image 3", "caption": "天帝淵滝 — photo 3"}, {"id": 14, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/photo-004.webp", "location": "天帝淵滝", "alt": "天帝淵滝 — gallery image 4", "caption": "天帝淵滝 — photo 4"}, {"id": 15, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "オーソルロック・ティーミュージアム", "alt": "オーソルロック・ティーミュージアム — ギャラリー画像 2", "caption": "オーソルロック・ティーミュージアム — 写真 2"}, {"id": 16, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "オーソルロック・ティーミュージアム", "alt": "オーソルロック・ティーミュージアム — ギャラリー画像 3", "caption": "オーソルロック・ティーミュージアム — 写真 3"}, {"id": 17, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "オーソルロック・ティーミュージアム", "alt": "オーソルロック・ティーミュージアム — ギャラリー画像 4", "caption": "オーソルロック・ティーミュージアム — 写真 4"}, {"id": 18, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "location": "愛月カフェ通り（翰潭海岸散策路）", "alt": "愛月カフェ通り（翰潭海岸散策路） — gallery image 2", "caption": "愛月カフェ通り（翰潭海岸散策路） — photo 2"}, {"id": 19, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "location": "愛月カフェ通り（翰潭海岸散策路）", "alt": "愛月カフェ通り（翰潭海岸散策路） — gallery image 3", "caption": "愛月カフェ通り（翰潭海岸散策路） — photo 3"}, {"id": 20, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "location": "愛月カフェ通り（翰潭海岸散策路）", "alt": "愛月カフェ通り（翰潭海岸散策路） — gallery image 4", "caption": "愛月カフェ通り（翰潭海岸散策路） — photo 4"}, {"id": 21, "type": "photo", "src": "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp", "location": "愛月カフェ通り（翰潭海岸散策路）", "alt": "愛月カフェ通り（翰潭海岸散策路） — gallery image 5", "caption": "愛月カフェ通り（翰潭海岸散策路） — photo 5"}, {"id": 22, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "location": "梨湖テウ海水浴場", "caption": "梨湖テウ海水浴場 — photo 1", "alt": "梨湖テウ海水浴場 — gallery image 1"}, {"id": 23, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp", "location": "梨湖テウ海水浴場", "caption": "梨湖テウ海水浴場 — photo 2", "alt": "梨湖テウ海水浴場 — gallery image 2"}], "itineraryStops": [{"number": 1, "time": "09:30", "duration": "45分", "name": "漢拏山1100高地", "category": "高山ラムサール湿地のデッキ歩道 — ユネスコ漢拏山を味わう", "description": "**漢拏山1100高地湿地（漢拏山1100高地湿地）**は、漢拏山西側斜面の標高**1,100m**に位置する高山湿地で、**2009年10月12日にラムサール条約の国際的に重要な湿地（第1893号）**として登録されました。面積は約**13ha**で、漢拏山の**ユネスコ世界自然遺産であり生物圏保護区**の境界内に位置します — つまり白鹿潭の山頂まで登らずとも、漢拏山のユネスコ的価値を気軽に体験できる区間です。 \n\n湿地は高原のあちこちに点在する**16か所以上の淡水湿地と池**で構成され、**約1kmの平坦な木製デッキ遊歩道（約20分）**に沿って一周することができます。デッキはほとんど傾斜がなく、ベビーカーや歩行が不自由な方も比較的らくに巡ることができます。絶滅危惧の鳥類3種と危急種の植物1種（国家指定）をはじめ、済州固有の哺乳類・爬虫類・昆虫が生息し、デッキ各所の案内板で湿地の生態を解説しています。 \n\n湿地へ向かう**1100道路（1100道路、1973年開通、全長36.6km）**は、**韓国で最も標高の高い場所を通る国道**で、済州市と西帰浦の中文を南北に結びます。道を渡った**1100高地休憩所**にはコンビニ（GS25）と温かい飲み物・ラーメンを出すカフェ、展望台、そして**白鹿（白鹿）の像**（仙人が白い鹿に乗って漢拏山に登ったという済州の伝説）と**韓国人初のエベレスト登頂者コ・サンドンを称える公園**があり、10〜15分ほど休憩するのに最適です。 \n\n標高1,100m地点は海岸より気温が**7〜10℃低く**、真夏でも薄手の上着が必要です。冬には雪に覆われたデッキと凍りついた湿地が済州屈指の雪景色撮影スポットになりますが、**1100道路は大雪・大雨・凍結時に真っ先に通行止めになる道路**でもあります — その場合、行程は済州市内の屋内名所（例：国立済州博物館）に変更されます。 \n\n入場料・駐車場ともに**無料**で、別途の予約は不要です。", "image": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "highlights": ["**ラムサール国際的に重要な湿地 第1893号**（2009年登録） — 漢拏山ユネスコ世界遺産＋生物圏保護区の境界内", "標高**1,100mの高山湿地** — 16か所以上の淡水湿地・池が高原に分布", "**約1kmの平坦な木製デッキ**（約20分） — ベビーカー・歩行が不自由な方も比較的らく", "**1100道路** — 1973年開通、36.6km、韓国で最も標高の高い場所を通る国道", "絶滅危惧の鳥類3種＋危急種の植物1種など**済州固有の生態**が生息", "道を渡った**1100高地休憩所** — 白鹿の像、コ・サンドン公園、コンビニ・カフェ・展望台", "海岸より**気温が7〜10℃低い** — 真夏でも上着を推奨", "冬の**雪景色スポット**（ただし大雪時は1100道路が通行止め→屋内に変更）", "**入場無料＋駐車無料**、予約不要"], "timeUsed": ["1100高地休憩所での駐車＋トイレ — 約5分", "デッキ湿地遊歩道を一周 — 約20分", "展望台＋白鹿の像で写真 — 約10分", "休憩所での休息／ドリンク — 約10分"], "whyOnRoute": "**南西ループの起点**。済州市から1100道路を走って高地へと登り、漢拏山の規模と高山生態を気軽に体験したあと、南の中文海岸へ下って柱状節理と天帝淵へとつながります。山頂登山や急な上り坂の登山道とは異なり、**平坦なデッキ散策**なので体力的な負担がほとんどなく、予約なしで無料で**ラムサール湿地＋ユネスコ漢拏山**を同時に味わえる区間です。山から始まって海岸へ下る流れなので移動の動線が自然で、早い時間帯のため1100道路は比較的すいています — 冬季の通行止め時には屋内名所に変更します。", "_poi_meta": {"poi_key": "hallasan_1100_wetland", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Ramsar Sites Information Service — Site #1893 (Hallasan 1100 Altitude Wetland)", "Hallasan National Park official site (hallasan.go.kr)", "UNESCO WHC inscription 1264 (Jeju Volcanic Island and Lava Tubes, 2007)", "VisitKorea — 1100 Altitude Wetland (1100-goji)", "Jeju Special Self-Governing Province — Wetland Protected Area records"]}, "visitBasics": {"hours": "湿地デッキ歩道は24時間開放（無料）；1100高地休憩所のカフェ・売店は約09:00〜17:00", "closed": "通年開放だが大雪・大雨時は1100道路が通行止めになる場合あり — 冬季は訪問前に道路状況を確認", "admission": "無料（ラムサール湿地、入場料・駐車料なし）", "walking": "とても易しい — 約1kmの平坦な木製デッキを一周、15〜20分；ベビーカーなどほとんどの歩行レベルで可能"}, "convenience": {"restroom": "道を渡った1100高地休憩所にトイレあり", "parking": "休憩所の無料駐車場（雪の降る週末は混雑する場合あり）"}, "smartNotes": {"photo": "淡水池の上を横切る木製デッキと遠くに見える漢拏山が代表的な構図で、冬の雪景色は済州で最も多く撮影される場面のひとつです。休憩所の白鹿の像も人気のフォトスポットです。", "facilities": "道を渡った1100高地休憩所にコンビニ・カフェ・展望台・トイレがまとまっています。", "tip": "真夏でも1,100mの高地は海岸より7〜10℃低いので、薄手の上着をご用意ください。冬は1100道路が真っ先に通行止めになるため道路状況を確認し、通行止め時は屋内名所に変更されます。"}, "images": ["/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp"], "imageCredits": [{"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "漢拏山1100高地", "caption": "漢拏山1100高地 — photo 1", "alt": "漢拏山1100高地 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "漢拏山1100高地", "caption": "漢拏山1100高地 — photo 2", "alt": "漢拏山1100高地 — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "漢拏山1100高地", "caption": "漢拏山1100高地 — photo 3", "alt": "漢拏山1100高地 — gallery image 3"}]}, {"number": 2, "time": "11:00", "duration": "45分", "name": "大浦柱状節理帯", "category": "火山性海岸線 — 六角柱状節理溶岩", "description": "**大浦柱状節理（대포 주상절리、通称「チサッゲ」）** は、済州島チュンムン海岸に広がる **六角柱状節理玄武岩の断崖が1kmにわたって続く地帯** で、**2005年1月6日に天然記念物第443号** に指定されました。柱は海面から **30〜40m** の高さにそびえ立ち、**5〜7角形のポリゴン**（主に六角形）が密接に並んでいます。この形状は、**ハルラサンの山腹噴火（約25万〜14万年前）で噴出した玄武岩質溶岩が海に達し、冷却・収縮する際に冷却面に対して垂直に割れた** ことで生まれました。\n\n世界的に有名な柱状節理としては **ジャイアンツ・コーズウェー（英国）**・**デビルズ・ポストパイル（米国）**・**フィンガルの洞窟（スコットランド）** などがありますが、柱状節理帯は **東アジア随一の柱状節理地** であり、最もアクセスしやすい場所の一つです。800mの **木道ループ** を進むと欄干付きの崖縁に直接たどり着けます。\n\n**満潮時には波が柱に打ちつけ、高さ20mまで飛沫が上がる** こともあり、時には欄干を越えることもあります。入場料は **大人₩2,000／青少年₩1,000／7歳未満・65歳以上無料** です。当地は **済州ジオパーク（ユネスコ、2010年10月指定）** の一部であり、城山日出峰・万丈窟溶岩洞・水月峰とともに島内 **13の公式ジオサイト** のひとつです。\n\n崖上のデッキは **バリアフリー**（車いす・ベビーカー対応）となっています。ループ沿いの3か所の展望台ではそれぞれ異なる角度から柱を観察できます。**第一展望台** では柱を横から眺めることができ（六角形の形状を撮影するのに最適）、**中間展望台** では柱の頭頂部のパターンを真上から見下ろせ、**奥の展望台** からは晴れた日にハルラサンを背景にした1kmの海岸線の全景が楽しめます。\n\n**撮影のベストタイム：14:00〜16:00** — 西日が柱の面を正面から照らす時間帯。夕方の訪問はシルエット構図が楽しめますが、柱のディテールは失われます。営業時間：**09:00〜18:00（最終入場17:30）**、年間を通じて営業。", "image": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "highlights": ["**天然記念物第443号** — **2005年1月6日** 指定、済州島の海岸天然記念物として最も新しい", "柱は **30〜40m** の高さにそびえ立ち、海岸線 **1km** にわたって **5〜7角形のポリゴン**（主に六角形）が密集", "形成：**ハルラサンの山腹溶岩が約25万〜14万年前に海で冷却**し、冷却面に垂直に収縮・亀裂", "**東アジア随一の柱状節理地** — ジャイアンツ・コーズウェー・デビルズ・ポストパイル・フィンガルの洞窟と並ぶ存在", "**満潮時には高さ20mまで飛沫** — 波しぶき写真の撮影チャンス", "**0.8kmの木道ループ**、約15分の散策 — バリアフリーデッキ、車いす・ベビーカー対応", "**済州ジオパーク（ユネスコ2010年10月）** の一部 — 島内13か所のジオサイト", "入場料 **₩2,000（大人）／₩1,000（青少年）／7歳未満・65歳以上無料**", "晴れた日には北方向にハルラサン山頂が望め、地質学的に **直接下流に位置**"], "timeUsed": ["駐車 ＋ チケット購入 ＋ 入場 — 約5分", "最初の展望台まで歩く — 約5分", "崖端の柱状節理見学 ＋ 写真撮影 — 約15分", "木道ループを進む — 約10分", "バスに戻る — 約10分"], "whyOnRoute": "**南西ループの地質学的核心地点** — 地理的・地質学的にハルラサンの直接下流に位置。ハルラサンを起点とした溶岩が海に達した後、柱状節理帯では **同じ溶岩が1kmの海岸線に沿って30〜40mの六角柱状に固まった** 様子を観察できます。ここからツアーは **西へ3kmの天帝淵の滝** へ向かいます（対照的な姉妹ツアーは東の正房の滝へ）。これにより午後の行程全体が済州南西部のチュンムン＋安德回廊内に収まります。**竜頭海岸（干潮・天候により訪問不可の日が約30%）** や **松岳山（歩行距離が1.6km長い）** と比べ、大浦は **天候不問・バリアフリー・15分の散策** で南海岸最高のコストパフォーマンスを誇ります。午前遅めのタイミングは、正午のクルーズ船観光客の波が押し寄せる前に到着できる点でも有利です。", "_poi_meta": {"poi_key": "daepo_jusangjeolli_cliff", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Cultural Heritage Administration — Natural Monument No. 443 designation (2005-01-06)", "Jeju Global Geopark official site (geopark.jeju.go.kr)", "UNESCO Global Geoparks Network — Jeju (2010 designation)", "VisitJeju — Daepo Jusangjeolli", "Korea Geological Survey — Jeju basalt formation studies"]}, "visitBasics": {"hours": "09:00〜18:00（最終入場17:40）", "closed": "年中無休", "admission": "大人2,000ウォン／子ども・青少年1,000ウォン", "walking": "易しい"}, "convenience": {"restroom": "入口エリア", "parking": "有料駐車場"}, "smartNotes": {"photo": "少し斜めのアングルは、正面からのショットよりも玄武岩のテクスチャーと波のエネルギーをより効果的に捉えることができます。", "facilities": "施設はシンプルですが、入口エリアは実用的で十分です。", "tip": "風や海霧がスポットの雰囲気を素早く変えることがあるため、一定のペースで進むのが最も効果的です。"}, "images": ["/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "/images/tours/jusangjeolli/photo-005.webp"], "imageCredits": [{"url": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/photo-005.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "location": "大浦柱状節理帯", "caption": "大浦柱状節理帯 — photo 1", "alt": "大浦柱状節理帯 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "location": "大浦柱状節理帯", "caption": "大浦柱状節理帯 — photo 2", "alt": "大浦柱状節理帯 — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "location": "大浦柱状節理帯", "caption": "大浦柱状節理帯 — photo 3", "alt": "大浦柱状節理帯 — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "location": "大浦柱状節理帯", "caption": "大浦柱状節理帯 — photo 4", "alt": "大浦柱状節理帯 — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/jusangjeolli/photo-005.webp", "location": "大浦柱状節理帯", "caption": "大浦柱状節理帯 — photo 5", "alt": "大浦柱状節理帯 — gallery image 5"}]}, {"number": 3, "time": "12:00", "duration": "70分", "name": "天帝淵滝", "category": "三段の滝＋森林 — 「天帝の池」", "description": "**天帝淵（천제연、「연」＝池・「천제」＝天帝）**は、中文の火山性渓谷に位置する**三段の滝**で、希少な生態的組み合わせを理由に**天然記念物第378号（1993年指定）**に指定されています。名称は**朝鮮時代の道教伝説に由来し、七人の仙女（선녀、*ソンニョ*）が毎夜天から降りてきて上段の池で沐浴した**という神話に基づいています——絶え間なく霧が漂うこの劇的な場の微気候がその伝説をより一層際立たせています。\n\n**第1段（落差22 m、水深21 mの池）**は円形の玄武岩の壷に落ち込み、大雨の後にのみ流れます——普段は上段の池が静かな鏡のように光を反射しています。**第2段（落差30 m）は一年中流れており**、撮影の主役です。第3段は海へと下り切る最終段です。ループ中間部で渓谷を横断する**全長120 m・高さ78 mの仙人橋（선임교、「七仙女の橋」）**の両側には鋳造ブロンズのレリーフパネルが並び、**七人の仙女が全員飛翔する姿**が描かれています——創建伝説を建築として文字通り体現したものです。\n\n周囲の森は**希少植物の生息地**で、**ヤマホトトギス（*Tricyrtis macropoda*）**や絶滅危惧種の**マンキュア・チェジュエンスシダ**（済州島固有種、IUCNクリティカリー・エンデンジャード）が生育しています。ループ距離：**0.8 km・徒歩約30分**（急な階段区間複数あり）。入場料：**大人₩2,500 / 青少年₩1,350 / 7歳未満・65歳以上無料**。\n\n天帝淵はまた、**朝鮮時代の文人による「瀛州十景（영주십경、済州の絶景10選）」**——漢拏山山頂・城山の日の出・正房の滝などと並ぶ風景の殿堂——にも名を連ねています。つまり本日の南西ルートでは、**10選のうち2か所（漢拏山＋天帝淵）を1日で巡る**ことになります。隔年開催の**済州七仙女（チルソンニョ）祭り**は5月（奇数年）に橋にて行われ、伝統舞踊と音楽演奏で仙女降臨の伝説を再現します——ツアー日程と重なる場合は事前予約が必要です。営業時間：**09:00〜18:00**（年中無休、最終入場17:30）。", "image": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "highlights": ["**天然記念物第378号（1993年指定）** — 三段の滝＋希少植物の生息地", "名称**「天帝淵」＝「天帝の池」** — 朝鮮時代の道教伝説に由来", "**七仙女（선녀）の伝説**が**全長120 m×高さ78 mの仙人橋**のレリーフパネルに刻まれている", "**第1段（落差22 m / 水深21 mの池）** — 大雨後にのみ流れる；**第2段（落差30 m）は通年流れる**", "**マンキュア・チェジュエンス（*Mankyua chejuense*）シダ**の生息地 — 済州島固有種、IUCNクリティカリー・エンデンジャード（深刻な絶滅危惧）", "**0.8 kmのループ / 約30分** — 中程度の階段あり、履物に注意", "入場料：**大人₩2,500 / 青少年₩1,350 / 7歳未満・65歳以上無料**", "**済州七仙女（チルソンニョ）祭り** — 現地で隔年開催、橋での式典あり", "**霧の微気候** — 天然の冷却効果あり、夏の午後に人気のリトリートスポット"], "timeUsed": ["入場＋チケット購入 — 約5分", "第1段展望台への下り道 — 約10分", "第1段・第2段の撮影 — 約20分", "仙人橋＋仙女レリーフパネル鑑賞 — 約15分", "森のループ＋バスへの帰り（上り） — 約25分"], "whyOnRoute": "**午後の感覚リセットポイント** — 漢拏山の広大な高山の景色と柱状節理帯の開放的な海岸の後、天帝淵の閉じた森の渓谷は感覚をリセットし、木陰の涼しさをもたらします。七仙女伝説＋仙人橋は、ソプジコジのKドラマ撮影地としての遺産や城山の地質学的伝承と比較して、カタログ中で済州最強の**神話的アンカー**です。中文に位置するため、柱状節理帯からバスで**5分・オソルロックまでバスで10分**——済州南西部ツアーで最もタイトな日中の移動ウィンドウです。13:00着は**午後の雲が正午以降の光を和らげ**、樹冠と滝の撮影に適した光をもたらします。", "_poi_meta": {"poi_key": "cheonjeyeon_falls", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Cultural Heritage Administration — Natural Monument No. 378 (1993 designation)", "VisitJeju — Cheonjeyeon Pokpo official listing", "Korea National Arboretum — Mankyua chejuense conservation records", "Jeju Cultural Foundation — Seven Nymphs Festival history", "Seogwipo City tourism — Cheonjeyeon admission and access"]}, "visitBasics": {"hours": "09:00〜17:50（最終入場17:10）", "closed": "年中無休", "admission": "大人₩2,500 / 青少年・子供₩1,350", "walking": "中程度、階段あり、濡れた区間もある場合あり"}, "convenience": {"restroom": "入口エリア", "parking": "駐車場あり"}, "smartNotes": {"photo": "すべてを1フレームに収めようとするより、橋と滝を組み合わせた重層的な構図の方が仕上がりが良くなることが多い。", "facilities": "基本的な施設は入口付近に集中している。", "tip": "階段や滑りやすい区間があるため、ゆっくりとしたペースで進む方がこのスポットをより楽しめることが多い。"}, "images": ["/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "/images/tours/cheonjeyeon-falls/photo-004.webp"], "imageCredits": [{"url": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "source": "atoc-korea"}, {"url": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "source": "atoc-korea"}, {"url": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "source": "atoc-korea"}, {"url": "/images/tours/cheonjeyeon-falls/photo-004.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "location": "天帝淵滝", "caption": "天帝淵滝 — photo 1", "alt": "天帝淵滝 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "location": "天帝淵滝", "caption": "天帝淵滝 — photo 2", "alt": "天帝淵滝 — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "location": "天帝淵滝", "caption": "天帝淵滝 — photo 3", "alt": "天帝淵滝 — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/photo-004.webp", "location": "天帝淵滝", "caption": "天帝淵滝 — photo 4", "alt": "天帝淵滝 — gallery image 4"}]}, {"number": 4, "time": "13:15", "duration": "60分", "name": "昼食 — 西帰浦／中文", "category": "昼の休憩 — 西帰浦／中文のご当地料理", "description": "**天帝淵滝とオソルロックの間の60分休憩** — 中文リゾート地区は両スポットからともに近く、観光客と地元客の双方に対応する飲食店街が密集しています。季節およびグループに応じたデフォルトのローテーションメニュー：船が入港する時期（9月〜2月）には西帰浦の専門店での**タチウオの煮付け**、年間を通じて提供される**アワビビビンバ**、またはグリル料理を好むゲストには**黒豚（済州黒豚BBQ）**。 \n\n済州黒豚（***Sus scrofa* domesticus、済州品種**）は**文化財資料第5号（2015年）**に指定された保護品種で、約12世紀の記録まで遡ることができます。ベジタリアン向けの代替メニュー（リクエストにより）：旬の済州野菜を添えた**ビビン麺**。**ハラール対応オプション**（原材料開示済み）はローテーション内の食堂の1か所で提供 — ピックアップ時にリクエストしてください。昼食後、コーチでオソルロックまで約25分の距離です。", "image": null, "highlights": ["**中文**のレストラン街 — 柱状節理帯と天帝淵の両方から3km", "旬の**갈치조림（タチウオの煮付け）**（9〜2月）、**전복비빔밥（アワビのビビンバ）**は年間を通じて", "**흑돼지（済州黒豚）**オプション — 文化財資料第5号（2015年）", "**ハラール対応＋ベジタリアン**オプション（ピックアップ時にリクエスト）", "昼食会場から**コーチで5分で天帝淵へ** — 食後の移動は最小限", "グループの食事制限はピックアップ時に確認；メニューは事前に確定"], "timeUsed": ["コーチで昼食会場まで — 約5分", "注文＋食事 — 約45分", "コーチで天帝淵入口まで — 約5分", "バッファー — 約5分"], "whyOnRoute": "中文の立地により、**柱状節理帯（前）と天帝淵（後）の両方へコーチで5分でアクセス可能** — 西帰浦中心部での昼食と比較して約15分の短縮になります。タチウオ・黒豚・アワビは済州の三大看板食材であり、すべて地元産 — 固形食が少ない午後のお茶＋カフェのシークエンスの前に、一度の食事でその日の食の要を体験できます。", "visitBasics": {"hours": "レストランによって異なります", "closed": "会場によって異なります", "admission": "商品の条件によって含まれる場合もあれば、現地払いの場合もあります", "walking": "最小限"}, "convenience": {"restroom": "レストラン内", "parking": "駐車場あり"}, "smartNotes": {"photo": "ライフスタイル風のギャラリーショットを撮りたい場合、フード写真はここで特によく映えます。", "facilities": "食事施設は十分すぎるほど整っています。", "tip": "落ち着いた昼食は、数分を節約するよりも午後の時間をより充実させることが多いです。"}}, {"number": 5, "time": "14:35", "duration": "70分", "name": "オソルロック・ティーミュージアム", "category": "お茶文化と西光茶園 — アモーレパシフィックの遺産", "description": "**オソルロック・ティーミュージアム（오설록 티 뮤지엄、「오설록」は「雪と緑の出会い」を意味する）**は、韓国最大の美容企業**アモーレパシフィックのお茶文化旗艦施設**です。創業者の**徐成煥（ソ・ソンファン）が1979年に自らこのプロジェクトを開拓し**、従来の常識ではお茶を韓国で商業的に栽培できないとされていた済州の西光高原の火山灰農地を再生しました。\n\n現在、**西光茶園（서광다원）**は**韓国最大の緑茶畑**となり、アモーレパシフィックの済州3農場で**年間約700トン**を生産しています。ミュージアムの建物は**2001年に農園の中心部に開館**し、茶畑の中に立つミニマリストな緑の屋根のパビリオンデザインが評価され、**designboomのトップ10美術館**に選出されました。**入場無料**、毎日**09:00〜18:00**営業、**年間来場者数約200万人**。\n\n訪問は自然に三つのパートに分かれます：**(1) ミュージアム内部** — お茶の製造工程、唐代（618〜907年）以降のアンティーク茶器コレクション、農園全体を一望できる屋上展望台；**(2) ティーハウスカフェ** — その年の収穫茶葉から直接提供されるシグネチャーの**抹茶ロールケーキ（오설록 롤케이크）**と**抹茶アイスクリーム**；**(3) 農園散策路** — 茶の木の列の間を通る砂利道で、西端での夕暮れ撮影に人気。\n\nまた、**イニスフリー済州ハウス**（アモーレパシフィックのナチュラルコスメブランド）は**徒歩5分**の場所にあり、ブランドエコシステムに関心のある方も入場無料で楽しめます（みかん石鹸DIYワークショップはオプション、₩15,000）。ミュージアム建物自体は韓国の建築家**マス・スタディーズ（チョ・ミンスク）**が設計し、意図的に低く水平な形態をとることで、農業景観と競うのではなく茶の列の幾何学を反映しています——この建築的謙虚さが、designboomトップ10選出と韓国現代ミュージアムデザインのケーススタディとしての継続的な活用をもたらしています。\n\nオプション追加：**オソルロック・ティークラス（1人₩30,000・60分・事前予約必要）** — 韓国の陶器を用いた醸造技術デモンストレーション付きガイドティーフライトテイスティング、毎日**10:00〜16:00**開催、水・土曜セッションは英語指導あり。", "image": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "highlights": ["**アモーレパシフィック**旗艦 — 韓国最大の美容企業；創業者徐成煥が**1979年**に済州での茶栽培を開拓", "**西光茶苑（ソグァン・ダウォン）＝韓国最大の緑茶畑**；年間生産量約700トン", "ミュージアムは**2001年開館**――designboom 建築部門トップ10美術館に選出", "**入場無料**、毎日**09:00〜18:00**、年間来場者数約200万人", "**唐代（618〜907年）**から近代の韓国朝鮮時代陶磁器まで、時代を超えたアンティーク茶器コレクション", "**緑茶ロールケーキ**＋**緑茶アイスクリーム**＝カフェの定番メニュー", "**イニスフリー済州ハウス**は徒歩5分――入場無料、オプションでみかん石鹸DIY体験₩15,000", "茶畑の散策路は**ゴールデンアワー（16:00〜17:00）**が写真撮影に最適", "屋上デッキと地上レベルの畝が、二つの異なる高さから茶畑の構図を生み出す"], "timeUsed": ["駐車場〜入口――約5分", "ミュージアム内部＋茶器コレクション――約20分", "ティーハウスカフェ（ロールケーキ＋アイスクリーム）――約20分", "茶畑散策路――約20分", "オプション：イニスフリー済州ハウス見学――約10分"], "whyOnRoute": "**自然の名所から済州ライフスタイルへの文化的転換**。漢拏山・柱状節理・天帝淵が済州の地質的アイデンティティであるとすれば、オスルロックは済州の**現代的ブランドアイデンティティ**――火山灰＋年間降水量1,500mm＋韓国の園芸投資が、世界に輸出される茶産業を築けることの生きた証明です。**入場無料＋年間200万人来場者**＝済州南西部で最も気軽に立ち寄れる屋内アンカースポット；天帝淵の後に雨に変わっても完璧な屋内の代替地となります。西光高原の立地は**南海岸の観光スポットと北西部・愛月を結ぶ地理的要衝**でもあり、午後の中継地点として理想的です。**翰林公園（植物園、₩15,000、体験がやや分散）**や**カメリアヒル（₩9,000、季節限定）**と比較しても、オスルロックは**無料・通年営業・ブランド力**の点で優れ、このエリアで最もコストパフォーマンスの高い屋内スポットです。", "_poi_meta": {"poi_key": "osulloc_tea_museum", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Amorepacific corporate history (amorepacific.com)", "O''sulloc Tea Museum official site (osulloc.com)", "designboom Top 10 art museums archival listing", "Korea Tea Industry Association — production statistics", "VisitJeju — Osulloc Tea Museum"], "image": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "images": ["/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp"], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "オーソルロック・ティーミュージアム", "alt": "オーソルロック・ティーミュージアム — ギャラリー画像 1", "caption": "オーソルロック・ティーミュージアム — 写真 1"}, {"id": 2, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "オーソルロック・ティーミュージアム", "alt": "オーソルロック・ティーミュージアム — ギャラリー画像 2", "caption": "オーソルロック・ティーミュージアム — 写真 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "オーソルロック・ティーミュージアム", "alt": "オーソルロック・ティーミュージアム — ギャラリー画像 3", "caption": "オーソルロック・ティーミュージアム — 写真 3"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "オーソルロック・ティーミュージアム", "alt": "オーソルロック・ティーミュージアム — ギャラリー画像 4", "caption": "オーソルロック・ティーミュージアム — 写真 4"}], "imageCredits": [{"url": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "source": "atoc-korea"}]}, "visitBasics": {"hours": "通常09:00〜18:00、季節によって変動あり", "closed": "年中無休", "admission": "無料", "walking": "容易"}, "convenience": {"restroom": "ミュージアムおよびカフェエリア", "parking": "駐車場あり"}, "smartNotes": {"photo": "カフェ周辺の茶畑を広角で捉えたビューやサイドアングルは、製品撮影スタイルのクローズアップだけよりも写真映えすることが多い。", "facilities": "トイレ・飲み物・休憩スペースが揃っており、1日の後半で最も快適な立ち寄りスポットのひとつ。", "tip": "ミュージアムだけを急いで回るよりも、景色とカフェの雰囲気の両方をゆっくり楽しむ方が、満足度が高いことが多い。"}, "images": ["/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp"], "imageCredits": [{"url": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "オーソルロック・ティーミュージアム", "alt": "オーソルロック・ティーミュージアム — ギャラリー画像 1", "caption": "オーソルロック・ティーミュージアム — 写真 1"}, {"id": 2, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "オーソルロック・ティーミュージアム", "alt": "オーソルロック・ティーミュージアム — ギャラリー画像 2", "caption": "オーソルロック・ティーミュージアム — 写真 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "オーソルロック・ティーミュージアム", "alt": "オーソルロック・ティーミュージアム — ギャラリー画像 3", "caption": "オーソルロック・ティーミュージアム — 写真 3"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "オーソルロック・ティーミュージアム", "alt": "オーソルロック・ティーミュージアム — ギャラリー画像 4", "caption": "オーソルロック・ティーミュージアム — 写真 4"}]}, {"number": 6, "time": "16:15", "duration": "55分", "name": "愛月カフェ通り（翰潭海岸散策路）", "category": "海沿いカフェ通り — 午後のカフェ＋オルレ15A区間", "description": "**愛月カフェ通り（애월 카페거리）**は、済州北西海岸の**翰潭海岸散策路（한담해안산책로）**沿いに広がる**愛月邑の5km海岸ストリップ**で、翰潭ビーチと郭支ビーチの間の崖沿いに30店舗以上のデザイン性の高いカフェが密集する、韓国で最も集積度の高い**「海を望むカフェ」スポット**です。この遊歩道は正式には**장한철산책로（チャン・ハンチョル散策路）**と呼ばれ、1771年に太平洋を漂流した体験を綴った**『표해록（漂海録）』**の著者であり、済州生まれの朝鮮時代の学者**チャン・ハンチョル（장한철、1744年〜?）**にちなんで命名されました。\n\n同書は現存する最古級の韓国語による海難サバイバル記録のひとつです。この散策路は**済州オルレトレイル15A（翰林→곤내）の片道30分の海岸セグメント**で、黒い玄武岩の崖、潮だまり、大浦よりも小規模な柱状節理、そして遮るもののない西向きの水平線が広がり、済州随一の夕日鑑賞スポットとして知られます。**季節ごとに話題の主要カフェ**：**봄날カフェ（ポムナル・カフェ）**――**2014年の韓国ドラマ「星から来たあなた（별에서 온 그대）」**に登場し、一夜にして愛月をセレブ巡礼地にした；**ランディーズ・ドーナツ**（LAブランドの韓国フランチャイズ――広い屋上デッキ）；**カフェ・ノッテッド**（名物クリームドーナツ＋海景色）；**해지개カフェ（ヘジゲ・カフェ）**（直訳「夕日カフェ」、夕刻の光を専門とするサービス）；**애월 the sunset（エウォル・ザ・サンセット）**（屋上テラス、プレミアム価格）。\n\nトレイルとビーチへの**入場は無料**；カフェは飲み物＋デザートで₩6,000〜12,000が相場。**チャン・ハンチョルの『表海録（표해록）』**――この遊歩道の名の由来となった著作――は**韓国海洋文学の礎**のひとつとされており、**1770年12月**に済州へ向かう船が嵐で流され、29日間漂流した記録です。琉球（現・沖縄）の漁師に救助され、長崎経由で帰国した彼の記録は、類似した西洋のサバイバル回顧録より数十年先駆けており、現代の韓国海洋史研究にも影響を与えています。\n\n崖沿いの案内板にはこの著作の一節が韓国語と英語で引用されており、珍しい現地文学遺産マーカーとなっています。**写真愛好家へのメモ**：愛月海岸沿いのドローン使用は**済州国際空港から9kmの進入回廊外**では許可されています――飛行前にKorea Drone Mapアプリで正確な境界を確認してください。**オルレトレイル15Aセグメント**は翰林港→愛月→곤내港の13kmを走り；本日のツアーでは翰潭と郭支の間の中央1.5kmを歩きます。", "image": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "highlights": ["翰潭ビーチと郭支ビーチの間に広がる**5kmの海沿いカフェストリップ**――韓国で最も密集した海景色カフェ群", "**チャン・ハンチョル散策路**――済州生まれの朝鮮時代の学者（1744年〜?）、サバイバル記録**『漂海録（표해록）』**の著者にちなんで命名", "**オルレトレイル15A**セグメント（翰林→곤내）――片道30分の海岸ウォーク", "**ボムナル カフェ（봄날 카페）** = **『星から来たあなた』（2014年、SBS）**のロケ地", "人気カフェのローテーション：**ランディーズ・ドーナツ**、**カフェ・ノッテッド**、**ヘジガエ カフェ**、**エウォル・ザ・サンセット**", "**西向きの水平線** = 遮るもののない夕日鑑賞 — **春・秋は17:30〜18:30**", "**六角形の節理が観察可能** — 漢潭（ハンダム）の断崖上部にて — 大浦と同じ地質、規模は小さめ", "沿岸遊歩道＋ビーチは**無料**；カフェはドリンク＋デザートで約₩6,000〜12,000", "**済州国際空港からコーチで約40分** — 夕方のフライト前に立ち寄れる最後のスポット"], "timeUsed": ["コーチ到着＋漢潭駐車 — 約5分", "沿岸遊歩道ウォーク（漢潭→中間地点） — 約20分", "選択カフェ休憩（ドリンク＋デザート） — 約30分", "断崖上部での夕日撮影 — 約15分", "コーチへの帰路ウォーク — 約5分"], "whyOnRoute": "**夕日を軸としたフィナーレ**。南西ループが애월（エウォル）で終わるのは意図的な理由がある：(1) **西向きの水平線** = その日のルートで唯一、遮るものなく夕日を望める地点；(2) **済州空港までコーチで40分** = 引き返しなしで夕方のフライト前に立ち寄れる最後のスポット；(3) **カフェが密集した屋内代替案** = 天候が崩れても、ゲストはサイトを離れることなく沿岸ウォークから屋内カフェへ切り替え可能。姉妹ツアーである**城山日出峰（東海岸、夕日ではなく日の出アンカー）**で終わるハイライトループと比較すると、애월 = **ライフスタイルのフィナーレ**、城山 = **ユネスコのフィナーレ** — 異なる性格を持つ、互いを補完するルート。15:50の到着は**春・秋の夕日ウィンドウ17:30〜18:30**に合わせて設定されており、ゲストはコーチで済州市に戻る前に、遊歩道を歩き、カフェでくつろぎ、断崖デッキから夕日を撮影するための約75分を確保できる。", "_poi_meta": {"poi_key": "aewol_cafe_street", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Jeju Olle Foundation — Trail 15A official map (Hallim → Gonae)", "Aewol-eup Cultural Office — Jang Han Chul historical records", "VisitJeju — Aewol Cafe Street", "SBS Drama Archive — ''You Who Came From the Stars'' filming locations", "Joseon Wangjo Sillok / Korean Folklore Society — Pyohaerok textual study"]}, "visitBasics": {"hours": "エリア自体は終日開放；各カフェは独自の営業時間を設けている", "closed": "エリア全体としての定休日なし", "admission": "無料", "walking": "易しい"}, "convenience": {"restroom": "利用するカフェによって異なる", "parking": "エリア内に駐車場あり"}, "smartNotes": {"photo": "午後遅い時間の逆光と海向きのテラスが、ここでの最高の写真を生み出すことが多い。", "facilities": "快適さはどのカフェを選ぶかによって変わるため、一つの会場に固執しすぎるより柔軟な運営の方が効果的。", "tip": "ゲストにより自由なリズムを与えた場合、このスポットは厳格にガイドした場合より高評価を得ることが多い。"}, "images": ["/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp"], "imageCredits": [{"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "location": "愛月カフェ通り（翰潭海岸散策路）", "caption": "愛月カフェ通り（翰潭海岸散策路） — photo 1", "alt": "愛月カフェ通り（翰潭海岸散策路） — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "location": "愛月カフェ通り（翰潭海岸散策路）", "caption": "愛月カフェ通り（翰潭海岸散策路） — photo 2", "alt": "愛月カフェ通り（翰潭海岸散策路） — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "location": "愛月カフェ通り（翰潭海岸散策路）", "caption": "愛月カフェ通り（翰潭海岸散策路） — photo 3", "alt": "愛月カフェ通り（翰潭海岸散策路） — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "location": "愛月カフェ通り（翰潭海岸散策路）", "caption": "愛月カフェ通り（翰潭海岸散策路） — photo 4", "alt": "愛月カフェ通り（翰潭海岸散策路） — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp", "location": "愛月カフェ通り（翰潭海岸散策路）", "caption": "愛月カフェ通り（翰潭海岸散策路） — photo 5", "alt": "愛月カフェ通り（翰潭海岸散策路） — gallery image 5"}]}, {"number": 7, "time": "17:30", "duration": "45分", "name": "梨湖テウ海水浴場（馬の灯台・夕日）", "category": "済州市の海水浴場 — チョランマルの灯台＋夕日のフィナーレ", "description": "**梨湖テウ海水浴場（梨湖テウ海水浴場、梨湖海水浴場）**は、済州市内・済州国際空港から最も近い海水浴場で、一日を締めくくる**夕日のフィナーレ**の区間です。最も象徴的な見どころは、防波堤の上で向かい合って立つ**チョランマル（済州の馬）の灯台（馬の灯台）**2基で、済州のチョランマルをかたどった**高さ約12mの赤い馬の灯台と白い馬の灯台**がそれぞれ外側・内側の防波堤に立っています — 白と赤は船が航路の左右を見分けられるよう塗られた航海標識で、青い海・空と調和し、済州屈指の絶景写真スポットになっています。 \n\n砂浜は貝殻と砂が混じった**銀色がかったきめ細かい砂**でできており、傾斜が緩やかなため家族連れの海水浴客が多く訪れます。海岸の背後には**松林**があり日陰と散策路を提供し、最も潮が引く干潮時には広い砂浜とともに**ウォンダム**の姿を見ることができます — ウォンダムは満潮と干潮の差を利用して魚を閉じ込めて獲った済州の伝統的な漁法（石干見）で、梨湖テウにはこれを復元した**イホ・モサルウォン**が残っています。 \n\n海岸のすぐ隣には**トドゥ洞レインボー海岸道路**が続き、色とりどりの消波ブロックと海岸ドライブを楽しむことができ、空港に近いため**夕方の飛行機に搭乗する前に最後に立ち寄るのに最適な立地**です。海岸と散策路への**入場は無料**です。", "image": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "highlights": ["済州市内・**空港から最も近い海水浴場** — 夕日のフィナーレ＋空港への移動が便利", "象徴的な**チョランマルの灯台（馬の灯台）** — 赤・白の2基、高さ約12m、代表的なフォトスポット", "貝殻が混じった**銀色のきめ細かい砂**＋緩やかな傾斜 — 家族向けの海岸", "海岸背後の**松林**の日陰・散策路", "干潮時に現れる済州の伝統的な漁労施設**ウォンダム（イホ・モサルウォン）**", "すぐ隣の**トドゥ洞レインボー海岸道路**での海岸ドライブ", "**入場無料** — 夕日の時間帯の黄金色の光"], "timeUsed": ["海岸での駐車＋移動 — 約5分", "チョランマルの灯台・防波堤の散策＋写真 — 約20分", "砂浜・レインボー海岸道路で夕日鑑賞 — 約15分", "再集合 — 約5分"], "whyOnRoute": "**一日の夕日のフィナーレであり最後の訪問地**。愛月でカフェと海岸を楽しんだあと、済州市方面へ戻る道沿いにあるので動線が自然で、西へ開けた水平線とチョランマルの灯台が調和して一日を黄金色に締めくくります。済州国際空港に近いため**ドロップオフや夕方の飛行機に搭乗する前の最後のコース**として適しています — 夕日の時刻は季節によって変わるため（夏は遅く、冬は早く）、到着時間をその日の夕日に合わせて調整します。", "_poi_meta": {"poi_key": "iho_tewoo_beach", "kb_version": "raw-2026", "verified_date": "2026-06-23", "sources": ["VisitKorea — Iho Tewoo Beach (이호테우해변)", "VisitKorea — Iho Tewoo Horse Lighthouses (이호테우 말 등대)", "Jeju Tourism Organization", "Jeju City official tourism data"]}, "visitBasics": {"hours": "海岸・散策路は24時間開放（無料）；夕日の時間帯に訪問", "closed": "通年開放", "admission": "無料（入場料・駐車料なし）", "walking": "易しい — 平坦な砂浜と防波堤の散策、約15〜20分"}, "convenience": {"restroom": "海水浴場の公衆トイレ", "parking": "無料駐車場（繁忙期の週末は混雑）"}, "smartNotes": {"photo": "赤・白のチョランマルの灯台を防波堤の先端から収めると最も印象的で、夕日の時刻の逆光シルエットとレインボー海岸道路が人気の構図です。", "facilities": "海岸周辺にカフェ・食堂・利便施設がよく整っています。", "tip": "夕日の時刻は季節ごとに異なるので（夏は約19:30、春・秋は約18:30、冬は約17:40）、到着時間をその日の夕日に合わせます。空港が近いので夕方の飛行機前の最後のコースとして最適です。"}, "images": ["/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp"], "imageCredits": [{"url": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "source": "atoc-korea"}, {"url": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "location": "梨湖テウ海水浴場", "caption": "梨湖テウ海水浴場 — photo 1", "alt": "梨湖テウ海水浴場 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp", "location": "梨湖テウ海水浴場", "caption": "梨湖テウ海水浴場 — photo 2", "alt": "梨湖テウ海水浴場 — gallery image 2"}]}], "routeFlowStops": [{"name": "1100高地", "theme": "漢拏山", "type": "01"}, {"name": "柱状節理", "theme": "海岸", "type": "02"}, {"name": "天帝淵", "theme": "滝", "type": "03"}, {"name": "昼食", "theme": "リセット", "type": "04"}, {"name": "オソルロク", "theme": "茶畑", "type": "05"}, {"name": "愛月", "theme": "カフェ", "type": "06"}, {"name": "梨湖テウ", "theme": "夕日", "type": "07"}], "routePhases": [{"phase": "오전", "duration": "1-3", "description": ""}, {"phase": "정오~오후 초반", "duration": "4-5", "description": ""}, {"phase": "마무리", "duration": "6-7", "description": ""}], "routeShapeIntro": {"title": "このコースの流れ", "subtitle": "漢拏山1100高地のラムサール湿地から始まり、火山性海岸と滝、昼食、茶畑を経て、愛月カフェ通りと梨湖テウの夕日で締めくくるコースです。おおよそ09:30〜18:15。"}, "whyTourWorks": {"bestFor": ["済州島初訪問の旅行者とカップル", "大人が中心の家族旅行", "自然、お茶畑、穏やかなフィニッシュを求める旅行者", "アクティブな中高年の旅行者"], "lessIdealFor": ["短い階段や上り坂さえも避けたい旅行者", "ベビーカーへの依存度が高いグループ", "幼児を中心に組まれた旅程"], "routeLogicSections": [{"title": "ペースと構成", "icon": "sun", "iconBg": "bg-amber-50/80", "items": [{"label": "気軽に始める漢拏山の高地", "detail": "1100高地湿地は平坦なデッキ散策なので体力的な負担なく始められ、漢拏山高地の雰囲気を感じられ、コースが自然に南の海岸へとつながります。"}, {"label": "昼食は最適な位置に設定", "detail": "昼食は、開放的でダイナミックな午前のスポットと、その後に続く落ち着いた滝・お茶畑セクションの間で、一日をリセットする役割を果たす。"}, {"label": "オソルロク後の軽やかなフィナーレ", "detail": "茶畑が雰囲気をやわらげてくれると、愛月がコーヒーと海の眺めで午後を開き、最後の梨湖テウの夕日が一日を黄金色に締めくくります。"}]}, {"title": "ルートの設計について", "icon": "mountain", "iconBg": "bg-sky-50/80", "items": [{"label": "山が先、海が後", "detail": "このコースはまず漢拏山1100高地で高度感と高山湿地を体験したあと、柱状節理で海岸へと爽快に視界が開けるよう設計されています。"}, {"label": "茶畑の前の滝", "detail": "チョンジェヨン（天帝淵）は、オソルロックがより軽やかで穏やかな雰囲気で後半を始める前に、ルートの流れを落ち着かせる役割を担います。"}, {"label": "夕日で締める海岸のフィナーレ", "detail": "愛月でカフェと海岸を楽しんだあと梨湖テウのチョランマルの灯台で夕日を迎え、また一つの詰め込んだ観光コースではなく、ライフスタイル志向のフィナーレで一日を締めくくります。"}]}, {"title": "状況が変わる場合", "icon": "wind", "iconBg": "bg-slate-50/80", "items": [{"label": "漢拏山の道路の変動要因", "detail": "1100高地は大雪・大雨・凍結時に1100道路が通行止めになる場合があり、その際は国立済州博物館などの屋内代替名所に調整されます。"}, {"label": "海岸の風", "detail": "チュサンジョルリ（柱状節理）とエウォル（愛月）は、内陸のスポットと比べて風の影響を直接受けやすい場所です。"}, {"label": "全体的にバランスの取れた歩行の負担", "detail": "1100高地と梨湖テウは平坦ですが、天帝淵は階段と短い上り坂の区間があるため注意が必要です。"}]}]}, "practicalAccordionItems": [{"id": "pickup", "title": "お迎えと帰着", "preview": "済州市エリアのホテルロビーへのお迎え", "content": ["午前8時20分から8時50分の間にホテルのロビーへピックアップにうかがいます。", "帰着は梨湖テウの夕日のあと、午後6時30分から7時の間を予定しています。", "ご要望に応じて空港でのピックアップ／ドロップオフが可能な場合があります。", "正確なピックアップ時間は前夜に確定します。"]}, {"id": "walking", "title": "歩行と地形", "preview": "全体的に中程度の難易度で、ほとんどのお客様が無理なく歩けます", "content": ["1日の総歩行距離は通常3.5〜4.5km程度です。", "1100高地：約1kmの平坦なデッキ遊歩道（約20分）で最も歩きやすいです。", "柱状節理：歩きやすい海岸の遊歩道です。", "天帝淵：森の道、階段、そして時折滑りやすい区間があります。", "オソルロク・愛月・梨湖テウ：ゆったりと休みながら過ごせる快適なコースです。", "滑り止め性能の良いウォーキングシューズを推奨します。"]}, {"id": "weather", "title": "天候および施設クローズに伴う変更について", "preview": "ツアーは基本的に実施されますが、必要に応じて変更する場合があります", "content": ["小雨：ツアーは通常予定どおり進行します。", "大雪・大雨・凍結で1100道路が通行止めの場合：1100高地が屋内代替名所（例：国立済州博物館）に調整される場合があります。", "強風時：柱状節理、愛月または梨湖テウの滞在時間が短縮される場合があります。", "午後に天候が悪化した場合：オソルロクでの午後の時間の比重が増える場合があります。", "特定の訪問地が休業の場合：代替の訪問地を利用する場合があります。"]}, {"id": "wear", "title": "服装と持ち物", "preview": "歩きやすい靴、重ね着、軽いジャケット", "content": ["グリップ力のある靴", "山岳部と沿岸部の気温差に対応した重ね着", "軽いウィンドブレーカー", "帽子と日焼け止め", "ウォーターボトル"]}, {"id": "included", "title": "含まれるもの／含まれないもの", "preview": "ガイド、車両、送迎、入場料込み", "variant": "含まれるもの", "content": ["英語対応ガイド", "少人数制の車両", "済州市エリアのホテルへの送迎", "すべての入場券", "ミネラルウォーター", "昼食（現地払い）", "個人的な買い物の費用", "ガイドへのチップ"]}], "practicalWeatherStatic": {"today": {"temp": "—", "label": "リアルタイム天気連携"}, "tomorrow": {"temp": "—", "label": "毎日更新"}, "_seasonalSummary": "Southwest Jeju has the most varied terrain on the island — from Hallasan''s 1100 Highland Ramsar wetland to Iho Tewoo''s city beach. The 1100m highland runs 7-10°C cooler than the coast; bring a layer year-round.", "_seasonalTemperatures": [{"season": "Spring (Mar–May)", "range": "6–20°C inland / 10–22°C coast", "notes": "Cherry blossoms; new tea leaves at Osulloc."}, {"season": "Summer (Jun–Aug)", "range": "18–25°C inland / 22–30°C coast", "notes": "1100 Highland stays cool; Iho Tewoo lively at sunset."}, {"season": "Autumn (Sep–Nov)", "range": "8–22°C inland / 12–24°C coast", "notes": "Best season — golden tea fields, clear Hallasan views."}, {"season": "Winter (Dec–Feb)", "range": "-2–7°C inland / 3–10°C coast", "notes": "1100 Highland often snowy — striking, but Road 1100 may close; warm layers required."}]}, "seasonalVariations": [{"season": "春", "description": "菜の花が咲き、海岸沿いの一部に黄色の彩りを添える季節。"}, {"season": "夏", "description": "日が長く、ルート沿いの緑が特に深く鮮やかに感じられます。"}, {"season": "秋", "description": "晴れた空は、ルートの山・海岸・茶畑の重なりをひときわ鮮明に感じさせてくれることが多い。"}, {"season": "冬", "description": "日照時間が短く、全体的に落ち着いた雰囲気で、ルートはより静かに感じられることが多い。"}], "bookingTrustItems": [{"icon": "check-circle", "title": "地元公認の運営", "description": "済州島で合法的に運営されているガイドサービス", "iconBg": "bg-emerald-50/80"}, {"icon": "route", "title": "済州島南西部を中心に構成", "description": "南西ルートに特化して設計", "iconBg": "bg-sky-50/80"}, {"icon": "users", "title": "少人数グループで運営", "description": "最大8名まで", "iconBg": "bg-amber-50/80"}], "bookingSupportSteps": [{"timing": "予約直後", "title": "即時確認", "detail": "当日の概要をまとめた予約確認書が届きます。"}, {"timing": "12時間前", "title": "12時間前リマインダー", "detail": "天気情報とルートの変更点が事前に共有されます。"}, {"timing": "前日夜", "title": "最終送迎案内", "detail": "正確なお迎え時間とドライバーの連絡先が共有されます。"}, {"timing": "ツアー当日の朝", "title": "当日のルート案内", "detail": "現地のリアルタイムの状況に基づいた、簡単な朝のブリーフィングが行われます。"}, {"timing": "ツアー中", "title": "リアルタイムの各スポットガイダンス", "detail": "各スポットで必要な情報が提供されます。"}, {"timing": "ツアー終了後", "title": "ツアー後のサポート", "detail": "ツアー終了後も、追加のガイダンスやおすすめ情報を共有できます。"}], "staticQuestions": [{"id": "first-time", "question": "済州島を初めて訪れる旅行者に良い選択ですか？", "answer": "はい。漢拏山1100高地の景色、火山性海岸線、滝の散策、茶畑の雰囲気、そして愛月と梨湖テウの夕日のフィナーレまで、バランスの取れた1日の行程を体験できます。"}, {"id": "walking", "question": "歩行の難易度は高いですか？", "answer": "いいえ。天帝淵が階段があって最もアクティブな区間ですが、1100高地は平坦なデッキ散策で、残りの行程も全体的に無理なくこなせます。"}, {"id": "rain", "question": "雨の日でもツアーは催行されますか？", "answer": "はい。雨でもコースを進めることができ、大雪・大雨で1100道路が通行止めになると、1100高地が屋内代替名所に変わったり、露出の多い海岸区間が短縮されたりする場合があります。"}, {"id": "parents", "question": "親や年配の家族との旅行に適していますか？", "answer": "多くの場合、適しています。特に全員が階段や短い上り坂に問題がない場合、大人の家族旅行に最適です。"}, {"id": "children", "question": "子ども連れで参加できますか？", "answer": "はい。特に8歳前後以上の、短い散策や終日ツアーのペースについていける子どもに特に適しています。"}, {"id": "order", "question": "現地の状況によって訪問の順序が変わることはありますか？", "answer": "はい。山の天候、海岸の風、交通状況、夕日の時刻、来訪者の流れなどによって、特に1100高地と海岸区間の周辺で小幅な順序変更がある場合があります。"}, {"id": "lunch", "question": "昼食は含まれていますか？", "answer": "それはプランの条件によります。ルートには昼食の時間が組み込まれていますが、食事自体が含まれるかどうかはご予約のプランに従います。"}, {"id": "why-1100goji", "question": "コースが1100高地から始まる理由は何ですか？", "answer": "重い登山の行程にすることなく、最もエネルギーにあふれる時間に平坦なデッキ散策で漢拏山の高地を気軽に体験しながら一日を開くためです。"}, {"id": "why-jusangjeolli", "question": "なぜ漢拏山の後にチュサンジョルリへ行くのですか？", "answer": "済州島の火山の物語が、山岳地形から壮大な玄武岩の海岸線へと自然に展開されるからです。"}, {"id": "why-osulloc", "question": "オソルロクが愛月より先である理由は何ですか？", "answer": "滝の区間のあと雰囲気をやわらかく切り替えてくれることで、後半のコースである愛月と梨湖テウの夕日がより一層ゆったりと快適に感じられるようにするためです。"}, {"id": "later-structure", "question": "後半がこのような構成になっている理由は何ですか？", "answer": "昼食と天帝淵が活気のある午前の区間のあとリズムを落ち着かせ、オソルロクは気軽に茶畑を楽しむ休息を加え、愛月と梨湖テウの夕日が一日を自然に余韻のある形で締めくくるためです。"}], "guestReviews": [], "reviewsSummary": {"averageRating": 0, "totalReviews": 0, "ratingDistribution": [{"stars": 5, "count": 0, "percentage": 0}, {"stars": 4, "count": 0, "percentage": 0}, {"stars": 3, "count": 0, "percentage": 0}, {"stars": 2, "count": 0, "percentage": 0}, {"stars": 1, "count": 0, "percentage": 0}], "highlights": []}, "sticky_booking_bar": {"note": "checkout_tour_idはSupabase／環境変数から実行時に解決されます。静的JSONBの一部ではありません。", "price": {"amountLabel": "52", "originalPriceUsd": null, "salePriceUsd": 52, "discountPercent": null, "currency": "USD", "per": "person"}}, "matching_profile": {"product_type": "small_group", "route_type": "fixed_route", "region_type": "jeju_southwest", "region_tags": ["jeju_southwest", "jeju_aewol", "jeju_hallasan", "jeju_city"], "theme_tags": ["nature", "cafe", "tea_culture", "first_time_friendly", "beach", "sunset"], "poi_tags": ["hallasan_1100_wetland", "osulloc_tea_museum", "iho_tewoo_beach", "cheonjeyeon_falls", "aewol_cafe_street"], "pace_level": 0.6, "walking_level": 0.55, "scenic_level": 1, "photo_level": 1, "cultur