": "mountain", "label": "風景優美", "value": "良好", "level": 4}, {"icon": "footprints", "label": "步行", "value": "適中", "level": 3}, {"icon": "cloud-rain", "label": "雨天安全性", "value": "適中", "level": 3}, {"icon": "users", "label": "適合家庭", "value": "良好", "level": 4}, {"icon": "gauge", "label": "均衡度", "value": "均衡", "level": 4}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "漢拿山1100高地", "alt": "漢拿山1100高地 — gallery image 1", "caption": "漢拿山1100高地 — photo 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "location": "大浦柱狀節理海岸", "alt": "大浦柱狀節理海岸 — gallery image 1", "caption": "大浦柱狀節理海岸 — photo 1"}, {"id": 3, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "location": "天帝淵瀑布", "alt": "天帝淵瀑布 — gallery image 1", "caption": "天帝淵瀑布 — photo 1"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "雪綠茶博物館", "alt": "雪綠茶博物館 — 圖庫圖片 1", "caption": "雪綠茶博物館 — 照片 1"}, {"id": 5, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "location": "涯月咖啡街（翰潭海岸步道）", "alt": "涯月咖啡街（翰潭海岸步道） — gallery image 1", "caption": "涯月咖啡街（翰潭海岸步道） — photo 1"}, {"id": 6, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "漢拿山1100高地", "alt": "漢拿山1100高地 — gallery image 2", "caption": "漢拿山1100高地 — photo 2"}, {"id": 7, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "漢拿山1100高地", "alt": "漢拿山1100高地 — gallery image 3", "caption": "漢拿山1100高地 — photo 3"}, {"id": 8, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "location": "大浦柱狀節理海岸", "alt": "大浦柱狀節理海岸 — gallery image 2", "caption": "大浦柱狀節理海岸 — photo 2"}, {"id": 9, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "location": "大浦柱狀節理海岸", "alt": "大浦柱狀節理海岸 — gallery image 3", "caption": "大浦柱狀節理海岸 — photo 3"}, {"id": 10, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "location": "大浦柱狀節理海岸", "alt": "大浦柱狀節理海岸 — gallery image 4", "caption": "大浦柱狀節理海岸 — photo 4"}, {"id": 11, "type": "photo", "src": "/images/tours/jusangjeolli/photo-005.webp", "location": "大浦柱狀節理海岸", "alt": "大浦柱狀節理海岸 — gallery image 5", "caption": "大浦柱狀節理海岸 — photo 5"}, {"id": 12, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "location": "天帝淵瀑布", "alt": "天帝淵瀑布 — gallery image 2", "caption": "天帝淵瀑布 — photo 2"}, {"id": 13, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "location": "天帝淵瀑布", "alt": "天帝淵瀑布 — gallery image 3", "caption": "天帝淵瀑布 — photo 3"}, {"id": 14, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/photo-004.webp", "location": "天帝淵瀑布", "alt": "天帝淵瀑布 — gallery image 4", "caption": "天帝淵瀑布 — photo 4"}, {"id": 15, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "雪綠茶博物館", "alt": "雪綠茶博物館 — 圖庫圖片 2", "caption": "雪綠茶博物館 — 照片 2"}, {"id": 16, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "雪綠茶博物館", "alt": "雪綠茶博物館 — 圖庫圖片 3", "caption": "雪綠茶博物館 — 照片 3"}, {"id": 17, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "雪綠茶博物館", "alt": "雪綠茶博物館 — 圖庫圖片 4", "caption": "雪綠茶博物館 — 照片 4"}, {"id": 18, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "location": "涯月咖啡街（翰潭海岸步道）", "alt": "涯月咖啡街（翰潭海岸步道） — gallery image 2", "caption": "涯月咖啡街（翰潭海岸步道） — photo 2"}, {"id": 19, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "location": "涯月咖啡街（翰潭海岸步道）", "alt": "涯月咖啡街（翰潭海岸步道） — gallery image 3", "caption": "涯月咖啡街（翰潭海岸步道） — photo 3"}, {"id": 20, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "location": "涯月咖啡街（翰潭海岸步道）", "alt": "涯月咖啡街（翰潭海岸步道） — gallery image 4", "caption": "涯月咖啡街（翰潭海岸步道） — photo 4"}, {"id": 21, "type": "photo", "src": "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp", "location": "涯月咖啡街（翰潭海岸步道）", "alt": "涯月咖啡街（翰潭海岸步道） — gallery image 5", "caption": "涯月咖啡街（翰潭海岸步道） — photo 5"}, {"id": 22, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "location": "梨湖泰烏海灘", "caption": "梨湖泰烏海灘 — photo 1", "alt": "梨湖泰烏海灘 — gallery image 1"}, {"id": 23, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp", "location": "梨湖泰烏海灘", "caption": "梨湖泰烏海灘 — photo 2", "alt": "梨湖泰烏海灘 — gallery image 2"}], "itineraryStops": [{"number": 1, "time": "09:30", "duration": "45分鐘", "name": "漢拿山1100高地", "category": "高山拉姆薩濕地棧道 — UNESCO漢拿山初體驗", "description": "**漢拿山1100高地濕地（한라산 1100고지 습지）**是位於漢拿山西側山坡海拔**1,100公尺**的高山濕地，於**2009年10月12日登錄為拉姆薩公約國際重要濕地（第1893號）**。面積約**13公頃**，位於漢拿山**UNESCO世界自然遺產暨生物圈保護區**的範圍之內 — 也就是說，無需登上白鹿潭頂峰，即可輕鬆體驗漢拿山的UNESCO價值。 \n\n濕地由散布於高原各處的**16處以上淡水濕地與水潭**組成，沿著**約1公里的平坦木棧步道（約20分鐘）**即可繞行一圈。棧道幾乎沒有坡度，嬰兒車或行動不便者也能較為輕鬆地走訪。這裡棲息著3種瀕危鳥類與1種瀕危植物（國家指定），以及濟州特有的哺乳類、爬蟲類與昆蟲，棧道沿途的解說牌會介紹濕地生態。 \n\n通往濕地的**1100公路（1100도로，1973年通車，全長36.6公里）**是**韓國海拔最高的國道**，南北串聯濟州市與西歸浦中文。馬路對面的**1100高地休息站**設有便利商店（GS25）、供應熱飲與泡麵的咖啡廳、觀景台，以及**白鹿（白鹿）銅像**（傳說神仙騎著白鹿登上漢拿山的濟州傳說）與**紀念韓國首位聖母峰登頂者高相敦的公園**，適合休息10~15分鐘。 \n\n海拔1,100公尺處的氣溫比海岸**低7～10℃**，即使盛夏也需要一件薄外套。冬天積雪的棧道與結冰的濕地是濟州數一數二的雪景拍攝地，但**1100公路也是遇大雪、暴雨、結冰時最先封閉的道路** — 此時行程會改以濟州市區的室內景點（如國立濟州博物館）替代。 \n\n入場與停車皆**免費**，無需另行預約。", "image": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "highlights": ["**拉姆薩國際重要濕地第1893號**（2009年登錄）— 位於漢拿山UNESCO世界遺產＋生物圈保護區範圍內", "海拔**1,100公尺高山濕地** — 16處以上淡水濕地與水潭分布於高原", "**約1公里平坦木棧道**（約20分鐘）— 嬰兒車與行動不便者也較為輕鬆", "**1100公路** — 1973年通車，36.6公里，韓國海拔最高的國道", "棲息3種瀕危鳥類＋1種瀕危植物等**濟州特有生態**", "馬路對面**1100高地休息站** — 白鹿銅像、高相敦公園、便利商店與咖啡廳、觀景台", "氣溫比海岸**低7～10℃** — 即使盛夏也建議帶外套", "冬季**雪景名所**（惟大雪時1100公路封閉 → 改以室內替代）", "**免費入場＋免費停車**，無需預約"], "timeUsed": ["1100高地休息站停車＋洗手間 — 約5分鐘", "棧道濕地步道繞行一圈 — 約20分鐘", "觀景台＋白鹿銅像拍照 — 約10分鐘", "休息站休息／飲品 — 約10分鐘"], "whyOnRoute": "**西南環線的起點**。從濟州市沿1100公路上行至高地，輕鬆感受漢拿山的規模與高山生態後，再下行至南邊的中文海岸，接續柱狀節理與天帝淵。與登頂或陡峭上坡步道不同，這是**平坦的棧道散步**，幾乎沒有體力負擔，又能免預約、免費同時體驗**拉姆薩濕地＋UNESCO漢拿山**。由山上開始、向海岸下行的流程使移動動線自然，加上時間較早，1100公路相對清靜 — 冬季道路封閉時則改以室內景點替代。", "_poi_meta": {"poi_key": "hallasan_1100_wetland", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Ramsar Sites Information Service — Site #1893 (Hallasan 1100 Altitude Wetland)", "Hallasan National Park official site (hallasan.go.kr)", "UNESCO WHC inscription 1264 (Jeju Volcanic Island and Lava Tubes, 2007)", "VisitKorea — 1100 Altitude Wetland (1100-goji)", "Jeju Special Self-Governing Province — Wetland Protected Area records"]}, "visitBasics": {"hours": "濕地棧道24小時開放（免費）；1100高地休息站咖啡廳與商店約09:00–17:00", "closed": "全年開放，惟大雪、暴雨時1100公路可能封閉 — 冬季前往前請確認路況", "admission": "免費（拉姆薩濕地，無入場費與停車費）", "walking": "非常輕鬆 — 約1公里平坦木棧道繞行一圈，15～20分鐘；嬰兒車等大多數步行程度皆可"}, "convenience": {"restroom": "馬路對面的1100高地休息站設有洗手間", "parking": "休息站免費停車（下雪的週末可能擁擠）"}, "smartNotes": {"photo": "橫越淡水潭的木棧道與遠處的漢拿山是代表性構圖，冬季雪景更是濟州拍攝最多的場景之一。休息站的白鹿銅像也是熱門拍照點。", "facilities": "馬路對面的1100高地休息站集中了便利商店、咖啡廳、觀景台與洗手間。", "tip": "即使盛夏，1,100公尺高地也比海岸低7～10℃，請帶一件薄外套。冬季1100公路最先封閉，請確認路況，封閉時改以室內景點替代。"}, "images": ["/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp"], "imageCredits": [{"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "漢拿山1100高地", "caption": "漢拿山1100高地 — photo 1", "alt": "漢拿山1100高地 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "漢拿山1100高地", "caption": "漢拿山1100高地 — photo 2", "alt": "漢拿山1100高地 — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "漢拿山1100高地", "caption": "漢拿山1100高地 — photo 3", "alt": "漢拿山1100高地 — gallery image 3"}]}, {"number": 2, "time": "11:00", "duration": "45分鐘", "name": "大浦柱狀節理海岸", "category": "火山海岸線——六角柱狀節理熔岩", "description": "**大浦柱狀節理（대포 주상절리，「Jisatgae」）**是位於中文海岸的**1公里長六角柱狀節理玄武岩懸崖**——於**2005年1月6日被指定為天然紀念物第443號**。岩柱從海面聳立**30至40公尺**，緊密排列呈**5至7邊形多邊形**（多為六邊形）——此幾何形態由**漢拿山側翼噴發的玄武岩熔岩（約25萬至14萬年前）流入海洋後冷卻收縮、垂直冷卻面斷裂**所形成。\n\n全球最著名的柱狀節理地形包括**巨人堤道（英國）**、**魔鬼柱群（美國）**及**芬加爾洞（蘇格蘭）**——柱狀節理是**東亞首屈一指的代表景點**，亦是最易到訪之處。全長800公尺的**木棧道環線**將遊客引至緊鄰岩柱頂部的有欄杆崖邊；**大潮日海浪拍打岩柱，浪花最高可達20公尺**，偶爾越過護欄。門票：**成人₩2,000 / 青少年₩1,000 / 7歲以下及65歲以上免費**。\n\n此景點隸屬**濟州世界地質公園（聯合國教科文組織2010年10月認定）**，是島上**13處官方地質景點**之一，與城山日出峰、萬丈窟熔岩管及水月峰並列。崖頂步道為**無障礙設施**（輪椅／嬰兒車可通行）。環線設有三處觀景台，提供不同角度欣賞岩柱：**第一觀景台**從側面觀賞岩柱（最適合拍攝六邊形幾何構圖）；**中間觀景台**可從正上方俯瞰柱頂圖案；**遠端觀景台**則可將1公里海岸全景盡收眼底，晴天時漢拿山作為遠景背景。\n\n**最佳攝影時段：14:00至16:00**，此時西斜陽光正面照亮柱面；日落時分可拍攝剪影構圖，但會損失岩柱細節質感。開放時間：**09:00–18:00（最後入場17:30）**，全年運營。", "image": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "highlights": ["**天然紀念物第443號**——指定於**2005年1月6日**，為濟州最新指定的海岸天然紀念物", "岩柱高達**30至40公尺**，沿**1公里**海岸線排列，呈**5至7邊形多邊形**（多為六邊形）", "成因：**漢拿山側翼熔岩約於25萬至14萬年前流入海洋冷卻**，垂直冷卻面收縮斷裂", "**東亞首屈一指的柱狀節理景點**——與巨人堤道（英國）、魔鬼柱群（美國）、芬加爾洞（蘇格蘭）齊名", "**大潮日浪花可高達20公尺**——浪花噴泉攝影絕佳時機", "**0.8公里木棧道環線**，步行約15分鐘——無障礙設施，輪椅／嬰兒車可通行", "隸屬**濟州世界地質公園（聯合國教科文組織2010年10月認定）**——島內共13處地質景點", "門票：**成人₩2,000 / 青少年₩1,000 / 7歲以下及65歲以上免費**", "晴天時可向北望見漢拿山山頂，地質上**直接位於其下游**"], "timeUsed": ["停車、購票及入場——約5分鐘", "步行至第一觀景台——約5分鐘", "崖邊柱狀節理觀賞與拍照——約15分鐘", "繼續沿木棧道環線步行——約10分鐘", "返回遊覽車——約10分鐘"], "whyOnRoute": "**西南環線的地質核心**——在地理和地質上均位於漢拿山的正下游。繼漢拿山火山源頭之後，柱狀節理展示了**同一熔岩流入海洋後凝固成30至40公尺高六邊形岩柱**，沿1公里海岸線延伸。從此處，行程繼續**向西3公里前往天帝淵瀑布**（相較之下，姊妹行程則向東前往正房瀑布）——使整個下午行程完全在西南部中文＋安德走廊內進行。與**龍頭海岸（約30%的參觀日因潮汐／天氣關係無法入場）**及**松岳山（步行距離多1.6公里）**相比，大浦**全天候開放、無障礙設施、步行僅需15分鐘**——是南海岸單位時間收益最高的景點。上午晚些時候抵達，亦可趕在中午郵輪岸上觀光人潮湧入之前。", "_poi_meta": {"poi_key": "daepo_jusangjeolli_cliff", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Cultural Heritage Administration — Natural Monument No. 443 designation (2005-01-06)", "Jeju Global Geopark official site (geopark.jeju.go.kr)", "UNESCO Global Geoparks Network — Jeju (2010 designation)", "VisitJeju — Daepo Jusangjeolli", "Korea Geological Survey — Jeju basalt formation studies"]}, "visitBasics": {"hours": "09:00–18:00（最後入場17:40）", "closed": "全年開放", "admission": "成人2,000韓元 / 兒童及青少年1,000韓元", "walking": "輕鬆"}, "convenience": {"restroom": "入口區域", "parking": "收費停車場"}, "smartNotes": {"photo": "稍微側角通常比正面拍攝更能捕捉玄武岩的紋理與海浪的動感。", "facilities": "設施簡單，但入口區域實用且足夠。", "tip": "由於風與海霧可能迅速改變景點的氛圍，保持穩定的節奏效果最佳。"}, "images": ["/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "/images/tours/jusangjeolli/photo-005.webp"], "imageCredits": [{"url": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/photo-005.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "location": "大浦柱狀節理海岸", "caption": "大浦柱狀節理海岸 — photo 1", "alt": "大浦柱狀節理海岸 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "location": "大浦柱狀節理海岸", "caption": "大浦柱狀節理海岸 — photo 2", "alt": "大浦柱狀節理海岸 — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "location": "大浦柱狀節理海岸", "caption": "大浦柱狀節理海岸 — photo 3", "alt": "大浦柱狀節理海岸 — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "location": "大浦柱狀節理海岸", "caption": "大浦柱狀節理海岸 — photo 4", "alt": "大浦柱狀節理海岸 — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/jusangjeolli/photo-005.webp", "location": "大浦柱狀節理海岸", "caption": "大浦柱狀節理海岸 — photo 5", "alt": "大浦柱狀節理海岸 — gallery image 5"}]}, {"number": 3, "time": "12:00", "duration": "70分鐘", "name": "天帝淵瀑布", "category": "三層瀑布＋森林 — 「天帝之淵」", "description": "**天帝淵瀑布（천제연，''연 = 潭 + 천제 = 天帝''）** 是位於中文洞火山峽谷中的**三段式瀑布**，因其罕見的生態組合，於1993年被指定為**天然紀念物第378號**。其名稱源於**朝鮮時代的道教傳說——七位仙女（선녀，*seonnyeo*）每夜從天而降，在上層水潭沐浴**——這一神話因此地長年瀰漫薄霧的微氣候而更顯真實。**第一段（瀑高22公尺，潭深21公尺）**落入圓形玄武岩水潭，僅在大雨過後才有水流——大多數日子裡，上層水潭平靜如鏡、倒影清晰。\n\n**第二段（瀑高30公尺）終年流水不斷**，是最具代表性的拍攝主題。第三段則延伸至海岸完成整段落差。**全長120公尺、橋高78公尺的仙臨橋（선임교，「七仙女之橋」）**橫跨峽谷中段——橋身兩側鑄有銅製浮雕，描繪**七位仙女凌空飛翔**的姿態，將建廟傳說以建築形式具象化。周圍森林為**珍稀植物棲息地**，包含**台灣油點草（*Tricyrtis macropoda*）**及瀕危物種**濟州滿葵蕨（*Mankyua chejuense*）**（濟州特有種，IUCN極危等級）。\n\n環形步道全長**0.8公里，步行約30分鐘**，途中設有多處陡峭階梯。門票：**成人₩2,500 / 青少年₩1,350 / 7歲以下及65歲以上免費**。天帝淵亦是朝鮮時代文人評選的**「瀛洲十景（영주십경）」**之一——與漢拏山山頂、城山日出及正房瀑布並列——意即今日的西南環線單日即可涵蓋**十景中的兩景（漢拏山 + 天帝淵）**。每兩年在橋畔舉辦一次的**濟州七仙女節（Jeju Chilseonyeo Festival）**於五月（單數年）舉行，以傳統舞蹈與音樂演出重現仙女降凡的傳說——若節慶與行程日期重疊，需提前預訂。開放時間：全年**09:00–18:00**（最後入場17:30）。", "image": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "highlights": ["**天然紀念物第378號（1993年指定）** — 三段式瀑布 + 珍稀植物棲息地", "名稱**「天帝淵」=「天帝之潭」** — 朝鮮道教傳說", "**七仙女（선녀）傳說**刻於**全長120公尺 × 橋高78公尺的仙臨橋**銅製浮雕面板上", "**第一段（瀑高22公尺 / 潭深21公尺）** — 僅在大雨後有流水；**第二段（瀑高30公尺）終年流水**", "**濟州滿葵蕨（*Mankyua chejuense*）**棲息地 — 濟州特有種，IUCN極危等級", "**環形步道0.8公里 / 約30分鐘** — 設有中等難度階梯，鞋履選擇至關重要", "門票：**成人₩2,500 / 青少年₩1,350 / 7歲以下及65歲以上免費**", "**濟州七仙女節（Jeju Chilseonyeo Festival）**每兩年在此舉辦 — 橋畔降凡儀式", "**薄霧微氣候** — 天然降溫，夏季午後熱門避暑勝地"], "timeUsed": ["入口 + 購票 — 約5分鐘", "下行至第一段觀景台 — 約10分鐘", "第一段 + 第二段攝影 — 約20分鐘", "仙臨橋 + 仙女浮雕面板 — 約15分鐘", "森林環形步道 + 返回遊覽車 — 約25分鐘"], "whyOnRoute": "**午後感官轉換錨點** — 在漢拏山開闊的高山視野與柱狀節理之壁暴露的海岸線之後，天帝淵封閉的森林峽谷重置感官體驗，提供蔭涼的休憩空間。七仙女傳說 + 仙臨橋 = 行程目錄中濟州**神話底蘊最深厚的單一錨點**（相較於涉地可峰的韓劇拍攝遺址或城山的地質傳說）。中文洞的地理位置意味著**從柱狀節理搭遊覽車僅需5分鐘，前往O''Sulloc僅需10分鐘** — 是濟州西南路線午間轉乘窗口最為緊湊的一段。13:00抵達也恰好遇上**正午過後的雲層覆蓋，使頂光變得柔和**，有利於林冠與瀑布攝影。", "_poi_meta": {"poi_key": "cheonjeyeon_falls", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Cultural Heritage Administration — Natural Monument No. 378 (1993 designation)", "VisitJeju — Cheonjeyeon Pokpo official listing", "Korea National Arboretum — Mankyua chejuense conservation records", "Jeju Cultural Foundation — Seven Nymphs Festival history", "Seogwipo City tourism — Cheonjeyeon admission and access"]}, "visitBasics": {"hours": "09:00–17:50（最後入場17:10）", "closed": "全年開放", "admission": "成人₩2,500 / 青少年及兒童₩1,350", "walking": "中等難度，含階梯及部分潮濕路段"}, "convenience": {"restroom": "入口區域", "parking": "設有停車場"}, "smartNotes": {"photo": "比起將所有元素塞入同一畫面，以橋梁與瀑布構成層次感的構圖通常效果更佳。", "facilities": "基本設施集中於入口附近。", "tip": "由於設有階梯且部分路段可能濕滑，保持穩定的步伐通常能讓這個景點的遊覽體驗更為愉快。"}, "images": ["/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "/images/tours/cheonjeyeon-falls/photo-004.webp"], "imageCredits": [{"url": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "source": "atoc-korea"}, {"url": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "source": "atoc-korea"}, {"url": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "source": "atoc-korea"}, {"url": "/images/tours/cheonjeyeon-falls/photo-004.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "location": "天帝淵瀑布", "caption": "天帝淵瀑布 — photo 1", "alt": "天帝淵瀑布 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "location": "天帝淵瀑布", "caption": "天帝淵瀑布 — photo 2", "alt": "天帝淵瀑布 — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "location": "天帝淵瀑布", "caption": "天帝淵瀑布 — photo 3", "alt": "天帝淵瀑布 — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/photo-004.webp", "location": "天帝淵瀑布", "caption": "天帝淵瀑布 — photo 4", "alt": "天帝淵瀑布 — gallery image 4"}]}, {"number": 4, "time": "13:15", "duration": "60分鐘", "name": "午餐 — 西歸浦／中文", "category": "午間休整 — 西歸浦／中文在地料理", "description": "**天帝淵瀑布與O''Sulloc之間的60分鐘休整** — 中文度假區距兩處皆近，餐廳林立，同時吸引觀光客與在地客群。依季節與團體類型的預設輪替菜單：漁船靠港期間（9月至2月）可於西歸浦專門店品嚐**燉白帶魚**，**鮑魚拌飯**全年供應，偏好烤肉的旅客可選擇**黑豬（濟州黑豬BBQ）**。 \n\n濟州黑豬（***Sus scrofa* domesticus，濟州品種**）被列為**文化財資料第5號（2015年）**的保護品種，可追溯至約12世紀的歷史記載。素食替代選項（依需求提供）：搭配濟州當季蔬菜的**拌麵**。輪替餐廳中有一間提供**清真友善選項**（已標示食材）— 請於接送時提出需求。午餐後搭乘巴士前往O''Sulloc約25分鐘車程。", "image": null, "highlights": ["**中文**餐廳街 — 距柱狀節理海岸與天帝淵均為3公里", "當季**갈치조림（白帶魚燉煮）**（9月至2月），**전복비빔밥（鮑魚拌飯）**全年供應", "**흑돼지（濟州黑豬）**選項 — 文化財料第5號（2015年）", "**清真友善＋素食**選項（請於接送時提出需求）", "午餐地點**巴士5分鐘即達天帝淵** — 餐後交通時間極短", "團體飲食需求於接送時收集；菜單事先確認"], "timeUsed": ["巴士前往午餐地點 — 約5分鐘", "點餐＋用餐 — 約45分鐘", "巴士前往天帝淵入口 — 約5分鐘", "緩衝時間 — 約5分鐘"], "whyOnRoute": "中文的地理位置意味著**前往柱狀節理海岸（餐前）及天帝淵（餐後）均僅需5分鐘車程** — 與在西歸浦市中心用餐相比，可節省約15分鐘。白帶魚、黑豬、鮑魚是濟州三大代表性蛋白質，均為在地食材 — 旅客在下午茶與咖啡廳行程（固體食物攝取較少）之前，能在一頓飯中體驗到當日的飲食文化精髓。", "visitBasics": {"hours": "視餐廳而定", "closed": "依場地而異", "admission": "視產品條件可能已包含，或於現場自費", "walking": "極少"}, "convenience": {"restroom": "餐廳內部", "parking": "提供停車場"}, "smartNotes": {"photo": "若想拍攝生活風格式的精選照片，食物攝影在此處效果尤佳。", "facilities": "餐飲設施相當完善。", "tip": "從容的午餐通常比節省幾分鐘更能提升下午的整體體驗。"}}, {"number": 5, "time": "14:35", "duration": "70分鐘", "name": "O''Sulloc茶博物館", "category": "茶文化與西廣茶園 — 愛茉莉太平洋品牌遺產", "description": "**O''Sulloc茶博物館（오설록 티 뮤지엄，「오설록」意為「遇雪 + 翠綠」）**是**愛茉莉太平洋集團**（韓國最大美妝企業）旗下的茶文化旗艦品牌。創辦人**徐成煥於1979年親自開創此項目**，在傳統認知認為韓國不適合商業種茶之時，將濟州西廣高原上的火山灰農地加以開墾利用。如今，**西廣茶園（서광다원）**是**韓國最大的綠茶茶園**，每年透過愛茉莉太平洋旗下三座濟州茶莊生產約**700公噸**茶葉。\n\n博物館建築於**2001年**在茶園中心落成，以其**極簡主義綠頂亭閣置身茶行之間**的設計，入選**designboom全球十大藝術博物館**。**免費入場**，每日開放時間**09:00–18:00**，年訪客量約**200萬人次**。參觀行程自然分為三部分：**(1) 館內展覽** — 茶葉生產流程、唐代（618–907年）起的古董茶器收藏，及俯瞰茶園全景的屋頂觀景台；**(2) 茶屋咖啡廳** — 提供招牌**綠茶捲蛋糕（오설록 롤케이크）**及以當季採摘茶葉製成的**抹茶冰淇淋**；**(3) 茶園步道** — 穿梭於茶樹行列間的碎石小徑，西側邊緣是拍攝日落的熱門地點。\n\n**Innisfree濟州之家**（愛茉莉太平洋旗下天然美妝品牌）步行僅需**5分鐘**，歡迎對品牌生態系感興趣的旅客前往參觀——同樣免費入場，並可選擇參加濟州柑橘香皂DIY工作坊（₩15,000）。博物館建築由韓國建築師**Mass Studies（趙敏碩）**設計，刻意採用低調的水平形態，呼應茶行的幾何美學，而非與農業景觀相互爭奪焦點——這份建築上的謙遜之姿不僅為其贏得designboom十大排名，至今仍是韓國當代博物館設計的經典案例。\n\n可選擇加購：**O''Sulloc茶藝課程（每人₩30,000，60分鐘，需提前預訂）** — 在韓式陶瓷器皿上進行導覽品茶體驗，含泡茶技法示範，每日**10:00–16:00**開課，週三及週六場次提供英語授課。", "image": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "highlights": ["**愛茉莉太平洋**旗艦品牌 — 韓國最大美妝企業；創辦人徐成煥於**1979年**在濟州開創種茶先河", "**西廣茶園＝韓國最大綠茶茶園**；年產量約 700 公噸", "博物館**於 2001 年開館**——曾獲 designboom 評選為建築十大藝術博物館", "**免費入場**，每日開放 **09:00–18:00**，年訪客量約 200 萬人次", "古代茶器收藏橫跨**唐代（618–907 年）**至韓國近代朝鮮陶瓷", "**綠茶捲蛋糕** ＋ **綠茶冰淇淋** ＝ 咖啡廳招牌品項", "**悅詩風吟濟州之家**步行 5 分鐘即達——免費參觀，可選擇參加柑橘香皂 DIY 體驗，費用 ₩15,000", "茶園步道**在黃金時段（16:00–17:00）最適合拍照**", "屋頂平台與地面茶行提供兩種不同高度，可拍攝各具特色的茶田構圖"], "timeUsed": ["停車＋入場——約 5 分鐘", "博物館內部＋茶器展覽——約 20 分鐘", "茶館咖啡廳（捲蛋糕＋冰淇淋）——約 20 分鐘", "茶園步道漫步——約 20 分鐘", "可選：悅詩風吟濟州之家參觀——約 10 分鐘"], "whyOnRoute": "**從自然景點轉向濟州生活風格的文化轉折點**。漢拏山、柱狀節理帶、天帝淵是濟州的地質名片；O''Sulloc 則是濟州的**現代品牌象徵**——它有力地證明了火山灰土壤、年均 1,500 毫米降雨量，加上韓國的園藝投資，足以孕育出一個行銷全球的茶葉產業。**免費入場＋年訪客 200 萬人次** ＝ 濟州西南部摩擦係數最低的室內錨點景點；若天帝淵參觀後遭遇降雨，此處也是絕佳的室內備案。西廣高原的地理位置同時也是**南海岸景點與北西部涯月之間的地理樞紐**——是下午過渡的天然中繼站。相較於**翰林公園（植物園，₩15,000，體驗較分散）**或**山茶花丘（₩9,000，賞花季節有限）**，O''Sulloc **免費、全年開放且品牌辨識度高**——是這條旅遊走廊中性價比最高的室內景點。", "_poi_meta": {"poi_key": "osulloc_tea_museum", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Amorepacific corporate history (amorepacific.com)", "O''sulloc Tea Museum official site (osulloc.com)", "designboom Top 10 art museums archival listing", "Korea Tea Industry Association — production statistics", "VisitJeju — Osulloc Tea Museum"], "image": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "images": ["/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp"], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "雪綠茶博物館", "alt": "雪綠茶博物館 — 圖庫圖片 1", "caption": "雪綠茶博物館 — 照片 1"}, {"id": 2, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "雪綠茶博物館", "alt": "雪綠茶博物館 — 圖庫圖片 2", "caption": "雪綠茶博物館 — 照片 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "雪綠茶博物館", "alt": "雪綠茶博物館 — 圖庫圖片 3", "caption": "雪綠茶博物館 — 照片 3"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "雪綠茶博物館", "alt": "雪綠茶博物館 — 圖庫圖片 4", "caption": "雪綠茶博物館 — 照片 4"}], "imageCredits": [{"url": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "source": "atoc-korea"}]}, "visitBasics": {"hours": "通常 09:00–18:00 開放，部分季節可能有所調整", "closed": "全年開放", "admission": "免費", "walking": "交通便利"}, "convenience": {"restroom": "博物館及咖啡廳區域", "parking": "備有停車場"}, "smartNotes": {"photo": "咖啡廳附近的廣角茶田視野及側面角度，通常比單純的特寫拍攝更具視覺效果。", "facilities": "設有洗手間、飲品供應及休憩座位，是下午行程中最舒適的景點之一。", "tip": "比起只匆匆參觀博物館，同時享受景色與咖啡廳氛圍，通常會讓整趟旅程更加充實滿足。"}, "images": ["/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp"], "imageCredits": [{"url": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "雪綠茶博物館", "alt": "雪綠茶博物館 — 圖庫圖片 1", "caption": "雪綠茶博物館 — 照片 1"}, {"id": 2, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "雪綠茶博物館", "alt": "雪綠茶博物館 — 圖庫圖片 2", "caption": "雪綠茶博物館 — 照片 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "雪綠茶博物館", "alt": "雪綠茶博物館 — 圖庫圖片 3", "caption": "雪綠茶博物館 — 照片 3"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "雪綠茶博物館", "alt": "雪綠茶博物館 — 圖庫圖片 4", "caption": "雪綠茶博物館 — 照片 4"}]}, {"number": 6, "time": "16:15", "duration": "55分鐘", "name": "涯月咖啡街（翰潭海岸步道）", "category": "海岸咖啡街 — 午後咖啡＋偶來小路15A路段", "description": "**涯月咖啡街（애월 카페거리）**是位於濟州西北海岸、沿**翰潭海岸步道（한담해안산책로）**延伸的**5 公里海岸帶**——這裡是韓國最密集的**「海景咖啡廳」目的地**，超過 30 家設計感十足的咖啡廳聚集於翰潭海灘至郭支海灘之間的懸崖邊。這條步道正式名稱為**張漢哲散步路（장한철산책로）**，得名自**張漢哲（장한철，1744–?）**——一位出身濟州的朝鮮時代學者，其著作**《漂海錄（표해록）》**是韓國最早的海上求生紀事之一，記錄了他於 1771 年在太平洋上漂流的親身經歷。\n\n步道是**濟州偶來小路 15A（翰林→科內）的 30 分鐘單程海岸路段**——黑色玄武岩懸崖、潮池、小規模六角柱狀節理，加上無遮蔽的西向地平線，是濟州首屈一指的觀日落勝地。**依季節輪替的代表性咖啡廳**：**봄날카페（春日咖啡）**——曾出現於 **2014 年韓劇《來自星星的您》**，使涯月一夜之間成為粉絲朝聖地；**Randy''s Donuts**（洛杉磯品牌、韓國加盟店——設有寬敞屋頂平台）；**Cafe Knotted**（招牌奶油甜甜圈＋海景）；**해지개 카페（海之蓋咖啡，即夕陽咖啡廳）**（專為傍晚光線而設的服務理念）；**Aewol the Sunset**（屋頂露台，定價較高）。\n\n步道及海灘**免費**入場；咖啡廳飲品＋甜點定價約 ₩6,000–12,000。**張漢哲的《漂海錄》**——即步道命名之典故——被視為**韓國海洋文學的奠基文本之一**，記錄了他在 **1770 年 12 月**搭乘前往濟州的船隻遭暴風吹離航道後，在太平洋上漂流 29 天的遭遇。他最終獲琉球（今沖繩）漁民救起，並輾轉經長崎回國，其紀述比西方同類求生回憶錄早了數十年，對現代韓國海洋史學研究具有重要參考價值。\n\n沿懸崖步道設有引用該書韓英雙語段落的說明牌——是罕見的文學遺產現地標記。給**攝影愛好者**的提示：沿涯月海岸使用無人機，**在濟州國際機場 9 公里進場航道管制區以外**的區域是被允許的——飛行前請透過「韓國無人機地圖」App 確認精確禁飛範圍。**偶來小路 15A** 全程官方路線為翰林港 → 涯月 → 科內港，全長 13 公里；今日行程步行其中央段，即翰潭至郭支之間約 1.5 公里。", "image": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "highlights": ["翰潭與郭支海灘之間的**5 公里海岸咖啡帶**——韓國密度最高的海景咖啡廳聚集地", "**張漢哲散步路**——以濟州出身的朝鮮學者（1744–?）、《**漂海錄**》求生回憶錄作者之名命名", "**偶來小路 15A** 路段（翰林→科內）——單程 30 分鐘海岸步道", "**春日咖啡廳（봄날 카페）** = **《來自星星的您》（2014年，SBS）** 拍攝地", "輪替人氣咖啡廳：**Randy''s Donuts**、**Cafe Knotted**、**Haejigae Cafe**、**Aewol the Sunset**", "**面西地平線** = 無遮蔽夕陽觀賞地點 —— **春秋季節 17:30–18:30**", "涵德海崖頂端**可見六角柱狀節理** —— 與大浦地質相同，規模較小", "海岸步道 + 海灘**免費**；咖啡廳每杯飲料 + 甜點約₩6,000–12,000", "**距濟州國際機場車程約40分鐘** —— 傍晚航班前最後可行的停留點"], "timeUsed": ["巴士抵達 + 涵德停車 —— 約5分鐘", "海岸步道步行（涵德 → 中段） —— 約20分鐘", "選定咖啡廳休息（飲料 + 甜點） —— 約30分鐘", "峭壁頂端夕陽攝影 —— 約15分鐘", "步行返回巴士 —— 約5分鐘"], "whyOnRoute": "**以夕陽為核心的壓軸行程**。西南環線刻意以涯月作結，原因如下：（1）**面西地平線** = 當日路線中唯一可無遮蔽觀賞夕陽的地點；（2）**車程40分鐘可達濟州機場** = 不需折返的前提下，傍晚航班前最後可行的停留點；（3）**咖啡廳密集的室內備案** = 若天氣轉壞，旅客無須離開現場，可直接從海岸步道轉移至室內咖啡廳座位。與另一條以**城山日出峰（東海岸，以黎明為核心而非夕陽）**作結的精華環線相比，涯月 = **生活風格式壓軸**，城山 = **世界遺產式壓軸** —— 氣質各異，行程互補。15:50抵達的時間特別配合**春秋季節17:30–18:30的夕陽窗口** —— 旅客有約75分鐘步行步道、在咖啡廳安頓下來，並在返回濟州市的巴士出發前於峭壁平台拍攝夕陽。", "_poi_meta": {"poi_key": "aewol_cafe_street", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Jeju Olle Foundation — Trail 15A official map (Hallim → Gonae)", "Aewol-eup Cultural Office — Jang Han Chul historical records", "VisitJeju — Aewol Cafe Street", "SBS Drama Archive — ''You Who Came From the Stars'' filming locations", "Joseon Wangjo Sillok / Korean Folklore Society — Pyohaerok textual study"]}, "visitBasics": {"hours": "該區域全天開放；各咖啡廳各有其營業時間", "closed": "整個區域無固定公休日", "admission": "免費", "walking": "輕鬆"}, "convenience": {"restroom": "視所選咖啡廳而定", "parking": "區域內設有停車場"}, "smartNotes": {"photo": "午後的逆光效果與面海露臺，通常是此處拍攝最佳照片的黃金條件。", "facilities": "舒適度取決於所選咖啡廳，因此彈性安排比過度固定單一場地效果更佳。", "tip": "當旅客享有較自由的節奏、而非被過度引導時，此站通常獲得更高評價。"}, "images": ["/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp"], "imageCredits": [{"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "location": "涯月咖啡街（翰潭海岸步道）", "caption": "涯月咖啡街（翰潭海岸步道） — photo 1", "alt": "涯月咖啡街（翰潭海岸步道） — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "location": "涯月咖啡街（翰潭海岸步道）", "caption": "涯月咖啡街（翰潭海岸步道） — photo 2", "alt": "涯月咖啡街（翰潭海岸步道） — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "location": "涯月咖啡街（翰潭海岸步道）", "caption": "涯月咖啡街（翰潭海岸步道） — photo 3", "alt": "涯月咖啡街（翰潭海岸步道） — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "location": "涯月咖啡街（翰潭海岸步道）", "caption": "涯月咖啡街（翰潭海岸步道） — photo 4", "alt": "涯月咖啡街（翰潭海岸步道） — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp", "location": "涯月咖啡街（翰潭海岸步道）", "caption": "涯月咖啡街（翰潭海岸步道） — photo 5", "alt": "涯月咖啡街（翰潭海岸步道） — gallery image 5"}]}, {"number": 7, "time": "17:30", "duration": "45分鐘", "name": "梨湖泰烏海灘（馬燈塔 · 日落）", "category": "濟州市海灘 — 濟州矮馬燈塔＋日落壓軸", "description": "**梨湖泰烏海灘（이호테우해변，梨湖海水浴場）**是距離濟州市區與濟州國際機場最近的海水浴場，是為一天畫下句點的**日落壓軸**景點。最具代表性的看點，是矗立於防波堤上相對而立的兩座**濟州矮馬燈塔（馬燈塔）** — 以濟州矮馬為造型、**高約12公尺的紅色馬燈塔與白色馬燈塔**分別佇立於外側與內側防波堤 — 白色與紅色是供船隻辨別航道左右的航海標誌，與蔚藍的海洋、天空相映成趣，成為濟州數一數二的人生美照名所。 \n\n沙灘由貝殼與沙混合而成的**泛著銀光的細沙**鋪成，坡度平緩，吸引許多家庭遊客造訪。海灘後方有**松樹林**提供樹蔭與步道，退潮時除了寬廣的沙灘，還能看見**元堂（濟州傳統石滬捕魚設施）**的樣貌 — 元堂是利用漲退潮落差將魚困住捕撈的濟州傳統漁法，梨湖泰烏留有復原而成的**梨湖Mosalwon**。 \n\n海灘旁緊接著**道頭洞彩虹海岸路**，可享受色彩繽紛的防護塊與海岸兜風，又因鄰近機場，是**搭乘傍晚航班前最後順道一遊的理想位置**。海灘與步道**入場免費**。", "image": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "highlights": ["距濟州市區與**機場最近的海水浴場** — 日落壓軸＋前往機場便利", "代表性的**濟州矮馬燈塔（馬燈塔）** — 紅白兩座，高約12公尺，代表性拍照點", "混有貝殼的**銀光細沙**＋平緩坡度 — 親子友善海灘", "海灘後方**松樹林**樹蔭與步道", "退潮時顯現的濟州傳統漁法設施**元堂（梨湖Mosalwon）**", "緊鄰的**道頭洞彩虹海岸路**海岸兜風", "**免費入場** — 日落時段的金色光線"], "timeUsed": ["海灘停車＋移動 — 約5分鐘", "濟州矮馬燈塔與防波堤散步＋拍照 — 約20分鐘", "沙灘與彩虹海岸路日落觀賞 — 約15分鐘", "重新集合 — 約5分鐘"], "whyOnRoute": "**一天的日落壓軸暨最後一個景點**。位於從涯月享受咖啡與海岸後返回濟州市方向的途中，動線自然，向西開闊的水平線與濟州矮馬燈塔相互輝映，為一天畫下金色的句點。鄰近濟州國際機場，**適合作為下車地點或搭乘傍晚航班前的最後一站** — 日落時刻因季節而異（夏季晚、冬季早），故會依當天的日落調整抵達時間。", "_poi_meta": {"poi_key": "iho_tewoo_beach", "kb_version": "raw-2026", "verified_date": "2026-06-23", "sources": ["VisitKorea — Iho Tewoo Beach (이호테우해변)", "VisitKorea — Iho Tewoo Horse Lighthouses (이호테우 말 등대)", "Jeju Tourism Organization", "Jeju City official tourism data"]}, "visitBasics": {"hours": "海灘與步道24小時開放（免費）；於日落時段造訪", "closed": "全年開放", "admission": "免費（無入場費與停車費）", "walking": "輕鬆 — 平坦沙灘與防波堤散步，約15～20分鐘"}, "convenience": {"restroom": "海水浴場公共洗手間", "parking": "免費停車場（旺季週末擁擠）"}, "smartNotes": {"photo": "從防波堤盡頭拍攝紅白濟州矮馬燈塔最為震撼，日落時刻的逆光剪影與彩虹海岸路是熱門構圖。", "facilities": "海灘周邊咖啡廳、餐廳與便利設施完善。", "tip": "日落時刻每季不同（夏季約19:30、春秋約18:30、冬季約17:40），請依當天日落調整抵達時間。鄰近機場，適合作為搭乘傍晚航班前的最後一站。"}, "images": ["/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp"], "imageCredits": [{"url": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "source": "atoc-korea"}, {"url": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "location": "梨湖泰烏海灘", "caption": "梨湖泰烏海灘 — photo 1", "alt": "梨湖泰烏海灘 — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp", "location": "梨湖泰烏海灘", "caption": "梨湖泰烏海灘 — photo 2", "alt": "梨湖泰烏海灘 — gallery image 2"}]}], "routeFlowStops": [{"name": "1100高地", "theme": "漢拿山", "type": "01"}, {"name": "柱狀節理", "theme": "海岸", "type": "02"}, {"name": "天帝淵", "theme": "瀑布", "type": "03"}, {"name": "午餐", "theme": "重整", "type": "04"}, {"name": "O''Sulloc", "theme": "茶園", "type": "05"}, {"name": "涯月", "theme": "咖啡廳", "type": "06"}, {"name": "梨湖泰烏", "theme": "日落", "type": "07"}], "routePhases": [{"phase": "오전", "duration": "1-3", "description": ""}, {"phase": "정오~오후 초반", "duration": "4-5", "description": ""}, {"phase": "마무리", "duration": "6-7", "description": ""}], "routeShapeIntro": {"title": "這條路線的流程", "subtitle": "從漢拿山1100高地拉姆薩濕地出發，途經火山海岸與瀑布、午餐、茶園，最後以涯月咖啡街與梨湖泰烏日落作結。大致為09:30～18:15。"}, "whyTourWorks": {"bestFor": ["初次造訪濟州的旅客及情侶", "成人家庭旅遊", "喜愛自然風光、茶園，並希望以輕鬆氛圍收尾的旅客", "活力充沛的中高齡旅客"], "lessIdealFor": ["希望避免任何短程階梯或上坡路段的旅客", "大量依賴嬰兒車的旅遊群體", "以幼齡兒童為主軸規劃的行程"], "routeLogicSections": [{"title": "節奏與架構", "icon": "sun", "iconBg": "bg-amber-50/80", "items": [{"label": "輕鬆起步的漢拿山高地", "detail": "1100高地濕地是平坦的棧道散步，可在沒有體力負擔的情況下起步，同時感受漢拿山高地的氛圍，路線並自然銜接至南邊海岸。"}, {"label": "午餐安排在恰當的時間點", "detail": "午餐在早晨較為開闊壯麗的景點，與隨後較為靜謐的瀑布及茶園段之間，為整日行程帶來轉換與調整。"}, {"label": "O''Sulloc之後的輕鬆收尾", "detail": "茶園柔和了氛圍後，涯月以咖啡與海景開啟午後，最後的梨湖泰烏日落為一天畫下金色的句點。"}]}, {"title": "路線的設計理念", "icon": "mountain", "iconBg": "bg-sky-50/80", "items": [{"label": "先山後海", "detail": "這條路線設計為先在漢拿山1100高地體驗高度感與高山濕地，再於柱狀節理向海岸暢快開展視野。"}, {"label": "茶園前的瀑布", "detail": "天帝淵在 O''Sulloc 以更輕鬆、更溫和的方式開啟下半段行程之前，讓整條路線沉澱下來。"}, {"label": "以日落收束的海岸結尾", "detail": "在涯月享受咖啡與海岸後，於梨湖泰烏濟州矮馬燈塔迎接日落，以生活風格導向的收尾為一天畫下句點，而非又一個緊湊的觀光行程。"}]}, {"title": "當條件發生變化時", "icon": "wind", "iconBg": "bg-slate-50/80", "items": [{"label": "漢拿山道路變數", "detail": "1100高地在大雪、暴雨、結冰時1100公路可能封閉，此時會調整為國立濟州博物館等室內替代景點。"}, {"label": "海岸的風", "detail": "柱狀節理帶和涯月比內陸景點更直接暴露在強風之中。"}, {"label": "整體均衡的步行負擔", "detail": "1100高地與梨湖泰烏皆平坦，但天帝淵有階梯與短距離上坡路段，需多加留意。"}]}]}, "practicalAccordionItems": [{"id": "pickup", "title": "接送服務", "preview": "濟州市區飯店大廳接送", "content": ["上午8點20分至8點50分之間於飯店大廳進行接送。", "返程預計於梨湖泰烏日落後的下午6點30分至7點之間。", "機場接送可依需求另行安排。", "確切接送時間將於前一晚確認。"]}, {"id": "walking", "title": "步行與地形", "preview": "整體難度適中，大多數旅客均可輕鬆應付", "content": ["全天總步行距離通常約3.5～4.5公里。", "1100高地：約1公里的平坦棧道（約20分鐘），最為輕鬆。", "柱狀節理：好走的海岸步道。", "天帝淵：林間小徑、階梯，偶有濕滑路段。", "O''Sulloc與涯月、梨湖泰烏：可悠閒休憩的舒適行程。", "建議穿著止滑性佳的步行鞋。"]}, {"id": "weather", "title": "天氣與行程異動調整", "preview": "行程通常照常進行，如有需要將視情況調整", "content": ["小雨：行程通常按原定計劃進行。", "因大雪、暴雨、結冰封閉1100公路時：1100高地可能調整為室內替代景點（如國立濟州博物館）。", "強風時：柱狀節理、涯月或梨湖泰烏的停留時間可能縮短。", "午後天氣轉壞時：O''Sulloc的午後時間比重可能增加。", "特定景點休館時：可能改用替代景點。"]}, {"id": "wear", "title": "穿著與攜帶建議", "preview": "舒適的鞋子、多層衣物及輕薄外套", "content": ["防滑鞋", "適應山地與海岸溫差的多層次穿搭", "輕薄防風外套", "帽子與防曬乳", "水壺"]}, {"id": "included", "title": "包含／不包含項目", "preview": "含導遊、車輛、接送及門票", "variant": "包含", "content": ["英語導遊", "小型團體車輛", "濟州市區飯店接送與送回", "所有景點門票", "瓶裝水", "午餐（現場自付）", "個人購物費用", "導遊小費"]}], "practicalWeatherStatic": {"today": {"temp": "—", "label": "即時天氣整合"}, "tomorrow": {"temp": "—", "label": "每日更新"}, "_seasonalSummary": "Southwest Jeju has the most varied terrain on the island — from Hallasan''s 1100 Highland Ramsar wetland to Iho Tewoo''s city beach. The 1100m highland runs 7-10°C cooler than the coast; bring a layer year-round.", "_seasonalTemperatures": [{"season": "Spring (Mar–May)", "range": "6–20°C inland / 10–22°C coast", "notes": "Cherry blossoms; new tea leaves at Osulloc."}, {"season": "Summer (Jun–Aug)", "range": "18–25°C inland / 22–30°C coast", "notes": "1100 Highland stays cool; Iho Tewoo lively at sunset."}, {"season": "Autumn (Sep–Nov)", "range": "8–22°C inland / 12–24°C coast", "notes": "Best season — golden tea fields, clear Hallasan views."}, {"season": "Winter (Dec–Feb)", "range": "-2–7°C inland / 3–10°C coast", "notes": "1100 Highland often snowy — striking, but Road 1100 may close; warm layers required."}]}, "seasonalVariations": [{"season": "春季", "description": "油菜花盛開的季節，為部分海岸線添上一抹金黃色彩。"}, {"season": "夏季", "description": "白晝漫長，沿途的綠意格外深邃濃郁。"}, {"season": "秋季", "description": "晴朗的天空往往讓路線上的山巒、海岸與茶園層次顯得格外清晰。"}, {"season": "冬季", "description": "路線通常顯得更為寧靜，日照時間較短，整體氛圍也更加平和。"}], "bookingTrustItems": [{"icon": "check-circle", "title": "持牌本地營運", "description": "於濟州合法營運的導覽服務", "iconBg": "bg-emerald-50/80"}, {"icon": "route", "title": "以濟州西南部為核心設計", "description": "專為西南路線量身設計", "iconBg": "bg-sky-50/80"}, {"icon": "users", "title": "小團體運作", "description": "最多8位賓客", "iconBg": "bg-amber-50/80"}], "bookingSupportSteps": [{"timing": "預訂後即時", "title": "即時確認", "detail": "您將收到包含當日行程摘要的預訂確認通知。"}, {"timing": "出發前12小時", "title": "12小時前提醒", "detail": "提前分享天氣資訊及路線調整說明。"}, {"timing": "前一晚", "title": "最終接送通知", "detail": "將告知您確切的接送時間及司機聯絡資料。"}, {"timing": "行程當天早晨", "title": "當日路線說明", "detail": "將根據現場即時狀況進行簡短的早間說明。"}, {"timing": "行程進行中", "title": "即時逐站導覽", "detail": "您將在每個停靠點獲得所需資訊。"}, {"timing": "行程結束後", "title": "行程後續支援", "detail": "事後可進一步提供指引與建議。"}], "staticQuestions": [{"id": "first-time", "question": "對初次造訪濟州的旅客是好選擇嗎？", "answer": "是的。可體驗漢拿山1100高地風景、火山海岸線、瀑布散步、茶園氛圍，以及涯月與梨湖泰烏日落收尾在內的均衡一日行程。"}, {"id": "walking", "question": "步行難度會很高嗎？", "answer": "不會。天帝淵因有階梯而是最活躍的一段，但1100高地是平坦的棧道散步，其餘行程整體也都能輕鬆應付。"}, {"id": "rain", "question": "下雨天行程也會進行嗎？", "answer": "是的。下雨也能進行行程，若因大雪、暴雨封閉1100公路，1100高地會改為室內替代景點，或暴露較多的海岸路段可能縮短。"}, {"id": "parents", "question": "適合與父母或年長家人同行嗎？", "answer": "在許多情況下適合。特別適合成人家庭旅遊，尤其是所有人都能應對階梯和短距離上坡路段的情況。"}, {"id": "children", "question": "可以帶孩子參加嗎？", "answer": "可以。特別適合約8歲以上、能配合短程步行及全日行程節奏的孩子。"}, {"id": "order", "question": "造訪順序會依現場狀況調整嗎？", "answer": "是的。會依山區天氣、海岸風勢、交通狀況、日落時刻、遊客流量等，尤其在1100高地與海岸路段一帶可能有小幅順序調整。"}, {"id": "lunch", "question": "含午餐嗎？", "answer": "視方案條件而定。行程中已安排午餐時間，但餐點是否包含在內，需依您所預訂的方案為準。"}, {"id": "why-1100goji", "question": "路線為什麼從1100高地開始？", "answer": "因為在不變成沉重登山行程的前提下，於精力最充沛的時段以平坦的棧道散步輕鬆體驗漢拿山高地，為一天揭開序幕。"}, {"id": "why-jusangjeolli", "question": "為什麼漢拿山之後要去柱狀節理帶？", "answer": "因為這樣能讓濟州的火山故事自然地從山地地形延伸至壯觀的玄武岩海岸線。"}, {"id": "why-osulloc", "question": "O''Sulloc為什麼排在涯月之前？", "answer": "因為在瀑布路段之後柔和地轉換氛圍，讓後半段的涯月與梨湖泰烏日落感覺更加從容而放鬆。"}, {"id": "later-structure", "question": "後半段為什麼這樣安排？", "answer": "因為午餐與天帝淵在充滿活力的上午路段之後穩定節奏，O''Sulloc增添輕鬆享受茶園的休憩，涯月與梨湖泰烏日落則自然而餘韻悠長地為一天畫下句點。"}], "guestReviews": [], "reviewsSummary": {"averageRating": 0, "totalReviews": 0, "ratingDistribution": [{"stars": 5, "count": 0, "percentage": 0}, {"stars": 4, "count": 0, "percentage": 0}, {"stars": 3, "count": 0, "percentage": 0}, {"stars": 2, "count": 0, "percentage": 0}, {"stars": 1, "count": 0, "percentage": 0}], "highlights": []}, "sticky_booking_bar": {"note": "checkout_tour_id 於執行時從 Supabase／環境變數解析；非靜態 JSONB 的一部分。", "price": {"amountLabel": "52", "originalPriceUsd": null, "salePriceUsd": 52, "discountPercent": null, "currency": "USD", "per": "person"}}, "matching_profile": {"product_type": "small_group", "route_type": "fixed_route", "region_type": "jeju_southwest", "region_tags": ["jeju_southwest", "jeju_aewol", "jeju_hallasan", "jeju_city"], "theme_tags": ["nature", "cafe", "tea_culture", "first_time_friendly", "beach", "sunset"], "poi_tags": ["hallasan_1100_wetland", "osulloc_tea_museum", "iho_tewoo_beach", "cheonjeyeon_falls", "aewol_cafe_stre