hwest_jeju", "자연", "카페", "일몰"]}, "headlineLine1": "Jeju Suroeste", "headlineLine2": "Hallasan, O''Sulloc, Aewol e Iho Tewoo", "price": {"amountLabel": "52", "originalPriceUsd": null, "salePriceUsd": 52, "discountPercent": null, "currency": "USD", "per": "person"}, "hero": {"imageUrl": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "imagePosition": "center 35%", "tagline": "Trekking por el humedal de las Tierras Altas 1100, acantilados volcánicos, sendero a la cascada, campos de té y un final al atardecer en Aewol e Iho Tewoo", "pills": ["Ideal para visitantes de Jeju por primera vez", "Suroeste de Jeju"], "meta": {"duration": "9 horas", "region": "Suroeste de Jeju", "stops": "7 paradas", "rating": 0, "ratingStars": 5}}, "subnavItems": [{"id": "overview", "label": "Descripción general"}, {"id": "itinerary", "label": "Itinerario"}, {"id": "details", "label": "Detalles"}, {"id": "faq", "label": "FAQ"}, {"id": "reviews", "label": "**Reviews** → Reseñas"}], "glanceItems": [{"icon": "camera", "label": "**Photo Value** → Valor fotográfico", "value": "**Excellent** → Excelente", "level": 5}, {"icon": "mountain", "label": "**Scenic** → Pintoresco", "value": "**Good** → Bueno", "level": 4}, {"icon": "footprints", "label": "**Walking** → Caminata", "value": "**Moderate** → Moderado", "level": 3}, {"icon": "cloud-rain", "label": "**Rain Safety** → Seguridad bajo la lluvia", "value": "**Moderate** → Moderado", "level": 3}, {"icon": "users", "label": "**Family Fit** → Apto para familias", "value": "**Good** → Bueno", "level": 4}, {"icon": "gauge", "label": "**Balance** → Equilibrio", "value": "**Balanced** → Equilibrado", "level": 4}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "Tierras Altas 1100 de Hallasan", "alt": "Tierras Altas 1100 de Hallasan — gallery image 1", "caption": "Tierras Altas 1100 de Hallasan — photo 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "location": "Acantilado Daepo Jusangjeolli", "alt": "Acantilado Daepo Jusangjeolli — gallery image 1", "caption": "Acantilado Daepo Jusangjeolli — photo 1"}, {"id": 3, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "location": "Cascada Cheonjeyeon", "alt": "Cascada Cheonjeyeon — gallery image 1", "caption": "Cascada Cheonjeyeon — photo 1"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "Museo del Té O''sulloc", "alt": "Museo del Té O''sulloc — imagen de galería 1", "caption": "Museo del Té O''sulloc — foto 1"}, {"id": 5, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "location": "Calle de Cafés de Aewol (Sendero Costero Handam)", "alt": "Calle de Cafés de Aewol (Sendero Costero Handam) — gallery image 1", "caption": "Calle de Cafés de Aewol (Sendero Costero Handam) — photo 1"}, {"id": 6, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "Tierras Altas 1100 de Hallasan", "alt": "Tierras Altas 1100 de Hallasan — gallery image 2", "caption": "Tierras Altas 1100 de Hallasan — photo 2"}, {"id": 7, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "Tierras Altas 1100 de Hallasan", "alt": "Tierras Altas 1100 de Hallasan — gallery image 3", "caption": "Tierras Altas 1100 de Hallasan — photo 3"}, {"id": 8, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "location": "Acantilado Daepo Jusangjeolli", "alt": "Acantilado Daepo Jusangjeolli — gallery image 2", "caption": "Acantilado Daepo Jusangjeolli — photo 2"}, {"id": 9, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "location": "Acantilado Daepo Jusangjeolli", "alt": "Acantilado Daepo Jusangjeolli — gallery image 3", "caption": "Acantilado Daepo Jusangjeolli — photo 3"}, {"id": 10, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "location": "Acantilado Daepo Jusangjeolli", "alt": "Acantilado Daepo Jusangjeolli — gallery image 4", "caption": "Acantilado Daepo Jusangjeolli — photo 4"}, {"id": 11, "type": "photo", "src": "/images/tours/jusangjeolli/photo-005.webp", "location": "Acantilado Daepo Jusangjeolli", "alt": "Acantilado Daepo Jusangjeolli — gallery image 5", "caption": "Acantilado Daepo Jusangjeolli — photo 5"}, {"id": 12, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "location": "Cascada Cheonjeyeon", "alt": "Cascada Cheonjeyeon — gallery image 2", "caption": "Cascada Cheonjeyeon — photo 2"}, {"id": 13, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "location": "Cascada Cheonjeyeon", "alt": "Cascada Cheonjeyeon — gallery image 3", "caption": "Cascada Cheonjeyeon — photo 3"}, {"id": 14, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/photo-004.webp", "location": "Cascada Cheonjeyeon", "alt": "Cascada Cheonjeyeon — gallery image 4", "caption": "Cascada Cheonjeyeon — photo 4"}, {"id": 15, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "Museo del Té O''sulloc", "alt": "Museo del Té O''sulloc — imagen de galería 2", "caption": "Museo del Té O''sulloc — foto 2"}, {"id": 16, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "Museo del Té O''sulloc", "alt": "Museo del Té O''sulloc — imagen de galería 3", "caption": "Museo del Té O''sulloc — foto 3"}, {"id": 17, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "Museo del Té O''sulloc", "alt": "Museo del Té O''sulloc — imagen de galería 4", "caption": "Museo del Té O''sulloc — foto 4"}, {"id": 18, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "location": "Calle de Cafés de Aewol (Sendero Costero Handam)", "alt": "Calle de Cafés de Aewol (Sendero Costero Handam) — gallery image 2", "caption": "Calle de Cafés de Aewol (Sendero Costero Handam) — photo 2"}, {"id": 19, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "location": "Calle de Cafés de Aewol (Sendero Costero Handam)", "alt": "Calle de Cafés de Aewol (Sendero Costero Handam) — gallery image 3", "caption": "Calle de Cafés de Aewol (Sendero Costero Handam) — photo 3"}, {"id": 20, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "location": "Calle de Cafés de Aewol (Sendero Costero Handam)", "alt": "Calle de Cafés de Aewol (Sendero Costero Handam) — gallery image 4", "caption": "Calle de Cafés de Aewol (Sendero Costero Handam) — photo 4"}, {"id": 21, "type": "photo", "src": "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp", "location": "Calle de Cafés de Aewol (Sendero Costero Handam)", "alt": "Calle de Cafés de Aewol (Sendero Costero Handam) — gallery image 5", "caption": "Calle de Cafés de Aewol (Sendero Costero Handam) — photo 5"}, {"id": 22, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "location": "Playa de Iho Tewoo", "caption": "Playa de Iho Tewoo — photo 1", "alt": "Playa de Iho Tewoo — gallery image 1"}, {"id": 23, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp", "location": "Playa de Iho Tewoo", "caption": "Playa de Iho Tewoo — photo 2", "alt": "Playa de Iho Tewoo — gallery image 2"}], "itineraryStops": [{"number": 1, "time": "09:30", "duration": "45 min", "name": "Tierras Altas 1100 de Hallasan", "category": "Humedal Ramsar de alta montaña con pasarela — una muestra del Hallasan de la UNESCO", "description": "El **Humedal de las Tierras Altas 1100 de Hallasan (한라산 1100고지 습지)** es un humedal de alta montaña situado a **1.100 m** de altitud en la ladera occidental del Hallasan, inscrito el **12 de octubre de 2009 como Humedal de Importancia Internacional de la Convención de Ramsar (Sitio Ramsar n.º 1893)**. Tiene una superficie de aproximadamente **13 ha** y se encuentra dentro de los límites del Hallasan, **Patrimonio Natural Mundial de la UNESCO y Reserva de la Biosfera** — es decir, un tramo donde se puede experimentar de forma ligera el valor UNESCO del Hallasan sin tener que ascender hasta la cima del Baengnokdam. \n\nEl humedal está formado por **más de 16 humedales y charcas de agua dulce** dispersos por la meseta, y se puede recorrer en un circuito a lo largo de una **pasarela de madera llana de aproximadamente 1 km (unos 20 minutos)**. La pasarela apenas tiene pendiente, por lo que pueden recorrerla con relativa facilidad incluso quienes llevan cochecito o tienen movilidad reducida. Alberga 3 especies de aves en peligro de extinción y 1 especie vegetal amenazada (de designación nacional), además de mamíferos, reptiles e insectos propios de Jeju, y los paneles informativos a lo largo de la pasarela explican la ecología del humedal. \n\nLa **Carretera 1100 (1100도로, inaugurada en 1973, de 36,6 km de longitud)** que conduce al humedal es la **carretera nacional que atraviesa el punto más alto de Corea**, y conecta de norte a sur la ciudad de Jeju con Jungmun, en Seogwipo. Al otro lado de la carretera, el **Área de Descanso 1100** cuenta con una tienda de conveniencia (GS25), una cafetería que vende bebidas calientes y ramen, un mirador y un parque que rinde homenaje a la **estatua del Ciervo Blanco (백록, Baekrok)** (la leyenda jejuana de un inmortal que subió al Hallasan a lomos de un ciervo blanco) y a **Go Sang-don, el primer coreano en coronar el Everest** — un buen lugar para descansar de 10 a 15 minutos. \n\nA 1.100 m de altitud la temperatura es **de 7 a 10 °C más baja** que en la costa, por lo que incluso en pleno verano hace falta una chaqueta ligera. En invierno, la pasarela cubierta de nieve y el humedal helado se convierten en uno de los escenarios de nieve más fotografiados de Jeju, pero la **Carretera 1100 es también la primera en cerrarse en caso de nevadas intensas, lluvias torrenciales o heladas** — en ese caso, el itinerario se sustituye por una atracción interior en la ciudad de Jeju (por ejemplo, el Museo Nacional de Jeju). \n\nTanto la entrada como el aparcamiento son **gratuitos**, y no se necesita reserva.", "image": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "highlights": ["**Humedal de Importancia Internacional de Ramsar n.º 1893** (inscrito en 2009) — dentro de los límites del Patrimonio Mundial de la UNESCO + Reserva de la Biosfera del Hallasan", "**Humedal de alta montaña a 1.100 m** — más de 16 humedales y charcas de agua dulce repartidos por la meseta", "**Pasarela de madera llana de aproximadamente 1 km** (unos 20 minutos) — relativamente accesible para cochecitos y personas con movilidad reducida", "**Carretera 1100** — inaugurada en 1973, 36,6 km, la carretera nacional que atraviesa el punto más alto de Corea", "Hábitat de **ecología propia de Jeju**: 3 especies de aves en peligro + 1 especie vegetal amenazada, entre otras", "Al otro lado de la carretera, el **Área de Descanso 1100** — estatua del Ciervo Blanco, parque de Go Sang-don, tienda, cafetería y mirador", "Temperatura **7-10 °C más baja** que en la costa — se recomienda chaqueta incluso en pleno verano", "**Escenario de nieve** en invierno (eso sí, con nevadas intensas la Carretera 1100 se cierra → sustitución por interior)", "**Entrada gratuita + aparcamiento gratuito**, sin necesidad de reserva"], "timeUsed": ["Aparcamiento + baño en el Área de Descanso 1100 — unos 5 min", "Un circuito por la pasarela del humedal — unos 20 min", "Mirador + foto en la estatua del Ciervo Blanco — unos 10 min", "Descanso / bebida en el área de descanso — unos 10 min"], "whyOnRoute": "**Punto de partida del circuito suroeste**. Desde la ciudad de Jeju se asciende por la Carretera 1100 hasta las tierras altas para experimentar de forma ligera la magnitud del Hallasan y su ecología de alta montaña, antes de bajar a la costa sur de Jungmun y continuar hacia Jusangjeolli y Cheonjeyeon. A diferencia de un ascenso a la cima o de senderos empinados, se trata de un **paseo llano por pasarela**, casi sin esfuerzo físico, que permite saborear a la vez un **humedal Ramsar + el Hallasan de la UNESCO**, gratis y sin reserva. El flujo de empezar en la montaña y bajar a la costa hace que el recorrido sea natural, y a primera hora la Carretera 1100 está relativamente tranquila — en invierno, si la carretera se cierra, se sustituye por una atracción interior.", "_poi_meta": {"poi_key": "hallasan_1100_wetland", "kb_version": "1.29", "verified_date": "2026-06-23", "sources": ["Ramsar Sites Information Service — Site #1893 (Hallasan 1100 Altitude Wetland)", "Hallasan National Park official site (hallasan.go.kr)", "UNESCO WHC inscription 1264 (Jeju Volcanic Island and Lava Tubes, 2007)", "VisitKorea — 1100 Altitude Wetland (1100-goji)", "Jeju Special Self-Governing Province — Wetland Protected Area records"]}, "visitBasics": {"hours": "Pasarela del humedal abierta 24 horas (gratis); cafetería y tienda del Área de Descanso 1100 aproximadamente de 09:00 a 17:00", "closed": "Abierto todo el año, pero la Carretera 1100 puede cerrarse con nevadas intensas o lluvias torrenciales — compruebe el estado de la carretera antes de visitar en invierno", "admission": "Gratuito (humedal Ramsar, sin entrada ni tarifa de aparcamiento)", "walking": "Muy fácil — un circuito por una pasarela de madera llana de aproximadamente 1 km, de 15 a 20 min; apto para cochecitos y para la mayoría de niveles de movilidad"}, "convenience": {"restroom": "Baños en el Área de Descanso 1100, al otro lado de la carretera", "parking": "Aparcamiento gratuito del área de descanso (puede congestionarse los fines de semana con nieve)"}, "smartNotes": {"photo": "La composición más representativa es la pasarela de madera cruzando las charcas de agua dulce con el Hallasan al fondo, y el paisaje nevado de invierno es una de las escenas más fotografiadas de Jeju. La estatua del Ciervo Blanco del área de descanso también es un punto fotográfico popular.", "facilities": "Al otro lado de la carretera, el Área de Descanso 1100 reúne tienda, cafetería, mirador y baños.", "tip": "Incluso en pleno verano, a 1.100 m de altitud hace de 7 a 10 °C menos que en la costa, así que lleve una chaqueta ligera. En invierno la Carretera 1100 es la primera en cerrarse, por lo que conviene comprobar el estado de la carretera; si está cerrada, se sustituye por una atracción interior."}, "images": ["/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp"], "imageCredits": [{"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "source": "atoc-korea"}, {"url": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-21.webp", "location": "Tierras Altas 1100 de Hallasan", "caption": "Tierras Altas 1100 de Hallasan — photo 1", "alt": "Tierras Altas 1100 de Hallasan — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-22.webp", "location": "Tierras Altas 1100 de Hallasan", "caption": "Tierras Altas 1100 de Hallasan — photo 2", "alt": "Tierras Altas 1100 de Hallasan — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/hallasan-1100/kakaotalk-20260510-230009595-23.webp", "location": "Tierras Altas 1100 de Hallasan", "caption": "Tierras Altas 1100 de Hallasan — photo 3", "alt": "Tierras Altas 1100 de Hallasan — gallery image 3"}]}, {"number": 2, "time": "11:00", "duration": "45 min", "name": "Acantilado Daepo Jusangjeolli", "category": "Costa Volcánica — Lava con Disyunción Columnar Hexagonal", "description": "**Daepo Jusangjeolli (대포 주상절리, ''Jisatgae'')** es un **tramo de 1 km de acantilado de basalto con disyunción columnar hexagonal** en la costa de Jungmun — declarado **Monumento Natural n.º 443 el 06-01-2005**. \n\nLas columnas se elevan entre **30 y 40 m** sobre el mar, agrupadas en **polígonos de 5 a 7 lados** encajados con precisión (principalmente hexágonos) — una geometría producida cuando **la lava basáltica fundida procedente de una erupción en el flanco del Hallasan (hace ~250.000–140.000 años) alcanzó el océano y se contrajo al enfriarse**, fracturándose perpendicularmente a la superficie de enfriamiento. \n\nA nivel mundial, la disyunción columnar es más conocida en la **Calzada del Gigante (Reino Unido)**, **Devils Postpile (EE. UU.)** y **la Cueva de Fingal (Escocia)** — Jusangjeolli es el **ejemplo más destacado del este de Asia** y el más accesible. \n\nEl **paseo marítimo en bucle de 800 m** lleva a los visitantes hasta el borde del acantilado con barandilla, directamente sobre las columnas; **en días de marea alta, las olas rompen contra las columnas y lanzan salpicaduras de hasta 20 m**, ocasionalmente por encima de la barandilla. \n\nEntrada: **Adultos ₩2.000 / Jóvenes ₩1.000 / GRATIS menores de 7 años y mayores de 65**. El lugar forma parte del **Geoparque Global de Jeju (designado por la UNESCO en octubre de 2010)** — uno de los **13 geositios oficiales** de la isla, junto con Seongsan Ilchulbong, el Tubo de Lava Manjanggul y Suwolbong. \n\nLa plataforma superior del acantilado es **accesible** (sin barreras para sillas de ruedas y cochecitos). Tres miradores a lo largo del recorrido ofrecen distintos ángulos de las columnas: el **primer mirador** muestra las columnas de perfil (ideal para fotografiar la geometría hexagonal), el **mirador intermedio** ofrece una vista directa hacia abajo para apreciar los patrones superiores de las columnas, y el **mirador del fondo** captura el perfil costero de 1 km con el Hallasan de fondo en días despejados. \n\n**Ventana fotográfica óptima: 14:00–16:00**, cuando la luz solar del oeste ilumina las caras de las columnas frontalmente; las visitas al atardecer ofrecen composiciones en silueta, pero pierden el detalle de la textura de las columnas. Horario: **09:00–18:00 (última entrada 17:30)**, en funcionamiento todo el año.", "image": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "highlights": ["**Monumento Natural n.º 443** — declarado el **06-01-2005**, el monumento natural costero de Jeju designado más recientemente", "Las columnas se elevan entre **30 y 40 m**, agrupadas en **polígonos de 5 a 7 lados** (principalmente hexágonos) a lo largo de **1 km** de costa", "Formación: **la lava del flanco del Hallasan se enfrió en el mar hace ~250.000–140.000 años**, contrayéndose perpendicularmente a la superficie de enfriamiento", "**El sitio de disyunción columnar más destacado del este de Asia** — comparable a la Calzada del Gigante, Devils Postpile y la Cueva de Fingal", "**Salpicaduras de hasta 20 m en días de marea alta** — ventana para fotografiar las fuentes de olas", "**Paseo en bucle de 0,8 km**, ~15 min de caminata — plataforma sin barreras, accesible para sillas de ruedas y cochecitos", "Forma parte del **Geoparque Global de Jeju (UNESCO, octubre de 2010)** — 13 geositios en toda la isla", "Entrada **₩2.000 adultos / ₩1.000 jóvenes / GRATIS menores de 7 años y mayores de 65**", "La cumbre del Hallasan es visible al norte en días despejados, **directamente aguas arriba** desde el punto de vista geológico"], "timeUsed": ["Estacionamiento + compra de entradas + acceso — ~5 min", "Caminata hasta el primer mirador — ~5 min", "Observación de columnas al borde del acantilado + fotos — ~15 min", "Continuar el recorrido por el paseo marítimo — ~10 min", "Regreso al autobús — ~10 min"], "whyOnRoute": "**Punto geológico central del recorrido suroeste** — ubicado directamente aguas abajo del Hallasan tanto geográfica como geológicamente. Tras el origen en el Hallasan, Jusangjeolli muestra **la misma lava llegando al mar y solidificándose en columnas hexagonales de 30 a 40 m** a lo largo de 1 km de costa. Desde aquí, el tour se dirige **3 km al oeste hacia las Cataratas Cheonjeyeon** (en contraste con el tour paralelo que va hacia el este hasta Jeongbang) — manteniendo toda la tarde dentro del corredor suroeste de Jungmun + Andeok. En comparación con la **Costa de Yongmeori (cerrada ~el 30% de los días de visita por mareas o clima)** y **Songaksan (1,6 km más de caminata)**, Daepo ofrece **un recorrido con cualquier clima, sin barreras y de 15 minutos** — el mayor rendimiento por minuto en la costa sur. El horario de media mañana también permite llegar antes de la afluencia de cruceros de mediodía.", "_poi_meta": {"poi_key": "daepo_jusangjeolli_cliff", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Cultural Heritage Administration — Natural Monument No. 443 designation (2005-01-06)", "Jeju Global Geopark official site (geopark.jeju.go.kr)", "UNESCO Global Geoparks Network — Jeju (2010 designation)", "VisitJeju — Daepo Jusangjeolli", "Korea Geological Survey — Jeju basalt formation studies"]}, "visitBasics": {"hours": "09:00–18:00 (última entrada 17:40)", "closed": "Abierto todo el año", "admission": "KRW 2.000 adultos / KRW 1.000 niños y adolescentes", "walking": "Fácil"}, "convenience": {"restroom": "Área de la entrada", "parking": "Estacionamiento de pago"}, "smartNotes": {"photo": "Un ligero ángulo lateral generalmente capta mejor la textura del basalto y la energía de las olas que una toma frontal.", "facilities": "Las instalaciones son sencillas, pero el área de entrada es práctica y suficiente.", "tip": "Dado que el viento y la bruma marina pueden cambiar rápidamente el ambiente de la parada, funciona mejor con un ritmo constante."}, "images": ["/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "/images/tours/jusangjeolli/photo-005.webp"], "imageCredits": [{"url": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "source": "atoc-korea"}, {"url": "/images/tours/jusangjeolli/photo-005.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/jusangjeolli/chatgpt-image-2026-2-15-10-01-04.webp", "location": "Acantilado Daepo Jusangjeolli", "caption": "Acantilado Daepo Jusangjeolli — photo 1", "alt": "Acantilado Daepo Jusangjeolli — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-11.webp", "location": "Acantilado Daepo Jusangjeolli", "caption": "Acantilado Daepo Jusangjeolli — photo 2", "alt": "Acantilado Daepo Jusangjeolli — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-12.webp", "location": "Acantilado Daepo Jusangjeolli", "caption": "Acantilado Daepo Jusangjeolli — photo 3", "alt": "Acantilado Daepo Jusangjeolli — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/jusangjeolli/kakaotalk-20260510-230028438-13.webp", "location": "Acantilado Daepo Jusangjeolli", "caption": "Acantilado Daepo Jusangjeolli — photo 4", "alt": "Acantilado Daepo Jusangjeolli — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/jusangjeolli/photo-005.webp", "location": "Acantilado Daepo Jusangjeolli", "caption": "Acantilado Daepo Jusangjeolli — photo 5", "alt": "Acantilado Daepo Jusangjeolli — gallery image 5"}]}, {"number": 3, "time": "12:00", "duration": "70 min", "name": "Cascada Cheonjeyeon", "category": "Cascada de Tres Niveles + Bosque — ''Estanque del Emperador del Cielo''", "description": "**Cascadas Cheonjeyeon (천제연, ''연 = estanque + 천제 = Emperador del Cielo'')** es una **cascada de tres niveles** en la garganta volcánica de Jungmun, designada **Monumento Natural n.º 378 (1993)** por su singular combinación ecológica. \n\nEl nombre proviene de una **leyenda taoísta de la era Joseon que narra cómo siete ninfas (선녀, *seonnyeo*) descendían del cielo cada noche para bañarse en el estanque superior** — un mito reforzado por el microclima de niebla perpetua del dramático enclave. \n\nEl **primer nivel (caída de 22 m, estanque de 21 m de profundidad)** cae en un caldero circular de basalto y solo fluye tras lluvias intensas — la mayoría de los días el estanque superior permanece quieto y reflectante. \n\nEl **segundo nivel (caída de 30 m) fluye todo el año** — el principal sujeto fotográfico. El tercer nivel completa el descenso hasta el mar. El **Puente Seonimgyo (선임교, ''Puente de las Siete Ninfas''), de 120 m de longitud y 78 m de altura**, cruza la garganta a mitad del recorrido circular — sus paneles de relieve en bronce fundido a ambos lados representan **las siete ninfas en pleno vuelo**, una realización arquitectónica literal de la leyenda fundacional. \n\nEl bosque circundante es un **hábitat de plantas raras** que incluye el **lirio sapo coreano (***Tricyrtis macropoda***)** y el amenazado **helecho Mankyua chejuense** (endémico de Jeju, En Peligro Crítico según la UICN). Longitud del circuito: **0,8 km, ~30 min a pie** con varias secciones de escalones pronunciados. \n\nEntrada: **Adultos ₩2.500 / Jóvenes ₩1.350 / GRATUITO menores de 7 años y mayores de 65**. Cheonjeyeon también pertenece al canon literato de la época Joseon **''Yeongjusipgyeong (영주십경, las 10 Maravillas Escénicas de Jeju)''** — junto con la cima del Hallasan, el Amanecer de Seongsan y las Cascadas de Jeongbang — lo que significa que el circuito suroeste de hoy cubre **2 de las 10 (Hallasan + Cheonjeyeon)** en un solo día. \n\nEl bienal **Festival Jeju Chilseonyeo (Siete Ninfas)**, celebrado en el puente en mayo (cada año impar), recrea la leyenda del descenso con danza tradicional y actuaciones musicales — se requieren reservas cuando el festival coincide con una fecha de visita. Horario: **09:00–18:00** todo el año (última entrada 17:30).", "image": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "highlights": ["**Monumento Natural n.º 378 (designado en 1993)** — cascada de tres niveles + hábitat de plantas raras", "El nombre **''Cheonjeyeon'' = ''Estanque del Emperador del Cielo''** — leyenda taoísta de la era Joseon", "La **leyenda de las Siete Ninfas (선녀)** esculpida en los paneles de relieve del **Puente Seonimgyo (120 m × 78 m)**", "**Primer nivel (22 m / estanque de 21 m)** — solo fluye tras lluvias intensas; **segundo nivel (30 m) fluye todo el año**", "Hábitat del **helecho Mankyua chejuense** — endémico de Jeju, En Peligro Crítico según la UICN", "**Circuito de 0,8 km / ~30 min** — escalones moderados, el calzado es importante", "Entrada **₩2.500 adultos / ₩1.350 jóvenes / GRATUITO menores de 7 años y mayores de 65**", "**Festival Jeju Chilseonyeo (Siete Ninfas)** celebrado bienalmente en el lugar — ceremonia en el puente", "**Microclima de niebla** — refrigeración natural, popular refugio vespertino en verano"], "timeUsed": ["Entrada + taquilla — ~5 min", "Descenso hasta la plataforma de observación del primer nivel — ~10 min", "Fotografía del primer y segundo nivel — ~20 min", "Puente Seonimgyo + paneles de relieve de las ninfas — ~15 min", "Circuito forestal + ascenso de regreso al autocar — ~25 min"], "whyOnRoute": "**Ancla de contraste de media tarde** — tras la amplia panorámica alpina del Hallasan y la costa expuesta de Jusangjeolli, la garganta forestal cerrada de Cheonjeyeon restablece el registro sensorial y ofrece un descanso a la sombra. La leyenda de las Siete Ninfas + el Puente Seonimgyo = el **ancla mitológica** más potente de Jeju en el catálogo (frente al legado de rodajes de K-dramas de Seopjikoji o la narrativa geológica de Seongsan). La ubicación en Jungmun supone **5 min en autocar desde Jusangjeolli y 10 min en autocar hasta Osulloc** — la ventana de tránsito de mediodía más ajustada del turismo por el suroeste de Jeju. La llegada a las 13:00 también coincide con **la cobertura nubosa de después del mediodía que suaviza la luz cenital** para la fotografía de dosel y cascadas.", "_poi_meta": {"poi_key": "cheonjeyeon_falls", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Cultural Heritage Administration — Natural Monument No. 378 (1993 designation)", "VisitJeju — Cheonjeyeon Pokpo official listing", "Korea National Arboretum — Mankyua chejuense conservation records", "Jeju Cultural Foundation — Seven Nymphs Festival history", "Seogwipo City tourism — Cheonjeyeon admission and access"]}, "visitBasics": {"hours": "09:00–17:50 (última entrada 17:10)", "closed": "Abierto todo el año", "admission": "KRW 2.500 adultos / KRW 1.350 adolescentes y niños", "walking": "Moderado, con escalones y tramos a veces mojados"}, "convenience": {"restroom": "Zona de entrada", "parking": "Aparcamiento disponible"}, "smartNotes": {"photo": "En lugar de forzar todo en un solo encuadre, las composiciones en capas con el puente y la cascada suelen quedar mejor.", "facilities": "Las instalaciones básicas se concentran cerca de la entrada.", "tip": "Debido a los escalones y los posibles tramos resbaladizos, avanzar a un ritmo tranquilo suele hacer esta parada más agradable."}, "images": ["/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "/images/tours/cheonjeyeon-falls/photo-004.webp"], "imageCredits": [{"url": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "source": "atoc-korea"}, {"url": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "source": "atoc-korea"}, {"url": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "source": "atoc-korea"}, {"url": "/images/tours/cheonjeyeon-falls/photo-004.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-04.webp", "location": "Cascada Cheonjeyeon", "caption": "Cascada Cheonjeyeon — photo 1", "alt": "Cascada Cheonjeyeon — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-07.webp", "location": "Cascada Cheonjeyeon", "caption": "Cascada Cheonjeyeon — photo 2", "alt": "Cascada Cheonjeyeon — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/kakaotalk-20260510-230009595-08.webp", "location": "Cascada Cheonjeyeon", "caption": "Cascada Cheonjeyeon — photo 3", "alt": "Cascada Cheonjeyeon — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/cheonjeyeon-falls/photo-004.webp", "location": "Cascada Cheonjeyeon", "caption": "Cascada Cheonjeyeon — photo 4", "alt": "Cascada Cheonjeyeon — gallery image 4"}]}, {"number": 4, "time": "13:15", "duration": "60 min", "name": "Almuerzo — Seogwipo / Jungmun", "category": "Pausa del mediodía — gastronomía local de Seogwipo / Jungmun", "description": "**Pausa de 60 minutos entre la Cascada Cheonjeyeon y O''Sulloc** — el distrito turístico de Jungmun queda cerca de ambos lugares y concentra una zona de restaurantes que atiende tanto a turistas como a locales. Rotación básica del menú según la temporada y el grupo: **pez sable estofado (갈치조림)** en un especialista de la zona de Seogwipo cuando los barcos faenan (de septiembre a febrero), **bibimbap de abulón (전복비빔밥)** durante todo el año, o **cerdo negro (흑돼지, BBQ de cerdo negro de Jeju)** para los clientes que prefieren carne a la parrilla. \n\nEl cerdo negro de Jeju (***Sus scrofa* domesticus, variedad Jeju**) es una raza protegida designada **Material del Patrimonio Cultural n.º 5 (2015)**, rastreable hasta registros de aproximadamente el siglo XII. Alternativa vegetariana (bajo petición): **bibim-guksu** con verduras de temporada de Jeju. Hay **opciones aptas para halal** (con ingredientes declarados) en uno de los restaurantes de la rotación — solicítelo en el momento de la recogida. Tras el almuerzo, el autobús tarda unos 25 minutos hasta O''Sulloc.", "image": null, "highlights": ["Zona de restaurantes de **Jungmun** — a 3 km de Jusangjeolli y Cheonjeyeon", "**Galchi-jorim** en temporada (sep–feb), **jeonbok-bibimbap** durante todo el año", "Opción **Heuk-doeji (cerdo negro de Jeju)** — Material del Patrimonio Cultural N.º 5 (2015)", "Opciones **aptas para halal + vegetarianas** (solicitar al momento de recogida)", "Desde el restaurante, **5 min en autobús hasta Cheonjeyeon** — trayecto mínimo tras la comida", "Los requisitos dietéticos del grupo se recogen al momento de la recogida; menú confirmado previamente"], "timeUsed": ["Autobús al restaurante — ~5 min", "Pedido + comida — ~45 min", "Autobús hasta la entrada de Cheonjeyeon — ~5 min", "Margen de tiempo — ~5 min"], "whyOnRoute": "La ubicación en Jungmun implica **trayectos de 5 minutos tanto a Jusangjeolli (antes) como a Cheonjeyeon (después)** — recupera ~15 min frente a un almuerzo en el centro de Seogwipo. El pez sable + el cerdo negro + el abulón son las tres proteínas emblemáticas de Jeju, todas de origen local — los visitantes obtienen el referente gastronómico del día en una sola comida, antes de la secuencia de té + café de la tarde, que es ligera en alimentos sólidos.", "visitBasics": {"hours": "Depende del restaurante", "closed": "Varía según el local", "admission": "Puede estar incluido según las condiciones del producto, o pagarse en el lugar", "walking": "Mínimo"}, "convenience": {"restroom": "Dentro del restaurante", "parking": "Estacionamiento disponible"}, "smartNotes": {"photo": "Si deseas fotos de galería al estilo lifestyle, las fotografías de comida funcionan especialmente bien aquí.", "facilities": "Las instalaciones del comedor son más que suficientes.", "tip": "Un almuerzo más tranquilo suele mejorar la segunda mitad del día más que ahorrar unos minutos extra."}}, {"number": 5, "time": "14:35", "duration": "70 min", "name": "Museo del Té O''Sulloc", "category": "Cultura del Té y Plantación de Seogwang — Patrimonio AmorePacific", "description": "**El Museo del Té O''Sulloc (오설록 티 뮤지엄, ''오설록'' significa ''encuentro de nieve + verde'')** es el buque insignia de la cultura del té de **Amorepacific Corporation** — la mayor empresa de cosmética de Corea. \n\nEl fundador **Suh Sung-whan impulsó personalmente el proyecto en 1979**, recuperando tierras de cultivo de ceniza volcánica en la meseta de Seogwang de Jeju cuando el consenso general sostenía que el té no podía cultivarse comercialmente en Corea. Hoy, la **plantación Seogwang Dawon (서광다원)** es el **mayor campo de té verde de Corea**, con una producción de **~700 toneladas anuales** en las tres fincas de Jeju de Amorepacific. \n\nEl edificio del museo **abrió en 2001** en el corazón de la plantación y fue incluido en el **Top 10 de museos de arte de designboom** por su diseño de pabellón minimalista con cubierta verde en medio de las hileras de té. \n\n**Entrada gratuita**, todos los días de **09:00 a 18:00**, con ~**2 millones de visitantes anuales**. La visita se divide naturalmente en tres segmentos: **(1) Interior del museo** — proceso de producción del té, colección de utensilios de té antiguos desde la dinastía Tang (618–907 d. \n\nC.) en adelante, y terraza de observación con vista panorámica de la plantación; **(2) Cafetería Tea House** — el emblemático **bizcocho enrollado de té verde (오설록 롤케이크)** y **helado de té verde** elaborados directamente con la cosecha de hojas de ese año; **(3) Senderos por la plantación** — hileras de gravilla entre los arbustos de té, populares para fotografía al atardecer en el borde occidental. \n\nLa **Casa Innisfree Jeju** (marca de cosmética natural de Amorepacific) se encuentra a **5 minutos a pie** para los visitantes interesados en el ecosistema más amplio de la marca — también con entrada gratuita y taller opcional de elaboración de jabón de mandarina (₩15.000). \n\nEl propio edificio del museo, diseñado por el arquitecto coreano **Mass Studies (Cho Min-suk)**, adopta una forma horizontal deliberadamente discreta que refleja la geometría de las hileras de té en lugar de competir con el paisaje agrícola — una deferencia arquitectónica que le valió tanto la inclusión en el Top 10 de designboom como su uso continuado como caso de estudio en el diseño de museos contemporáneos coreanos. \n\nComplemento opcional: la **Clase de Té Osulloc (₩30.000 por persona, 60 min, reserva anticipada obligatoria)** — cata guiada de té con demostración de técnica de preparación en cerámica coreana, disponible todos los días de **10:00 a 16:00**, con instrucción en inglés en las sesiones de miércoles y sábado.", "image": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "highlights": ["Buque insignia de **Amorepacific** — la mayor empresa de cosmética de Corea; el fundador Suh Sung-whan impulsó el cultivo del té en Jeju en **1979**", "**Seogwang Dawon = el mayor campo de té verde de Corea**; producción anual de ~700 toneladas", "Museo **inaugurado en 2001** — clasificado entre los 10 mejores museos de arte por designboom (arquitectura)", "**Entrada gratuita**, todos los días **09:00–18:00**, ~2 millones de visitantes anuales", "Colección de utensilios de té antiguos que abarca desde la **dinastía Tang (618–907 d. C.)** hasta la cerámica coreana moderna del período Joseon", "**Pastel enrollado de té verde** + **helado de té verde** = productos estrella de la cafetería", "**Innisfree Jeju House** a 5 minutos a pie — entrada gratuita, taller opcional de jabón de mandarina ₩15.000", "Los senderos por la plantación son **mejores durante la hora dorada (16:00–17:00)** para fotografía", "La terraza en la azotea y las hileras a nivel del suelo ofrecen dos elevaciones distintas para composiciones fotográficas entre filas de té"], "timeUsed": ["Aparcamiento + entrada — ~5 min", "Interior del museo + colección de utensilios de té — ~20 min", "Cafetería Tea House (pastel enrollado + helado) — ~20 min", "Sendero por la plantación — ~20 min", "Visita opcional a Innisfree Jeju House — ~10 min"], "whyOnRoute": "**Transición cultural de los puntos naturales a la vida cotidiana de Jeju**. Hallasan + Jusangjeolli + Cheonjeyeon son la identidad geológica de Jeju; Osulloc es la **identidad de marca moderna** de Jeju — la prueba visible de que la ceniza volcánica + 1.500 mm de lluvia anual + la inversión hortícola coreana pueden construir una industria tetera de exportación mundial. **Entrada gratuita + 2 millones de visitantes/año** = el punto de interior de menor fricción en el suroeste de Jeju; refugio interior perfecto si el día se vuelve lluvioso tras Cheonjeyeon. La ubicación en la meseta de Seogwang es también el **eje geográfico entre las atracciones de la costa sur y el noroeste de Aewol** — punto natural de parada a media tarde. En comparación con **Hallim Park (jardín botánico, ₩15.000, experiencia más dispersa)** o **Camellia Hill (₩9.000, ventana estacional reducida)**, Osulloc es **gratuito, disponible todo el año y con identidad de marca propia** — la parada de interior con mayor rentabilidad en este corredor.", "_poi_meta": {"poi_key": "osulloc_tea_museum", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Amorepacific corporate history (amorepacific.com)", "O''sulloc Tea Museum official site (osulloc.com)", "designboom Top 10 art museums archival listing", "Korea Tea Industry Association — production statistics", "VisitJeju — Osulloc Tea Museum"], "image": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "images": ["/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp"], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "Museo del Té O''sulloc", "alt": "Museo del Té O''sulloc — imagen de galería 1", "caption": "Museo del Té O''sulloc — foto 1"}, {"id": 2, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "Museo del Té O''sulloc", "alt": "Museo del Té O''sulloc — imagen de galería 2", "caption": "Museo del Té O''sulloc — foto 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "Museo del Té O''sulloc", "alt": "Museo del Té O''sulloc — imagen de galería 3", "caption": "Museo del Té O''sulloc — foto 3"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "Museo del Té O''sulloc", "alt": "Museo del Té O''sulloc — imagen de galería 4", "caption": "Museo del Té O''sulloc — foto 4"}], "imageCredits": [{"url": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "source": "atoc-korea"}]}, "visitBasics": {"hours": "Generalmente 09:00–18:00, con posibles variaciones estacionales", "closed": "Abierto todo el año", "admission": "Gratuito", "walking": "Fácil"}, "convenience": {"restroom": "Área del museo y la cafetería", "parking": "Aparcamiento disponible"}, "smartNotes": {"photo": "Las vistas amplias del campo de té y los ángulos laterales cerca de la cafetería suelen ofrecer mejores fotografías que los primeros planos de producto por sí solos.", "facilities": "Con aseos, bebidas y zonas para sentarse, esta es una de las paradas más cómodas en la segunda mitad del día.", "tip": "Por lo general resulta más satisfactorio disfrutar tanto del paisaje como del ambiente de la cafetería que recorrer el museo apresuradamente."}, "images": ["/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp"], "imageCredits": [{"url": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "source": "atoc-korea"}, {"url": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-sign-couple-20260521.webp", "location": "Museo del Té O''sulloc", "alt": "Museo del Té O''sulloc — imagen de galería 1", "caption": "Museo del Té O''sulloc — foto 1"}, {"id": 2, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-museum-interior-20260511.webp", "location": "Museo del Té O''sulloc", "alt": "Museo del Té O''sulloc — imagen de galería 2", "caption": "Museo del Té O''sulloc — foto 2"}, {"id": 3, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-tea-fields-20260511.webp", "location": "Museo del Té O''sulloc", "alt": "Museo del Té O''sulloc — imagen de galería 3", "caption": "Museo del Té O''sulloc — foto 3"}, {"id": 4, "type": "photo", "src": "/images/tours/osulloc-tea/osulloc-aerial-20260511.webp", "location": "Museo del Té O''sulloc", "alt": "Museo del Té O''sulloc — imagen de galería 4", "caption": "Museo del Té O''sulloc — foto 4"}]}, {"number": 6, "time": "16:15", "duration": "55 min", "name": "Calle de Cafés de Aewol (Sendero Costero Handam)", "category": "Calle de cafeterías de la costa — cafetería de tarde + tramo 15A del Olle Trail", "description": "**La Calle de Cafés de Aewol (애월 카페거리)** es el **tramo costero de 5 km de Aewol-eup a lo largo del Sendero Costero Handam (한담해안산책로)** en la costa noroeste de Jeju — el destino de **''cafés con vistas al mar''** más concentrado de Corea, con más de 30 cafés de diseño vanguardista apiñados en la franja al borde del acantilado entre la playa de Handam y la playa de Gwakji. \n\nEl paseo marítimo recibe el nombre oficial de **Paseo Jang Han Chul (장한철산책로)** en honor a **Jang Han Chul (장한철, 1744–?)** — un erudito del período Joseon nacido en Jeju cuyo **''Pyohaerok (표해록)''** es uno de los primeros relatos coreanos de supervivencia en el mar, escrito tras su deriva por el Pacífico en 1771. \n\nEl sendero es un **segmento costero de 30 minutos (solo ida) del Sendero Olle de Jeju 15A (Hallim → Gonae)** — acantilados de basalto negro, pozas de marea, junturas hexagonales a menor escala que en Daepo y un horizonte despejado orientado al oeste = la franja de observación del atardecer por excelencia en Jeju. \n\n**Cafés destacados por temporada**: **Bomnal Cafe (봄날 카페)** — apareció en el **dorama coreano de 2014 ''You Who Came From the Stars (별에서 온 그대)''** y convirtió Aewol de la noche a la mañana en un destino de peregrinación de celebridades; **Randy''s Donuts** (marca de Los Ángeles, franquicia coreana — gran terraza en la azotea); **Cafe Knotted** (donut de crema estrella + vistas al mar); **Haejigae Cafe** (literalmente ''café del atardecer'', dedicado al servicio vespertino); **Aewol the Sunset** (terraza en la azotea, precios premium). \n\nAcceso **gratuito** al sendero y las playas; precios en cafés: habitualmente ₩6.000–12.000 por bebida + postre. El **''Pyohaerok (표해록)''** de Jang Han Chul — la fuente del nombre del paseo — está considerado uno de los textos fundacionales de la **literatura marítima coreana**, en el que narra su deriva de 29 días por el Pacífico tras que un barco con destino a Jeju fuera desviado de su rumbo en **diciembre de 1770**. \n\nRescatado por pescadores de Ryukyu (actual Okinawa) y devuelto finalmente a su hogar vía Nagasaki, su relato precede en décadas a memorias de supervivencia occidentales similares e informa la historiografía oceánica coreana moderna. \n\nLa señalización del paseo a lo largo del acantilado cita fragmentos de la obra en coreano e inglés — un infrecuente marcador de patrimonio literario in situ. Nota para **aficionados a la fotografía**: el uso de drones en la costa de Aewol está permitido **fuera del corredor de aproximación de 9 km del Aeropuerto Internacional de Jeju** — confirme el perímetro exacto mediante la aplicación Korea Drone Map antes de volar. \n\nEl **segmento del Sendero Olle 15A** recorre oficialmente el Puerto de Hallim → Aewol → Puerto de Gonae a lo largo de 13 km; el recorrido de hoy cubre el tramo central de 1,5 km entre Handam y Gwakji.", "image": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "highlights": ["**Franja costera de cafés de 5 km** entre las playas de Handam y Gwakji — la hilera de cafés con vistas al mar más densa de Corea", "**Paseo Jang Han Chul** — nombrado en honor al erudito joseonés nacido en Jeju (1744–?) y autor de las memorias de supervivencia **''Pyohaerok''**", "Segmento del **Sendero Olle 15A** (Hallim → Gonae) — paseo costero de 30 minutos (solo ida)", "**Bomnal Cafe (봄날 카페)** = Lugar de rodaje de **''You Who Came From the Stars'' (2014, SBS)**", "Cafés destacados rotativos: **Randy''s Donuts**, **Cafe Knotted**, **Haejigae Cafe**, **Aewol the Sunset**", "**Horizonte orientado al oeste** = vistas de puesta de sol sin obstáculos — **17:30–18:30 en primavera/otoño**", "**Juntas hexagonales visibles** en los acantilados de Handam — misma geología que Daepo, a menor escala", "Sendero costero + playas **GRATIS**; cafés ~₩6,000–12,000 por bebida + postre", "**40 minutos en autobús desde el Aeropuerto Internacional de Jeju** — última parada viable antes de los vuelos nocturnos"], "timeUsed": ["Llegada del autobús + aparcamiento en Handam — ~5 min", "Paseo por el sendero costero (Handam → sección intermedia) — ~20 min", "Parada en el café seleccionado (bebida + postre) — ~30 min", "Fotografía del atardecer en lo alto del acantilado — ~15 min", "Regreso caminando al autobús — ~5 min"], "whyOnRoute": "**Final anclado en el atardecer.** El circuito suroeste termina deliberadamente en Aewol porque: (1) **horizonte orientado al oeste** = el único punto del recorrido del día con puesta de sol sin obstáculos; (2) **40 minutos en autobús hasta el Aeropuerto de Jeju** = última parada viable antes de los vuelos nocturnos sin dar marcha atrás; (3) **alternativa interior con alta densidad de cafés** = si el tiempo empeora, los visitantes pasan del paseo costero a los asientos interiores del café sin abandonar el lugar. En comparación con el tour gemelo de puntos destacados que termina en **Seongsan Sunrise Peak (costa este, anclado al amanecer y no al atardecer)**, Aewol = **final de estilo de vida**, Seongsan = **final UNESCO** — temperamentos distintos, itinerarios complementarios. La llegada a las 15:50 está calibrada para la **ventana de puesta de sol de primavera/otoño de 17:30–18:30** — los visitantes disponen de ~75 min para recorrer el sendero, acomodarse en un café y fotografiar el atardecer desde la terraza del acantilado antes de regresar en autobús a la ciudad de Jeju.", "_poi_meta": {"poi_key": "aewol_cafe_street", "kb_version": "1.18", "verified_date": "2026-04-29", "sources": ["Jeju Olle Foundation — Trail 15A official map (Hallim → Gonae)", "Aewol-eup Cultural Office — Jang Han Chul historical records", "VisitJeju — Aewol Cafe Street", "SBS Drama Archive — ''You Who Came From the Stars'' filming locations", "Joseon Wangjo Sillok / Korean Folklore Society — Pyohaerok textual study"]}, "visitBasics": {"hours": "La zona en sí está abierta todo el día; cada café tiene su propio horario", "closed": "No hay día de cierre para la zona en su conjunto", "admission": "Gratis", "walking": "Fácil"}, "convenience": {"restroom": "Depende del café que elijas", "parking": "Aparcamiento disponible en la zona"}, "smartNotes": {"photo": "La contraluz de última hora de la tarde y las terrazas con vistas al mar suelen crear las mejores imágenes aquí.", "facilities": "La comodidad depende del café elegido, por lo que una operación flexible funciona mejor que fijar un solo establecimiento de manera demasiado rígida.", "tip": "Esta parada suele recibir mejor puntuación cuando se permite a los visitantes un ritmo más libre en lugar de ser guiados con demasiada rigidez."}, "images": ["/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp"], "imageCredits": [{"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "source": "atoc-korea"}, {"url": "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-24.webp", "location": "Calle de Cafés de Aewol (Sendero Costero Handam)", "caption": "Calle de Cafés de Aewol (Sendero Costero Handam) — photo 1", "alt": "Calle de Cafés de Aewol (Sendero Costero Handam) — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-25.webp", "location": "Calle de Cafés de Aewol (Sendero Costero Handam)", "caption": "Calle de Cafés de Aewol (Sendero Costero Handam) — photo 2", "alt": "Calle de Cafés de Aewol (Sendero Costero Handam) — gallery image 2"}, {"id": 3, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-26.webp", "location": "Calle de Cafés de Aewol (Sendero Costero Handam)", "caption": "Calle de Cafés de Aewol (Sendero Costero Handam) — photo 3", "alt": "Calle de Cafés de Aewol (Sendero Costero Handam) — gallery image 3"}, {"id": 4, "type": "photo", "src": "/images/tours/aewol-cafe-street/kakaotalk-20260510-230009595-27.webp", "location": "Calle de Cafés de Aewol (Sendero Costero Handam)", "caption": "Calle de Cafés de Aewol (Sendero Costero Handam) — photo 4", "alt": "Calle de Cafés de Aewol (Sendero Costero Handam) — gallery image 4"}, {"id": 5, "type": "photo", "src": "/images/tours/aewol-cafe-street/chatgpt-image-2026-5-11-01-14-08.webp", "location": "Calle de Cafés de Aewol (Sendero Costero Handam)", "caption": "Calle de Cafés de Aewol (Sendero Costero Handam) — photo 5", "alt": "Calle de Cafés de Aewol (Sendero Costero Handam) — gallery image 5"}]}, {"number": 7, "time": "17:30", "duration": "45 min", "name": "Playa de Iho Tewoo (faros con forma de poni · atardecer)", "category": "Playa de la ciudad de Jeju — faros con forma de poni + final al atardecer", "description": "La **Playa de Iho Tewoo (이호테우해변, Playa de Iho)** es la playa más cercana al centro de la ciudad de Jeju y al Aeropuerto Internacional de Jeju, y constituye el tramo del **final al atardecer** que cierra la jornada. Su atractivo más emblemático son los dos **faros con forma de poni (말 등대)** que se alzan enfrentados sobre el rompeolas: un **faro rojo y un faro blanco de unos 12 m de altura** con forma de poni de Jeju, situados respectivamente en el rompeolas exterior y en el interior — el blanco y el rojo son señales náuticas pintadas para que los barcos distingan babor y estribor, y junto al mar y el cielo azules se han convertido en uno de los mejores lugares de Jeju para una foto de recuerdo. \n\nLa playa está formada por una **arena fina de tonos plateados** mezclada con conchas y arena, y su suave pendiente atrae a muchas familias. Detrás de la playa hay un **bosque de pinos** que ofrece sombra y senderos, y durante la marea más baja, junto a la amplia franja de arena, puede verse un **wondam** — el wondam es un método de pesca tradicional de Jeju que aprovechaba la diferencia entre la pleamar y la bajamar para atrapar peces (una trampa de pesca tradicional de piedra), y en Iho Tewoo se conserva una versión restaurada llamada **Iho Mosalwon**. \n\nJusto al lado de la playa continúa la **Carretera Costera Arcoíris de Dodu-dong**, donde se pueden disfrutar de coloridos bloques de protección y de un paseo costero en coche, y su cercanía al aeropuerto la convierte en una **ubicación ideal para la última parada antes de tomar el vuelo de la tarde**. La entrada a la playa y a los senderos es **gratuita**.", "image": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "highlights": ["La **playa más cercana al centro de la ciudad de Jeju y al aeropuerto** — final al atardecer + traslado cómodo al aeropuerto", "Los emblemáticos **faros con forma de poni (말 등대)** — dos faros, uno rojo y uno blanco, de unos 12 m de altura, punto fotográfico estrella", "**Arena fina de tonos plateados** mezclada con conchas + pendiente suave — playa familiar", "**Bosque de pinos** con sombra y senderos detrás de la playa", "El **wondam (Iho Mosalwon)**, una instalación pesquera tradicional de Jeju que aflora con la marea baja", "Justo al lado, paseo costero en coche por la **Carretera Costera Arcoíris de Dodu-dong**", "**Entrada gratuita** — luz dorada a la hora del atardecer"], "timeUsed": ["Aparcamiento en la playa + desplazamiento — unos 5 min", "Paseo por los faros con forma de poni y el rompeolas + fotos — unos 20 min", "Contemplación del atardecer en la playa y la Carretera Costera Arcoíris — unos 15 min", "Reagrupación — unos 5 min"], "whyOnRoute": "**Final al atardecer de la jornada y última parada**. Situada en el camino de regreso hacia la ciudad de Jeju tras disfrutar de las cafeterías y la costa de Aewol, encaja de forma natural en el recorrido, y el horizonte despejado hacia el oeste junto con los faros con forma de poni cierran el día con un tono dorado. Su proximidad al Aeropuerto Internacional de Jeju la hace idónea como **última parada antes del drop-off o de tomar el vuelo de la tarde** — como la hora del atardecer varía según la temporada (más tarde en verano, más temprano en invierno), la hora de llegada se ajusta al ocaso de cada día.", "_poi_meta": {"poi_key": "iho_tewoo_beach", "kb_version": "raw-2026", "verified_date": "2026-06-23", "sources": ["VisitKorea — Iho Tewoo Beach (이호테우해변)", "VisitKorea — Iho Tewoo Horse Lighthouses (이호테우 말 등대)", "Jeju Tourism Organization", "Jeju City official tourism data"]}, "visitBasics": {"hours": "Playa y senderos abiertos 24 horas (gratis); visita a la hora del atardecer", "closed": "Abierto todo el año", "admission": "Gratuito (sin entrada ni tarifa de aparcamiento)", "walking": "Fácil — paseo llano por la arena y el rompeolas, unos 15-20 min"}, "convenience": {"restroom": "Baños públicos de la playa", "parking": "Aparcamiento gratuito (congestionado los fines de semana de temporada alta)"}, "smartNotes": {"photo": "Captar los faros rojo y blanco con forma de poni desde el extremo del rompeolas resulta lo más impactante, y la silueta a contraluz a la hora del atardecer junto con la Carretera Costera Arcoíris son composiciones muy populares.", "facilities": "Los alrededores de la playa cuentan con cafeterías, restaurantes y buenos servicios.", "tip": "Como la hora del atardecer varía según la estación (verano hacia las 19:30, primavera y otoño hacia las 18:30, invierno hacia las 17:40), la hora de llegada se ajusta al ocaso de cada día. Al estar cerca del aeropuerto, es una buena última parada antes del vuelo de la tarde."}, "images": ["/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp"], "imageCredits": [{"url": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "source": "atoc-korea"}, {"url": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp", "source": "atoc-korea"}], "galleryItems": [{"id": 1, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-13.webp", "location": "Playa de Iho Tewoo", "caption": "Playa de Iho Tewoo — photo 1", "alt": "Playa de Iho Tewoo — gallery image 1"}, {"id": 2, "type": "photo", "src": "/images/tours/iho-teu/chatgpt-image-2026-5-9-01-17-19.webp", "location": "Playa de Iho Tewoo", "caption": "Playa de Iho Tewoo — photo 2", "alt": "Playa de Iho Tewoo — gallery image 2"}]}], "routeFlowStops": [{"name": "Tierras Altas 1100", "theme": "Hallasan", "type": "01"}, {"name": "Jusangjeolli", "theme": "Costa", "type": "02"}, {"name": "Cheonjeyeon", "theme": "Cascada", "type": "03"}, {"name": "Almuerzo", "theme": "Pausa", "type": "04"}, {"name": "O''Sulloc", "theme": "Campos de té", "type": "05"}, {"name": "Aewol", "theme": "Cafetería", "type": "06"}, {"name": "Iho Tewoo", "theme": "Atardecer", "type": "07"}], "routePhases": [{"phase": "오전", "duration": "1-3", "description": ""}, {"phase": "정오~오후 초반", "duration": "4-5", "description": ""}, {"phase": "마무리", "duration": "6-7", "description": ""}], "routeShapeIntro": {"title": "El recorrido de esta ruta", "subtitle": "Una ruta que comienza en el humedal Ramsar de las Tierras Altas 1100 de Hallasan, pasa por la costa volcánica, la cascada, el almuerzo y los campos de té, y termina con la calle de cafeterías de Aewol y el atardecer en Iho Tewoo. Aproximadamente de 09:30 a 18:15."}, "whyTourWorks": {"bestFor": ["Viajeros que visitan Jeju por primera vez y parejas", "Viajes familiares de adultos", "Viajeros que desean naturaleza, campos de té y un final más tranquilo", "Viajeros activos de mediana edad y mayores"], "lessIdealFor": ["Viajeros que desean evitar incluso tramos cortos de escaleras o caminatas cuesta arriba", "Grupos que dependen en gran medida de cochecitos de bebé", "Itinerarios diseñados para niños muy pequeños"], "routeLogicSections": [{"title": "Ritmo y estructura", "icon": "sun", "iconBg": "bg-amber-50/80", "items": [{"label": "Un comienzo suave en las tierras altas del Hallasan", "detail": "El humedal de las Tierras Altas 1100 es un paseo llano por pasarela, así que se empieza sin esfuerzo físico y aun así se percibe el ambiente de la alta montaña del Hallasan, y la ruta enlaza de forma natural con la costa sur."}, {"label": "El almuerzo se ubica en el momento adecuado", "detail": "El almuerzo reinicia el día entre las paradas matutinas más abiertas y dramáticas y la sección más tranquila de cascada y campos de té que sigue."}, {"label": "Un final ligero después de O''Sulloc", "detail": "Cuando los campos de té suavizan el ambiente, Aewol abre la tarde con café y vistas al mar, y el atardecer final en Iho Tewoo cierra el día con un tono dorado."}]}, {"title": "Cómo está diseñada la ruta", "icon": "mountain", "iconBg": "bg-sky-50/80", "items": [{"label": "Primero la montaña, después el mar", "detail": "Esta ruta está diseñada para experimentar primero la sensación de altitud y el humedal de alta montaña en las Tierras Altas 1100 de Hallasan y, después, abrir la vista de par en par hacia la costa en Jusangjeolli."}, {"label": "Cascada antes de los campos de té", "detail": "Cheonjeyeon tranquiliza la ruta antes de que O''Sulloc abra la segunda mitad de una manera más ligera y suave."}, {"label": "Un cierre costero al atardecer", "detail": "Tras disfrutar de las cafeterías y la costa de Aewol, se recibe el atardecer junto a los faros con forma de poni de Iho Tewoo, cerrando el día con un final orientado al estilo de vida y no como otra ruta turística cargada."}]}, {"title": "Cuando las condiciones cambian", "icon": "wind", "iconBg": "bg-slate-50/80", "items": [{"label": "La variable de la carretera del Hallasan", "detail": "En las Tierras Altas 1100, la Carretera 1100 puede cerrarse con nevadas intensas, lluvias torrenciales o heladas, y en ese caso se ajusta con atracciones interiores alternativas como el Museo Nacional de Jeju."}, {"label": "Viento en la costa", "detail": "Jusangjeolli y Aewol están mucho más expuestos directamente al viento que las paradas del interior."}, {"label": "Una carga de caminata equilibrada en conjunto", "detail": "Las Tierras Altas 1100 e Iho Tewoo son llanas, pero Cheonjeyeon tiene escalones y tramos cortos en cuesta que requieren atención."}]}]}, "practicalAccordionItems": [{"id": "pickup", "title": "Recogida y regreso", "preview": "Recogida en el vestíbulo del hotel en el área de la ciudad de Jeju", "content": ["La recogida en el vestíbulo del hotel se realiza entre las 8:20 y las 8:50 de la mañana.", "El regreso está previsto entre las 6:30 y las 7:00 de la tarde, tras el atardecer en Iho Tewoo.", "Bajo petición, puede ofrecerse recogida/traslado al aeropuerto.", "La hora exacta de recogida se confirma la noche anterior."]}, {"id": "walking", "title": "Caminata y terreno", "preview": "Moderado en general y manejable para la mayoría de los visitantes", "content": ["La distancia total a pie del día suele ser de unos 3,5 a 4,5 km.", "Tierras Altas 1100: una pasarela llana de aproximadamente 1 km (unos 20 min), el tramo más cómodo.", "Jusangjeolli: un paseo costero fácil de recorrer.", "Cheonjeyeon: senderos de bosque, escalones y, en ocasiones, tramos resbaladizos.", "O''Sulloc, Aewol e Iho Tewoo: tramos cómodos en los que se puede descansar con calma.", "Se recomiendan zapatillas con buena suela antideslizante."]}, {"id": "weather", "title": "Ajustes por clima y cierres", "preview": "El tour opera generalmente, con modificaciones si es necesario", "content": ["Lluvia ligera: el tour suele desarrollarse según lo previsto.", "Si la Carretera 1100 se cierra por nevadas intensas, lluvias torrenciales o heladas: las Tierras Altas 1100 pueden ajustarse a una atracción interior alternativa (por ejemplo, el Museo Nacional de Jeju).", "Con viento fuerte: el tiempo de permanencia en Jusangjeolli, Aewol o Iho Tewoo puede acortarse.", "Si el tiempo empeora por la tarde: puede aumentar la proporción de tiempo dedicada a O''Sulloc.", "Si una atracción concreta cierra: puede utilizarse una atracción alternativa."]}, {"id": "wear", "title": "Qué ponerse y qué llevar", "preview": "Calzado cómodo, ropa en capas y una chaqueta ligera", "content": ["Calzado con buena adherencia", "Ropa en capas para las diferencias de temperatura entre la montaña y la costa", "Un cortavientos ligero", "Sombrero y protector solar", "Botella de agua"]}, {"id": "included", "title": "Qué está incluido / Qué no está incluido", "preview": "Guía, vehículo, recogida y entradas incluidos", "variant": "Incluido", "content": ["Guía de habla inglesa", "Vehículo para grupos pequeños", "Recogida y regreso en hotel en la zona de la ciudad de Jeju", "Todas las entradas", "Agua embotellada", "Almuerzo (pago en el lugar)", "Gastos personales de compras", "Propinas para el guía"]}], "practicalWeatherStatic": {"today": {"temp": "—", "label": "Integración de clima en tiempo real"}, "tomorrow": {"temp": "—", "label": "Actualizado diariamente"}, "_seasonalSummary": "Southwest Jeju has the most varied terrain on the island — from Hallasan''s 1100 Highland Ramsar wetland to Iho Tewoo''s city beach. The 1100m highland runs 7-10°C cooler than the coast; bring a layer year-round.", "_seasonalTemperatures": [{"season": "Spring (Mar–May)", "range": "6–20°C inland / 10–22°C coast", "notes": "Cherry blossoms; new tea leaves at Osulloc."}, {"season": "Summer (Jun–Aug)", "range": "18–25°C inland / 22–30°C coast", "notes": "1100 Highland stays cool; Iho Tewoo lively at sunset."}, {"season": "Autumn (Sep–Nov)", "range": "8–22°C inland / 12–24°C coast", "notes": "Best season — golden tea fields, clear Hallasan views."}, {"season": "Winter (Dec–Feb)", "range": "-2–7°C inland / 3–10°C coast", "notes": "1100 Highland often snowy — striking, but Road 1100 may close; warm layers required."}]}, "seasonalVariations": [{"season": "Primavera", "description": "Una temporada en la que la floración de canola puede añadir un toque amarillo a partes de la costa."}, {"season": "Verano", "description": "Los días son largos y el verdor a lo largo del recorrido se siente especialmente intenso y vívido."}, {"season": "Otoño", "description": "Los cielos despejados suelen hacer que las capas de montaña, costa y campos de té de la ruta se sientan especialmente nítidas."}, {"season": "Invierno", "description": "La ruta suele sentirse más tranquila, con días más cortos y un ambiente general más sereno."}], "bookingTrustItems": [{"icon": "check-circle", "title": "Operación local con licencia", "description": "Guía operada legalmente en Jeju", "iconBg": "bg-emerald-50/80 *(código CSS — sin traducción)*"}, {"icon": "route", "title": "Diseñada en torno al suroeste de Jeju", "description": "Diseñada específicamente para la ruta del suroeste", "iconBg": "bg-sky-50/80 *(código CSS — sin traducción)*"}, {"icon": "users", "title": "Opera en grupos pequeños", "description": "Hasta 8 huéspedes", "iconBg": "bg-amber-50/80 *(código CSS — sin traducción)*"}], "bookingSupportSteps": [{"timing": "Justo después de la reserva", "title": "Confirmación instantánea", "detail": "Recibes una confirmación de reserva con un resumen del día."}, {"timing": "12 horas antes", "title": "Recordatorio de 12 horas", "detail": "Los avisos meteorológicos y los ajustes de ruta se comparten con antelación."}, {"timing": "La noche anterior", "title": "Aviso final de recogida", "detail": "Se comparten tu hora exacta de recogida y los datos de contacto del conductor."}, {"timing": "La mañana del tour", "title": "Nota de ruta del día", "detail": "Se ofrece un breve informe matutino basado en las condiciones en vivo del lugar."}, {"timing": "Durante el tour", "title": "Orientación en vivo parada por parada", "detail": "Recibes la información que necesitas en cada parada."}, {"timing": "Después del tour", "title": "Asistencia post-tour", "detail": "Se puede compartir orientación y recomendaciones adicionales al finalizar."}], "staticQuestions": [{"id": "first-time", "question": "¿Es una buena opción para quien visita Jeju por primera vez?", "answer": "Sí. Podrá vivir un itinerario equilibrado de un día que incluye los paisajes de las Tierras Altas 1100 de Hallasan, la costa volcánica, un paseo junto a la cascada, el ambiente de los campos de té y un final al atardecer en Aewol e Iho Tewoo."}, {"id": "walking", "question": "¿Es difícil la caminata?", "answer": "No. Cheonjeyeon es el tramo más exigente por sus escalones, pero las Tierras Altas 1100 son un paseo llano por pasarela y el resto del itinerario también se completa sin dificultad en general."}, {"id": "rain", "question": "¿Se realiza el tour aunque llueva?", "answer": "Sí. El recorrido puede llevarse a cabo aunque llueva, y si la Carretera 1100 se cierra por nevadas intensas o lluvias torrenciales, las Tierras Altas 1100 se sustituyen por una atracción interior o se acortan los tramos costeros más expuestos."}, {"id": "parents", "question": "¿Es adecuado para viajar con padres u otros familiares mayores?", "answer": "Sí, en muchos casos. Funciona bien para viajes en familia de adultos, especialmente cuando todos se sienten cómodos con escalones y tramos cortos de subida."}, {"id": "children", "question": "¿Puedo unirme con niños?", "answer": "Sí. Es especialmente adecuado para niños de alrededor de 8 años en adelante que puedan seguir el ritmo de caminatas cortas y de un tour de día completo."}, {"id": "order", "question": "¿Puede cambiar el orden de las visitas según las condiciones del momento?", "answer": "Sí. Según el tiempo en la montaña, el viento en la costa, el tráfico, la hora del atardecer o el flujo de visitantes, puede haber pequeños cambios de orden, sobre todo en torno a las Tierras Altas 1100 y los tramos costeros."}, {"id": "lunch", "question": "¿Está incluido el almuerzo?", "answer": "Depende de las condiciones del producto. El tiempo para el almuerzo está contemplado en la ruta, pero si la comida en sí está incluida depende del plan que haya reservado."}, {"id": "why-1100goji", "question": "¿Por qué la ruta empieza en las Tierras Altas 1100?", "answer": "Porque, sin convertir la jornada en un itinerario de montañismo exigente, abre el día experimentando de forma ligera las tierras altas del Hallasan con un paseo llano por pasarela, en el momento de mayor energía."}, {"id": "why-jusangjeolli", "question": "¿Por qué se va a Jusangjeolli después de Hallasan?", "answer": "Porque permite que la historia volcánica de Jeju se desarrolle de forma natural, pasando del paisaje montañoso a una dramática costa de basalto."}, {"id": "why-osulloc", "question": "¿Por qué O''Sulloc va antes que Aewol?", "answer": "Para suavizar la transición de ambiente tras el tramo de la cascada, de modo que la parte final de la ruta —Aewol y el atardecer en Iho Tewoo— se sienta más relajada y cómoda."}, {"id": "later-structure", "question": "¿Por qué la segunda mitad está estructurada así?", "answer": "Porque el almuerzo y Cheonjeyeon estabilizan el ritmo tras la animada mañana, O''Sulloc añade un descanso ligero disfrutando de los campos de té, y Aewol y el atardecer en Iho Tewoo cierran el día de forma natural y con un grato regusto."}], "guestReviews": [], "reviewsSummary": {"averageRating": 0, "totalReviews": 0, "ratingDistribution": [{"stars": 5, "count": 0, "percentage": 0}, {"stars": 4, "count": 0, "percentage": 0}, {"stars": 3, "count": 0, "percentage": 0}, {"stars": 2, "count": 0, "percentage": 0}, {"stars": 1, "count": 0, "percentage": 0}], "highlights": []}, "sticky_booking_bar": {"note": "checkout_tour_id se resuelve en tiempo de ejecución desde Supabase / env; no forma parte del JSONB estático.", "price": {"amountLabel": "52", "originalPriceUsd": null, "salePriceUsd": 52, "discountPercent": null, "currency": "USD", "per": "person"}}, "matching_profile": {"product_type": "small_group", "route_type": "fixed_route", "region_type": "jeju_southwest", "region_tags": ["jeju_southwest", "jeju_aewol", "jeju_hallasan", "jeju_city"], "theme_tags": ["nature", "cafe", "tea_culture", "first_time_friendly", "beach", "sunset"], "poi_tags": ["hallasan_1100_wetland", "osulloc_tea_museum", "iho_tewoo_beach", "cheonjeyeon_falls", "aewol_cafe_street"], "pace_level": 0.6, "walking_level": 0.55, "scenic_level": 1, "photo_level": 1, "culture_level": 0.8, "relax_level": 0.8, "first_time_fit": 1, "family_fit": 1, "senior_fit": 0.85, "couple_fit": 1, "active_traveler_fit": 0.8, "one_day_fit": 1, "same_day_flight_fit": 0.55, "rain_fit": 0.65, "value_for_money_fit": 1, "iconic_landmark_fit": 0.8, "cafe_fit": 1, "adult_family_fit": 1, "young_kids_fit": 0.55, "senior_active_fit": 0.8, "senior_general_fit": 0.8, "mobility_friendly_fit": 0.85, "stroller_fit": 0.7, "indoor_ratio": 0.3, "weather_sensitivity": 0.6, "local_culture_fit": 0.8, "shopping_fit": 0.4, "storytelling_fit": 0.8, "comfort_level": 0.8, "budget_fit": 1, "premium_fit": 0.6, "small_group_fit": 1, "private_fit": 0.2, "bus_fit": 0.2, "price_band": "mid", "pickup_base": "jeju_city", "return_time_band": "18:30-19:00", "duration_band": "9h", "min_recommended_age": 6, "hard_constraints": {"avoidIf": ["tight_same_day_departure", "strict_same_day_flight_sch